// ─── QUESTION BANKS ───
const QB_BPL = [
  {id:"bpl1",prompt:"Quel est l'objectif principal de la BPL au laboratoire ?",choices:["Accélérer les manipulations","Garantir fiabilité, traçabilité et sécurité","Réduire le nombre de contrôles","Supprimer les procédures écrites"],answer:1,diff:1,explication:"La BPL standardise, trace et sécurise toutes les activités.",tags:["BPL"]},
  {id:"bpl2",prompt:"Une correction dans un cahier de labo doit :",choices:["Être effacée au correcteur","Être surlignée en jaune","Être raturée d'un trait + datée + signée","Être refaite sur une autre page"],answer:2,diff:1,explication:"On conserve lisibilité et valeur probante : 1 trait, date, initiales.",tags:["BPL","Traçabilité"]},
  {id:"bpl3",prompt:"Que signifie DASRI ?",choices:["Déchets Assimilés Soins Risques Infectieux","Déchets d'Activités de Soins à Risques Infectieux","Document Analyse Sécurité Risques Industriels","Dispositif Aide Suivi Résultats Internes"],answer:1,diff:1,explication:"DASRI = Déchets d'Activités de Soins à Risques Infectieux.",tags:["BPL","Déchets"]},
  {id:"bpl4",prompt:"La FDS (Fiche de Données de Sécurité) informe sur :",choices:["Le prix du réactif","Les dangers et mesures de protection","La date de fabrication uniquement","Le fournisseur recommandé"],answer:1,diff:1,explication:"La FDS contient 16 rubriques : dangers, premiers secours, lutte incendie, etc.",tags:["BPL","Sécurité"]},
  {id:"bpl5",prompt:"Quel document recense les risques professionnels dans l'entreprise ?",choices:["Le manuel qualité","Le DUERP","La pharmacopée","Le cahier des charges"],answer:1,diff:1,explication:"Le DUERP (Document Unique d'Évaluation des Risques Professionnels) est obligatoire.",tags:["BPL","DUERP"]},
  {id:"bpl6",prompt:"Les EPI comprennent :",choices:["Uniquement la blouse","Blouse, gants, lunettes de protection","Le PSM et la sorbonne","Le système de ventilation du labo"],answer:1,diff:1,explication:"EPI = Équipements de Protection Individuelle (blouse, gants, lunettes, masque…). PSM et sorbonne sont des EPC.",tags:["BPL","EPI"]},
  {id:"bpl7",prompt:"Quelle est la différence entre EPI et EPC ?",choices:["EPI protège l'échantillon, EPC protège le labo","EPI est individuel (blouse, gants), EPC est collectif (PSM, sorbonne)","EPI est obligatoire, EPC est facultatif","Aucune différence, ce sont des synonymes"],answer:1,diff:1,explication:"EPI = individuel (porté par la personne). EPC = collectif (installé dans l'environnement).",tags:["BPL","EPI","EPC"]},
  {id:"bpl8",prompt:"Avant toute manipulation, le technicien doit :",choices:["Allumer la musique pour se concentrer","Vérifier EPI, poste propre, réactifs, équipements, support enregistrement","Appeler son responsable","Lire le journal officiel"],answer:1,diff:1,explication:"Check rapide obligatoire : EPI, propreté poste, réactifs vérifiés, équipements OK, support traçabilité prêt.",tags:["BPL"]},
  {id:"bpl9",prompt:"Le bionettoyage consiste à :",choices:["Nettoyer avec de l'eau uniquement","Nettoyer puis désinfecter les surfaces","Stériliser tout le matériel à l'autoclave","Jeter le matériel contaminé"],answer:1,diff:2,explication:"Bionettoyage = nettoyage (élimination salissures) + désinfection (réduction charge microbienne).",tags:["BPL","Hygiène"]},
  {id:"bpl10",prompt:"Le tri des déchets au laboratoire distingue :",choices:["Déchets solides et liquides uniquement","DASRI, déchets chimiques et déchets ménagers","Déchets recyclables et non-recyclables","Il n'y a pas de tri spécifique en labo"],answer:1,diff:1,explication:"3 filières minimum : DASRI (infectieux), chimiques (selon SGH), ménagers/assimilés.",tags:["BPL","Déchets"]},
  {id:"bpl11",prompt:"Un réactif dont la date de péremption est dépassée :",choices:["Peut être utilisé si l'aspect est normal","Doit être éliminé selon la filière appropriée","Peut être reconditionné","Est utilisable encore 6 mois"],answer:1,diff:1,explication:"Un réactif périmé ne garantit plus ses performances. Il doit être éliminé et tracé.",tags:["BPL","Réactifs"]},
  {id:"bpl12",prompt:"L'étiquetage d'un réactif ouvert doit comporter :",choices:["Le nom du réactif uniquement","Date d'ouverture, date de péremption, initiales de l'opérateur","Le prix d'achat","La marque du fournisseur uniquement"],answer:1,diff:1,explication:"Informations minimales : date ouverture, péremption après ouverture, initiales opérateur.",tags:["BPL","Réactifs","Traçabilité"]},
  {id:"bpl13",prompt:"Le SGH (Système Général Harmonisé) concerne :",choices:["La classification des micro-organismes","La classification et l'étiquetage des produits chimiques","Le classement des équipements","La hiérarchie des documents qualité"],answer:1,diff:2,explication:"Le SGH harmonise au niveau mondial la classification des dangers chimiques et leur étiquetage (pictogrammes losange rouge).",tags:["BPL","Sécurité","SGH"]},
  {id:"bpl14",prompt:"Combien de pictogrammes de danger le SGH comporte-t-il ?",choices:["5","7","9","12"],answer:2,diff:2,explication:"Le SGH comporte 9 pictogrammes : explosif, inflammable, comburant, gaz sous pression, corrosif, toxique, nocif/irritant, danger santé, danger environnement.",tags:["BPL","SGH"]},
  {id:"bpl15",prompt:"La mention « H302 » sur une étiquette SGH signifie :",choices:["Produit explosif","Nocif en cas d'ingestion","Provoque des brûlures","Toxique par inhalation"],answer:1,diff:3,explication:"Les mentions H3xx concernent les dangers pour la santé. H302 = nocif en cas d'ingestion.",tags:["BPL","SGH"]},
  {id:"bpl16",prompt:"Les précautions P correspondent à :",choices:["Les phrases de danger","Les conseils de prudence (prévention, intervention, stockage, élimination)","Les numéros CAS des produits","Les classes de risque biologique"],answer:1,diff:2,explication:"Les mentions P indiquent les mesures de prévention, d'intervention en cas d'accident, de stockage et d'élimination.",tags:["BPL","SGH"]},
  {id:"bpl17",prompt:"Le nettoyage se distingue de la désinfection par :",choices:["Le nettoyage élimine les salissures, la désinfection réduit la charge microbienne","Le nettoyage utilise des biocides, la désinfection utilise du savon","Aucune différence","Le nettoyage est réservé au sol, la désinfection aux paillasses"],answer:0,diff:2,explication:"Nettoyage = élimination physico-chimique des souillures. Désinfection = réduction de la charge microbienne à un niveau acceptable.",tags:["BPL","Hygiène"]},
  {id:"bpl18",prompt:"Un accident d'exposition au sang (AES) nécessite en priorité :",choices:["De continuer le travail et noter l'incident plus tard","De nettoyer la plaie, désinfecter et consulter immédiatement","D'attendre la fin de la journée pour déclarer","De changer de gants et continuer"],answer:1,diff:2,explication:"AES = urgence. Nettoyage immédiat (eau + savon), désinfection (Dakin ou javel diluée), déclaration et consultation dans les 4h.",tags:["BPL","Sécurité"]},
  {id:"bpl19",prompt:"Le document qui organise la gestion des déchets dans un labo est :",choices:["Le DUERP","Le protocole de gestion des déchets / plan de gestion","Le cahier de labo","La fiche de poste"],answer:1,diff:2,explication:"Le protocole ou plan de gestion des déchets détaille les filières, conteneurs, fréquences de collecte et responsabilités.",tags:["BPL","Déchets"]},
  {id:"bpl20",prompt:"La zone de confinement NSB2 est requise pour manipuler des agents de :",choices:["Groupe 1 (non pathogènes)","Groupe 2 (pathogènes, risque modéré)","Groupe 3 (pathogènes, risque grave)","Groupe 4 (pathogènes, risque très élevé)"],answer:1,diff:2,explication:"NSB2 = agents du groupe 2. NSB3 = groupe 3. NSB4 = groupe 4 (très rares, P4 Jean Mérieux).",tags:["BPL","Sécurité","NSB"]},
  {id:"bpl21",prompt:"Les classes de risque biologique vont de :",choices:["1 à 3","1 à 4","A à D","I à V"],answer:1,diff:2,explication:"4 groupes : 1 (non pathogène) à 4 (pathogène grave, pas de traitement). Classification OMS.",tags:["BPL","Sécurité"]},
  {id:"bpl22",prompt:"La douche de sécurité et le rince-œil doivent être :",choices:["Vérifiés une fois par an","Accessibles en moins de 10 secondes et testés régulièrement","Installés uniquement en labo de chimie","Utilisés uniquement par le responsable sécurité"],answer:1,diff:2,explication:"Accessibilité immédiate (<10s de marche) et tests réguliers documentés sont réglementaires.",tags:["BPL","Sécurité"]},
  {id:"bpl23",prompt:"Le principe ALARA en radioprotection signifie :",choices:["Toujours utiliser le maximum de protection","Maintenir les doses aussi basses que raisonnablement possible","Interdire toute manipulation radioactive","Limiter à 1h/jour l'exposition"],answer:1,diff:3,explication:"ALARA = As Low As Reasonably Achievable. Principe d'optimisation de la radioprotection.",tags:["BPL","Sécurité","Radioprotection"]},
  {id:"bpl24",prompt:"Un extincteur à CO₂ est adapté pour :",choices:["Les feux de papier","Les feux d'origine électrique et liquides inflammables","Les feux de métaux","Tous les types de feux sans exception"],answer:1,diff:2,explication:"CO₂ = feux électriques et liquides. Pas pour les métaux (risque d'explosion). Poudre ABC = polyvalent.",tags:["BPL","Sécurité"]},
  {id:"bpl25",prompt:"Le stockage des produits chimiques impose de séparer :",choices:["Les acides et les bases","Les comburants et les inflammables","Les toxiques et les non-toxiques","Toutes les réponses sont correctes"],answer:3,diff:2,explication:"Incompatibilités chimiques : acides/bases, comburants/inflammables, toxiques isolés. Armoires ventilées spécifiques.",tags:["BPL","Stockage"]},
  {id:"bpl26",prompt:"La procédure de lavage des mains au laboratoire recommande :",choices:["Eau seule pendant 10 secondes","Eau + savon antiseptique, 30 secondes minimum, séchage papier","Gel hydroalcoolique uniquement","Aucun lavage si on porte des gants"],answer:1,diff:1,explication:"Lavage hygiénique : mouiller, savonner 30s (espaces interdigitaux, poignets), rincer, sécher papier, robinet fermé au coude/papier.",tags:["BPL","Hygiène"]},
  {id:"bpl27",prompt:"Les gants nitrile sont préférés aux gants latex car :",choices:["Ils sont moins chers","Ils résistent mieux aux solvants et évitent les allergies au latex","Ils sont plus fins et plus sensibles","Ils sont toujours stériles"],answer:1,diff:2,explication:"Nitrile : résistance chimique supérieure, pas de protéines de latex (allergies type I), bonne résistance mécanique.",tags:["BPL","EPI"]},
  {id:"bpl28",prompt:"La sorbonne (hotte chimique) protège :",choices:["L'échantillon uniquement","L'opérateur contre les vapeurs toxiques","L'environnement uniquement","Personne, c'est juste un plan de travail ventilé"],answer:1,diff:1,explication:"La sorbonne aspire les vapeurs vers l'extérieur via des filtres. Protection de l'opérateur contre inhalation.",tags:["BPL","EPC"]},
  {id:"bpl29",prompt:"La vitesse frontale minimale recommandée pour une sorbonne est :",choices:["0.1 m/s","0.4 m/s","1.0 m/s","2.0 m/s"],answer:1,diff:3,explication:"Norme EN 14175 : vitesse frontale ≥ 0.4 m/s pour un confinement efficace. Vérification annuelle obligatoire.",tags:["BPL","EPC"]},
  {id:"bpl30",prompt:"En cas de déversement de produit chimique, la première action est :",choices:["Appeler les pompiers immédiatement","Identifier le produit, protéger les personnes, confiner avec absorbant adapté","Essuyer avec du papier","Ouvrir les fenêtres"],answer:1,diff:2,explication:"1) Identifier le produit (FDS). 2) Protéger (EPI). 3) Confiner (kit absorbant adapté). 4) Éliminer selon filière. 5) Tracer.",tags:["BPL","Sécurité"]},
  {id:"bpl31",prompt:"L'autoclave fonctionne à :",choices:["100°C à pression atmosphérique","121°C à 1 bar de surpression pendant 15-20 min","160°C à sec pendant 2h","Température ambiante sous UV"],answer:1,diff:1,explication:"Autoclavage standard : 121°C, 1 bar surpression, 15-20 min. Alternative : 134°C, 2 bar, 18 min (prions).",tags:["BPL","Stérilisation"]},
  {id:"bpl32",prompt:"Un indicateur de passage (ruban autoclave) prouve :",choices:["La stérilité du matériel","Que le matériel est passé dans l'autoclave (exposition à la chaleur)","La qualité du cycle complet","L'absence de micro-organismes"],answer:1,diff:2,explication:"L'indicateur de passage montre seulement l'exposition à la chaleur. Seul l'indicateur biologique (Geobacillus) prouve la stérilité.",tags:["BPL","Stérilisation"]},
  {id:"bpl33",prompt:"La stérilisation par chaleur sèche (four Pasteur/Poupinel) nécessite :",choices:["121°C pendant 15 min","160°C pendant 2h ou 180°C pendant 30 min","250°C pendant 5 min","Température variable selon le matériel"],answer:1,diff:2,explication:"Chaleur sèche : moins efficace que humide, nécessite T° plus élevée et temps plus long. 160°C/2h ou 180°C/30min.",tags:["BPL","Stérilisation"]},
  {id:"bpl34",prompt:"La filtration stérilisante utilise des filtres de porosité :",choices:["0.45 µm","0.22 µm","0.10 µm","1.0 µm"],answer:1,diff:2,explication:"0.22 µm retient les bactéries. 0.45 µm = préfiltration ou contrôle bioburden. 0.10 µm = rétention mycoplasmes.",tags:["BPL","Stérilisation"]},
  {id:"bpl35",prompt:"Le cahier de laboratoire a valeur :",choices:["Informative uniquement","Probante (preuve légale et réglementaire)","Pédagogique uniquement","Statistique"],answer:1,diff:2,explication:"Le cahier de labo est un document à valeur probante. Pages numérotées, encre indélébile, pas d'arrachage.",tags:["BPL","Traçabilité"]},
];

const QB_TRACABILITE = [
  {id:"tra1",prompt:"La traçabilité interne concerne :",choices:["Le suivi du produit chez le fournisseur","Le suivi de l'échantillon au sein du laboratoire","Le transport entre laboratoires","La facturation des analyses"],answer:1,diff:1,explication:"Traçabilité interne = suivi de l'échantillon depuis réception jusqu'au rendu de résultat au sein du labo.",tags:["Traçabilité"]},
  {id:"tra2",prompt:"Un numéro de lot permet de :",choices:["Identifier le fournisseur uniquement","Retrouver l'historique complet de fabrication et de contrôle","Calculer le prix du réactif","Déterminer la composition chimique"],answer:1,diff:1,explication:"Le lot lie toutes les informations : matières premières, conditions fabrication, contrôles, opérateurs, dates.",tags:["Traçabilité","Lot"]},
  {id:"tra3",prompt:"Dans la pyramide documentaire, quel document est au sommet ?",choices:["Les enregistrements","Les modes opératoires","Le manuel qualité","Les instructions de travail"],answer:2,diff:1,explication:"Pyramide : Manuel qualité > Procédures > Modes opératoires/Instructions > Enregistrements (base).",tags:["Traçabilité","Qualité"]},
  {id:"tra4",prompt:"Un enregistrement se distingue d'une procédure car :",choices:["L'enregistrement décrit comment faire, la procédure prouve ce qui a été fait","L'enregistrement prouve ce qui a été fait, la procédure décrit comment faire","Ce sont des synonymes","L'enregistrement est numérique, la procédure est papier"],answer:1,diff:2,explication:"Procédure = document de référence (comment faire). Enregistrement = preuve (ce qui a été fait).",tags:["Traçabilité","Documentation"]},
  {id:"tra5",prompt:"La gestion des versions d'un document qualité impose :",choices:["De garder uniquement la dernière version","De conserver les versions antérieures avec dates et indices de révision","De réécrire entièrement le document à chaque modification","De changer de format à chaque révision"],answer:1,diff:2,explication:"Gestion de versions : indice de révision, date, auteur, nature des modifications. Versions périmées archivées.",tags:["Traçabilité","Documentation"]},
  {id:"tra6",prompt:"Le LIMS (Laboratory Information Management System) permet de :",choices:["Uniquement stocker les résultats","Gérer échantillons, résultats, équipements, traçabilité de manière intégrée","Remplacer le cahier de labo dans tous les cas","Faire les analyses automatiquement"],answer:1,diff:2,explication:"Le LIMS est un système intégré de gestion : échantillons, workflow, résultats, CQ, traçabilité, rapports.",tags:["Traçabilité","LIMS"]},
  {id:"tra7",prompt:"L'archivage des documents qualité a une durée minimale de :",choices:["1 an","3 ans","Variable selon réglementation du secteur (souvent 5 à 30 ans)","Illimitée obligatoirement"],answer:2,diff:2,explication:"Durée variable : pharma 5 ans après AMM, alimentaire 5 ans, certains documents 30 ans. Réglementation sectorielle.",tags:["Traçabilité","Archivage"]},
  {id:"tra8",prompt:"Si ce n'est pas écrit... :",choices:["C'est quand même valable si quelqu'un se souvient","Ça n'existe pas (du point de vue qualité et réglementaire)","On peut le reconstituer plus tard","C'est acceptable en routine"],answer:1,diff:1,explication:"Règle fondamentale de la qualité : pas de trace = pas de preuve. Tout doit être documenté en temps réel.",tags:["Traçabilité"]},
  {id:"tra9",prompt:"La traçabilité métrologique concerne :",choices:["Le suivi des échantillons","Le raccordement des instruments de mesure à des étalons de référence","La documentation des méthodes","Le suivi des formations du personnel"],answer:1,diff:2,explication:"Traçabilité métrologique = chaîne ininterrompue de comparaisons reliant la mesure aux étalons nationaux/internationaux.",tags:["Traçabilité","Métrologie"]},
  {id:"tra10",prompt:"Un document de référence se distingue d'un document de preuve par :",choices:["Le référence dit quoi/comment faire, la preuve montre que ça a été fait","Le référence est ancien, la preuve est récente","Le référence est papier, la preuve est numérique","Aucune différence"],answer:0,diff:1,explication:"Référence = prescriptif (procédure, norme). Preuve = descriptif (enregistrement, résultat, signature).",tags:["Traçabilité","Documentation"]},
  {id:"tra11",prompt:"La norme ISO 17025 concerne :",choices:["La gestion environnementale","Les exigences générales pour les laboratoires d'essais et d'étalonnage","La sécurité alimentaire","La gestion de la qualité en production"],answer:1,diff:2,explication:"ISO 17025 : compétence des laboratoires d'essais et d'étalonnage. Base pour l'accréditation COFRAC.",tags:["Traçabilité","Qualité","ISO"]},
  {id:"tra12",prompt:"L'accréditation diffère de la certification car :",choices:["L'accréditation reconnaît la compétence technique, la certification la conformité à un référentiel","C'est la même chose","L'accréditation est volontaire, la certification obligatoire","L'accréditation concerne les produits, la certification les personnes"],answer:0,diff:2,explication:"Accréditation (COFRAC) = compétence technique. Certification (AFNOR, etc.) = conformité système qualité.",tags:["Traçabilité","Qualité"]},
];

const QB_PREVENTION = [
  {id:"prev1",prompt:"La différence entre danger et risque est :",choices:["Ce sont des synonymes","Le danger est la source potentielle de dommage, le risque est la probabilité que le dommage survienne","Le risque est plus grave que le danger","Le danger concerne les personnes, le risque concerne les équipements"],answer:1,diff:1,explication:"Danger = propriété intrinsèque (ex: produit corrosif). Risque = probabilité × gravité de l'exposition au danger.",tags:["Prévention","DUERP"]},
  {id:"prev2",prompt:"Les 9 principes généraux de prévention commencent par :",choices:["Former les travailleurs","Éviter les risques","Porter des EPI","Signaler les dangers"],answer:1,diff:2,explication:"1er principe : éviter les risques. Si impossible : évaluer, combattre à la source, adapter le travail, etc.",tags:["Prévention"]},
  {id:"prev3",prompt:"Le DUERP doit être mis à jour :",choices:["Tous les 5 ans","Au moins une fois par an et à chaque modification importante","Uniquement lors d'un accident","À la demande du médecin du travail"],answer:1,diff:1,explication:"Mise à jour annuelle obligatoire + à chaque changement de situation (nouveau risque, nouvel équipement, accident).",tags:["Prévention","DUERP"]},
  {id:"prev4",prompt:"L'ordre de priorité en prévention des risques est :",choices:["EPI > EPC > organisation > suppression","Suppression > substitution > EPC > organisation > EPI","EPC > EPI > suppression > organisation","Formation > suppression > EPI > EPC"],answer:1,diff:2,explication:"Hiérarchie : supprimer > substituer > protections collectives > organisation > protections individuelles (dernier recours).",tags:["Prévention"]},
  {id:"prev5",prompt:"Le pictogramme SGH « tête de mort » correspond à :",choices:["Danger pour l'environnement","Toxicité aiguë (mortel/toxique)","Produit inflammable","Gaz sous pression"],answer:1,diff:1,explication:"Tête de mort et tibias croisés = toxicité aiguë catégories 1-3 (mortel, toxique).",tags:["Prévention","SGH"]},
  {id:"prev6",prompt:"Le pictogramme SGH « point d'exclamation » signale :",choices:["Danger mortel","Nocif, irritant, sensibilisant cutané, narcotique","Produit corrosif","Danger pour la couche d'ozone"],answer:1,diff:2,explication:"Point d'exclamation = dangers moins graves : nocif, irritant, sensibilisant cutané, narcotique, irritant voies respiratoires.",tags:["Prévention","SGH"]},
  {id:"prev7",prompt:"Un agent biologique de groupe 3 :",choices:["N'est pas pathogène","Peut provoquer une maladie grave, prophylaxie/traitement existe","Provoque une maladie grave sans traitement","Est sans danger pour l'homme"],answer:1,diff:2,explication:"Groupe 3 : maladie grave possible, risque propagation, MAIS prophylaxie ou traitement efficace existe.",tags:["Prévention","Risque bio"]},
  {id:"prev8",prompt:"La conduite à tenir face à une projection oculaire de produit chimique :",choices:["Frotter l'œil vigoureusement","Rincer abondamment 15 min au rince-œil, consulter","Attendre que la douleur passe","Appliquer un pansement"],answer:1,diff:1,explication:"Rinçage immédiat 15 min minimum, paupières écartées, eau tiède. Consultation ophtalmologique urgente.",tags:["Prévention","Premiers secours"]},
  {id:"prev9",prompt:"Le diagramme d'Ishikawa (causes-effets) classe les causes selon :",choices:["3P","5M : Matière, Méthode, Main-d'œuvre, Milieu, Matériel","4C","ABC"],answer:1,diff:1,explication:"5M (parfois 6M avec Mesure) : arêtes de poisson pour analyse structurée des causes.",tags:["Prévention","Qualité","Outils"]},
  {id:"prev10",prompt:"L'outil « 5 Pourquoi » sert à :",choices:["Lister 5 solutions possibles","Remonter de la cause apparente à la cause racine","Évaluer 5 fournisseurs","Planifier 5 actions correctives"],answer:1,diff:1,explication:"En posant successivement « Pourquoi ? » (en moyenne 5 fois), on remonte à la cause profonde.",tags:["Prévention","Qualité","Outils"]},
  {id:"prev11",prompt:"La méthode HACCP signifie :",choices:["Hazard Analysis Critical Control Point","High Accuracy Chemical Control Process","Hygiene And Cleaning Control Protocol","Health Assessment and Contamination Control Plan"],answer:0,diff:2,explication:"HACCP = Analyse des dangers et maîtrise des points critiques. Obligatoire en agroalimentaire (paquet hygiène).",tags:["Prévention","HACCP","Qualité"]},
  {id:"prev12",prompt:"Un CCP (Critical Control Point) en HACCP est :",choices:["Un point de contrôle facultatif","Une étape où un contrôle est indispensable pour prévenir/éliminer un danger","Un document de traçabilité","Un type d'équipement de laboratoire"],answer:1,diff:2,explication:"CCP = étape où la maîtrise est essentielle pour prévenir, éliminer ou réduire un danger à un niveau acceptable.",tags:["Prévention","HACCP"]},
];

const QB_QUALITE = [
  {id:"qual1",prompt:"La roue de Deming (PDCA) comprend les étapes :",choices:["Plan, Do, Check, Act","Prepare, Deliver, Control, Archive","Plan, Design, Create, Approve","Predict, Develop, Certify, Audit"],answer:0,diff:1,explication:"PDCA = Planifier, Réaliser, Vérifier, Agir. Boucle d'amélioration continue.",tags:["Qualité","PDCA"]},
  {id:"qual2",prompt:"L'amélioration continue repose sur le principe de :",choices:["Tout changer en une fois","Itérations progressives et mesurables (PDCA)","Attendre qu'un problème survienne","Copier les méthodes du concurrent"],answer:1,diff:1,explication:"Amélioration continue = démarche itérative, mesurable, documentée, impliquant tous les acteurs.",tags:["Qualité"]},
  {id:"qual3",prompt:"Un audit interne est mené par :",choices:["Un organisme extérieur","Du personnel formé de l'entreprise, indépendant du service audité","Le client","L'organisme d'accréditation"],answer:1,diff:1,explication:"Audit interne = auditeurs internes formés et indépendants de l'activité auditée. Audit externe = organisme tiers.",tags:["Qualité","Audit"]},
  {id:"qual4",prompt:"La différence entre NC majeure et NC mineure :",choices:["Majeure = coût élevé, mineure = coût faible","Majeure = impact systémique/sécurité, mineure = écart ponctuel","Majeure = détectée en externe, mineure = détectée en interne","Aucune différence réelle"],answer:1,diff:2,explication:"NC majeure : défaillance systémique ou impact sécurité/qualité produit. NC mineure : écart ponctuel sans impact critique.",tags:["Qualité","NC"]},
  {id:"qual5",prompt:"La revue de direction a pour objectif :",choices:["Augmenter le chiffre d'affaires","Évaluer l'efficacité du système qualité et décider des améliorations","Recruter du personnel","Choisir les fournisseurs"],answer:1,diff:2,explication:"Revue de direction = examen périodique du SMQ par la direction : indicateurs, NC, audits, actions, ressources.",tags:["Qualité"]},
  {id:"qual6",prompt:"Le coût de la non-qualité comprend :",choices:["Uniquement les rebuts","Rebuts, reprises, réclamations clients, perte d'image, rappels produits","Le salaire du responsable qualité","Les investissements en équipement"],answer:1,diff:2,explication:"CNQ = coûts directs (rebuts, reprises, contrôles supplémentaires) + indirects (image, fidélisation, rappels).",tags:["Qualité"]},
  {id:"qual7",prompt:"Une action corrective traite :",choices:["La cause d'une non-conformité détectée","Un risque potentiel futur","Une amélioration souhaitée","Un changement de procédure planifié"],answer:0,diff:1,explication:"Action corrective = éliminer la cause d'une NC existante. Action préventive = éliminer la cause d'une NC potentielle.",tags:["Qualité","CAPA"]},
  {id:"qual8",prompt:"La vérification d'efficacité d'une CAPA consiste à :",choices:["Vérifier que l'action a été réalisée","Vérifier que la NC ne s'est pas reproduite après un délai défini","Vérifier le coût de l'action","Vérifier la satisfaction du client"],answer:1,diff:2,explication:"Efficacité = la cause racine est éliminée, la NC ne réapparaît pas. Vérifié après un délai raisonnable.",tags:["Qualité","CAPA"]},
  {id:"qual9",prompt:"Le diagramme de Pareto permet de :",choices:["Classer les causes par ordre de fréquence pour identifier les plus impactantes (80/20)","Suivre l'évolution d'un paramètre dans le temps","Comparer deux méthodes","Planifier les activités"],answer:0,diff:2,explication:"Pareto (80/20) : 80% des effets viennent de 20% des causes. Priorisation des actions d'amélioration.",tags:["Qualité","Outils"]},
  {id:"qual10",prompt:"La carte de contrôle de Levey-Jennings surveille :",choices:["La conformité des produits finis","La stabilité d'un processus analytique dans le temps","La satisfaction client","Les délais de livraison"],answer:1,diff:2,explication:"Levey-Jennings : valeur CQ tracée vs moyenne ± 1σ/2σ/3σ. Détecte dérives et erreurs via règles de Westgard.",tags:["Qualité","CQ","Westgard"]},
];

const QB_METROLOGIE = [
  {id:"met1",prompt:"L'exactitude d'une mesure combine :",choices:["Précision et rapidité","Justesse et fidélité","Sensibilité et spécificité","Linéarité et robustesse"],answer:1,diff:1,explication:"Exactitude = justesse (absence de biais systématique) + fidélité (faible dispersion).",tags:["Métrologie"]},
  {id:"met2",prompt:"La fidélité se décompose en :",choices:["Justesse et exactitude","Répétabilité et reproductibilité","Sensibilité et sélectivité","Linéarité et robustesse"],answer:1,diff:2,explication:"Fidélité = répétabilité (mêmes conditions) + reproductibilité (conditions différentes : opérateur, jour, etc.).",tags:["Métrologie"]},
  {id:"met3",prompt:"L'incertitude de type A est évaluée par :",choices:["Données constructeur","Méthode statistique (écart-type de répétabilité)","Avis d'expert","Certificat d'étalonnage"],answer:1,diff:2,explication:"Type A = évaluation statistique sur n mesures. Type B = autres sources (certificats, spécifications, etc.).",tags:["Métrologie","Incertitude"]},
  {id:"met4",prompt:"Un Z-score de 2.8 indique un résultat :",choices:["Satisfaisant","Douteux","Insatisfaisant","Excellent"],answer:1,diff:2,explication:"|Z|<2 = satisfaisant. 2<|Z|<3 = douteux. |Z|>3 = insatisfaisant.",tags:["Métrologie","Z-score"]},
  {id:"met5",prompt:"L'étalonnage consiste à :",choices:["Réparer un instrument défaillant","Comparer les indications d'un instrument à des valeurs de référence","Nettoyer le capteur","Remplacer les pièces usées"],answer:1,diff:1,explication:"Étalonnage = opération de comparaison. Ne modifie pas l'instrument (≠ ajustage).",tags:["Métrologie","Étalonnage"]},
  {id:"met6",prompt:"L'ajustage se distingue de l'étalonnage car :",choices:["C'est la même chose","L'ajustage modifie l'instrument pour corriger un écart","L'ajustage est moins précis","L'ajustage concerne uniquement les balances"],answer:1,diff:2,explication:"Étalonnage = constater. Ajustage = corriger. Vérification = décider si conforme aux spécifications.",tags:["Métrologie"]},
  {id:"met7",prompt:"La limite de détection (LOD) est :",choices:["La plus petite quantité quantifiable avec une exactitude acceptable","La plus petite quantité détectable de manière fiable (distinguable du bruit)","La concentration maximale mesurable","La plage de linéarité de la méthode"],answer:1,diff:2,explication:"LOD = plus petite quantité détectable (signal > bruit). LOQ = plus petite quantité quantifiable avec exactitude définie.",tags:["Métrologie","Validation"]},
  {id:"met8",prompt:"La LOQ (limite de quantification) est généralement :",choices:["Égale à la LOD","Inférieure à la LOD","3 à 10 fois supérieure à la LOD","100 fois la LOD"],answer:2,diff:2,explication:"Souvent LOQ ≈ 3×LOD (convention) ou 10×σ du blanc. LOQ > LOD toujours.",tags:["Métrologie","Validation"]},
  {id:"met9",prompt:"La linéarité d'une méthode est :",choices:["Sa capacité à donner des résultats rapides","Sa capacité à fournir des résultats proportionnels à la concentration dans un intervalle donné","Sa résistance aux interférences","Sa reproductibilité entre laboratoires"],answer:1,diff:2,explication:"Linéarité : relation proportionnelle (R²→1) entre signal et concentration dans l'intervalle de mesure.",tags:["Métrologie","Validation"]},
  {id:"met10",prompt:"La spécificité/sélectivité d'une méthode est :",choices:["Sa rapidité d'exécution","Sa capacité à mesurer l'analyte sans interférence d'autres composants","Sa plage de mesure","Son coût"],answer:1,diff:1,explication:"Spécificité = mesure uniquement l'analyte cible. Sélectivité = mesure l'analyte même en présence d'interférents.",tags:["Métrologie","Validation"]},
  {id:"met11",prompt:"Un étalon de travail est :",choices:["L'étalon primaire national","Un étalon utilisé en routine pour l'étalonnage courant","Un étalon détruit après usage","Un réactif quelconque"],answer:1,diff:2,explication:"Hiérarchie : étalon primaire > étalon secondaire > étalon de travail (routine quotidienne).",tags:["Métrologie","Étalonnage"]},
  {id:"met12",prompt:"L'étalonnage externe consiste à :",choices:["Envoyer l'échantillon dans un autre labo","Mesurer des étalons séparés de l'échantillon pour construire une courbe","Ajouter l'analyte directement dans l'échantillon","Comparer deux appareils"],answer:1,diff:2,explication:"Étalonnage externe : gamme étalon indépendante. Interne : étalon ajouté dans chaque échantillon. Ajouts dosés : analyte ajouté à l'échantillon.",tags:["Métrologie","Étalonnage"]},
  {id:"met13",prompt:"L'incertitude élargie U est obtenue en multipliant l'incertitude composée par :",choices:["Le nombre de mesures","Le facteur d'élargissement k (généralement k=2 pour 95%)","La concentration de l'analyte","Le nombre d'opérateurs"],answer:1,diff:2,explication:"U = k × uc. Avec k=2 : intervalle de confiance ≈ 95%. Avec k=3 : ≈ 99%.",tags:["Métrologie","Incertitude"]},
  {id:"met14",prompt:"Le résultat d'une analyse doit être exprimé sous la forme :",choices:["Valeur seule","Valeur ± incertitude avec unité","Valeur avec 10 décimales","Valeur arrondie à l'entier"],answer:1,diff:1,explication:"Résultat = valeur ± U (k=2) avec unité. Nombre de chiffres significatifs cohérent avec l'incertitude.",tags:["Métrologie"]},
  {id:"met15",prompt:"La robustesse d'une méthode mesure :",choices:["Sa vitesse d'exécution","Sa résistance à de petites variations des conditions opératoires","Sa capacité à détecter de faibles concentrations","Son coût de mise en œuvre"],answer:1,diff:2,explication:"Robustesse = insensibilité aux petites variations (T°, pH, opérateur, lot réactif). Testée par plans d'expérience.",tags:["Métrologie","Validation"]},
];

const QB_MICRO = [
  {id:"mic1",prompt:"Le PSM II protège :",choices:["Uniquement l'opérateur","Uniquement l'échantillon","Opérateur + échantillon + environnement","Uniquement l'environnement"],answer:2,diff:1,explication:"PSM II = triple protection grâce aux flux laminaires filtrés HEPA.",tags:["Microbiologie","PSM"]},
  {id:"mic2",prompt:"La coloration de Gram distingue les bactéries selon :",choices:["Leur taille","La structure de leur paroi (peptidoglycane)","Leur métabolisme","Leur forme uniquement"],answer:1,diff:1,explication:"Gram+ : paroi épaisse peptidoglycane (violet). Gram- : paroi fine + membrane externe (rose).",tags:["Microbiologie","Gram"]},
  {id:"mic3",prompt:"Le milieu MacConkey est :",choices:["Non sélectif d'enrichissement","Sélectif et différentiel pour Gram-","Chromogène universel","Conservation souches"],answer:1,diff:1,explication:"MacConkey : sels biliaires/cristal violet sélectionnent Gram-. Lactose différencie lactose+/lactose-.",tags:["Microbiologie","Milieux"]},
  {id:"mic4",prompt:"Pour le contrôle microbiologique de l'air, on utilise :",choices:["Spectrophotomètre","Biocollecteur","pH-mètre","Centrifugeuse"],answer:1,diff:1,explication:"Biocollecteur : aspire volume d'air connu, impacte micro-organismes sur gélose.",tags:["Microbiologie","Environnement"]},
  {id:"mic5",prompt:"L'autoclavage standard : conditions :",choices:["100°C, 30 min, pression atmo","121°C, 15-20 min, 1 bar surpression","134°C, 1h, 3 bar","80°C, 2h, sans pression"],answer:1,diff:1,explication:"121°C, 1 bar surpression, 15-20 min. Alternative prions : 134°C, 2 bar, 18 min.",tags:["Microbiologie","Stérilisation"]},
  {id:"mic6",prompt:"Une colonie bactérienne provient :",choices:["De millions de bactéries différentes","D'une seule cellule bactérienne (clone)","D'un mélange de virus et bactéries","De cellules eucaryotes contaminées"],answer:1,diff:1,explication:"1 colonie = 1 clone issu d'1 UFC (Unité Formant Colonie). Base du dénombrement sur milieu solide.",tags:["Microbiologie","Dénombrement"]},
  {id:"mic7",prompt:"UFC signifie :",choices:["Unité de Filtration Contrôlée","Unité Formant Colonie","Unité de Fluorescence Calibrée","Unité Fonctionnelle de Contrôle"],answer:1,diff:1,explication:"UFC = Unité Formant Colonie. Unité de dénombrement des micro-organismes viables sur milieu solide.",tags:["Microbiologie","Dénombrement"]},
  {id:"mic8",prompt:"Le dénombrement par filtration sur membrane est adapté pour :",choices:["Des échantillons très concentrés","Des échantillons peu chargés (eaux, boissons)","Des échantillons solides uniquement","Des échantillons gazeux"],answer:1,diff:2,explication:"Filtration membrane 0.45 µm : concentre les bactéries d'un grand volume. Idéal eaux, boissons, cosmétiques.",tags:["Microbiologie","Dénombrement"]},
  {id:"mic9",prompt:"La méthode NPP (Nombre le Plus Probable) est basée sur :",choices:["Le comptage direct de colonies","Une estimation statistique à partir de tubes positifs/négatifs","La mesure de turbidité","La PCR quantitative"],answer:1,diff:2,explication:"NPP : dilutions en série dans milieu liquide. Lecture +/- par tube. Table statistique pour estimation.",tags:["Microbiologie","Dénombrement"]},
  {id:"mic10",prompt:"La croissance bactérienne en milieu liquide comprend les phases :",choices:["Lag, Log, Stationnaire, Déclin","Initiation, Élongation, Terminaison","G1, S, G2, M","Primaire, Secondaire, Tertiaire"],answer:0,diff:1,explication:"Lag (adaptation) → Log (exponentielle) → Stationnaire (équilibre) → Déclin (mort).",tags:["Microbiologie","Croissance"]},
  {id:"mic11",prompt:"Pendant la phase exponentielle (log), le temps de génération est :",choices:["Variable et imprévisible","Constant et minimal pour les conditions données","Toujours de 20 minutes","Infini"],answer:1,diff:2,explication:"Phase log : g constant (temps de doublement minimal). Ex: E. coli ≈ 20 min en conditions optimales.",tags:["Microbiologie","Croissance"]},
  {id:"mic12",prompt:"La DO (densité optique) à 600 nm mesure :",choices:["La concentration en ADN","La turbidité liée à la biomasse bactérienne","Le pH du milieu","La concentration en glucose"],answer:1,diff:1,explication:"DO600 = turbidimétrie. Corrélation avec la concentration bactérienne. Mesure rapide mais ne distingue pas vivants/morts.",tags:["Microbiologie","Mesure"]},
  {id:"mic13",prompt:"Un milieu chromogène permet :",choices:["D'enrichir un type de bactérie","D'identifier directement par la couleur des colonies (substrats chromogéniques)","De stériliser les échantillons","De conserver les souches"],answer:1,diff:2,explication:"Milieu chromogène : substrats qui libèrent un chromophore quand clivés par une enzyme spécifique. Ex: CHROMagar.",tags:["Microbiologie","Milieux"]},
  {id:"mic14",prompt:"Le test de catalase différencie :",choices:["Gram+ et Gram-","Staphylocoques (catalase+) et Streptocoques (catalase-)","Aérobies et anaérobies","Bacilles et cocci"],answer:1,diff:2,explication:"Catalase décompose H₂O₂ en H₂O + O₂ (bulles). Staph catalase+ vs Strep catalase-.",tags:["Microbiologie","Identification"]},
  {id:"mic15",prompt:"Le test d'oxydase détecte :",choices:["La présence de catalase","Le cytochrome c oxydase","La bêta-galactosidase","La coagulase"],answer:1,diff:2,explication:"Oxydase = cytochrome c oxydase. Positif : Pseudomonas, Neisseria. Négatif : Entérobactéries.",tags:["Microbiologie","Identification"]},
  {id:"mic16",prompt:"Un antibiogramme mesure :",choices:["La concentration minimale inhibitrice uniquement","La sensibilité d'une souche aux antibiotiques (S, I, R)","La vitesse de croissance","Le profil biochimique"],answer:1,diff:1,explication:"Antibiogramme : disques d'antibiotiques sur gélose Mueller-Hinton. Lecture diamètres d'inhibition → S/I/R.",tags:["Microbiologie","Antibiogramme"]},
  {id:"mic17",prompt:"La CMI (Concentration Minimale Inhibitrice) est :",choices:["La concentration maximale tolérée par le patient","La plus faible concentration d'antibiotique inhibant la croissance visible","La concentration qui tue 99.9% des bactéries","La dose prescrite au patient"],answer:1,diff:2,explication:"CMI = plus faible concentration inhibant la croissance in vitro. Déterminée par dilution en milieu liquide ou E-test.",tags:["Microbiologie","Antibiogramme"]},
  {id:"mic18",prompt:"Les milieux sélectifs contiennent :",choices:["Tous les nutriments sans restriction","Des inhibiteurs qui empêchent la croissance de certains micro-organismes","Uniquement de l'eau et de l'agar","Des antibiotiques thérapeutiques"],answer:1,diff:1,explication:"Agents sélectifs : sels biliaires (inhibe Gram+), antibiotiques, NaCl élevé (sélectionne Staphylocoques), etc.",tags:["Microbiologie","Milieux"]},
  {id:"mic19",prompt:"Un biofilm est :",choices:["Un film plastique pour emballer les géloses","Une communauté microbienne adhérente à une surface, protégée par une matrice","Un type de coloration","Une technique de dénombrement"],answer:1,diff:2,explication:"Biofilm : micro-organismes + matrice extracellulaire (polysaccharides, protéines, ADN). Résistance accrue aux biocides.",tags:["Microbiologie","Biofilm"]},
  {id:"mic20",prompt:"La stérilisation par rayonnements UV agit par :",choices:["Dénaturation des protéines","Formation de dimères de thymine dans l'ADN","Oxydation des lipides","Lyse osmotique"],answer:1,diff:2,explication:"UV 254 nm : formation de dimères de thymine → blocage réplication. Action de surface uniquement.",tags:["Microbiologie","Stérilisation"]},
  {id:"mic21",prompt:"Le contrôle de stérilité d'un autoclave utilise comme indicateur biologique :",choices:["Escherichia coli","Geobacillus stearothermophilus","Staphylococcus aureus","Bacillus subtilis"],answer:1,diff:2,explication:"G. stearothermophilus : spores très thermorésistantes. Si éliminées → cycle efficace. B. subtilis = chaleur sèche.",tags:["Microbiologie","Stérilisation"]},
  {id:"mic22",prompt:"La pasteurisation se distingue de la stérilisation par :",choices:["Elle utilise des produits chimiques","Elle réduit la charge microbienne sans éliminer toutes les formes (spores viables)","Elle est plus chaude que l'autoclave","Elle ne change pas le produit"],answer:1,diff:1,explication:"Pasteurisation : destruction formes végétatives pathogènes. Spores survivent. Stérilisation : destruction totale.",tags:["Microbiologie","Traitement thermique"]},
  {id:"mic23",prompt:"L'anaérobiose stricte nécessite :",choices:["Simplement fermer le couvercle de la boîte","Une atmosphère sans O₂ (jarre + générateur ou enceinte anaérobie)","De l'oxygène à 5%","Un incubateur à CO₂"],answer:1,diff:2,explication:"Anaérobies stricts : O₂ toxique. Jarres anaérobies (sachets générateurs H₂+CO₂) ou enceintes anaérobies.",tags:["Microbiologie","Culture"]},
  {id:"mic24",prompt:"La température d'incubation standard pour les bactéries pathogènes humaines est :",choices:["25°C","30°C","37°C","42°C"],answer:2,diff:1,explication:"37°C = température corporelle humaine. 25-30°C = environnement. 42°C = thermophiles/coliformes thermotolérants.",tags:["Microbiologie","Culture"]},
  {id:"mic25",prompt:"Le test de coagulase permet de distinguer :",choices:["E. coli de Salmonella","S. aureus (coagulase+) de S. epidermidis (coagulase-)","Gram+ de Gram-","Aérobies d'anaérobies"],answer:1,diff:2,explication:"Coagulase libre : coagulation du plasma de lapin. S. aureus = coagulase+. Autres staphylocoques = coagulase-.",tags:["Microbiologie","Identification"]},
  {id:"mic26",prompt:"Les galeries API permettent :",choices:["L'antibiogramme","L'identification biochimique miniaturisée","Le dénombrement","La coloration de Gram"],answer:1,diff:1,explication:"Galeries API : 20 tests biochimiques miniaturisés. Profil numérique → identification par base de données.",tags:["Microbiologie","Identification"]},
  {id:"mic27",prompt:"Le milieu Sabouraud est utilisé pour :",choices:["Les bactéries aérobies","Les levures et champignons","Les virus","Les parasites"],answer:1,diff:1,explication:"Sabouraud : pH acide (5.6) + glucose → favorise levures et moisissures. Incubation 25-30°C.",tags:["Microbiologie","Milieux"]},
  {id:"mic28",prompt:"La technique d'ensemencement en profondeur consiste à :",choices:["Étaler sur la surface de la gélose","Mélanger l'échantillon avec la gélose en surfusion avant solidification","Piquer la gélose avec un fil","Filtrer puis déposer le filtre"],answer:1,diff:2,explication:"En profondeur : inoculum mélangé à gélose fondue (45°C) avant coulage. Pour dénombrement quantitatif.",tags:["Microbiologie","Dénombrement"]},
  {id:"mic29",prompt:"La zone de comptage optimale sur une boîte de Petri est :",choices:["0 à 10 colonies","15 à 300 colonies (selon la norme)","Plus de 1000 colonies","Exactement 100 colonies"],answer:1,diff:2,explication:"Zone de comptage : 15-300 ou 10-300 selon normes. Trop peu = manque de représentativité. Trop = confluence.",tags:["Microbiologie","Dénombrement"]},
  {id:"mic30",prompt:"Les souches ATCC sont :",choices:["Des souches cliniques non caractérisées","Des souches de référence certifiées (American Type Culture Collection)","Des souches résistantes aux antibiotiques","Des souches génétiquement modifiées"],answer:1,diff:2,explication:"ATCC = collection de référence internationale. Souches caractérisées, traçables, pour CQ milieux et méthodes.",tags:["Microbiologie","CQ"]},
  {id:"mic31",prompt:"La méthode de dilution en milieu liquide pour la CMI utilise :",choices:["Des disques d'antibiotiques","Des concentrations croissantes d'antibiotique dans des tubes/puits","Des bandelettes imprégnées","La diffusion en gélose"],answer:1,diff:2,explication:"Microdilution en plaque 96 puits : concentrations doublantes. Lecture turbidité. CMI = premier puits clair.",tags:["Microbiologie","Antibiogramme"]},
  {id:"mic32",prompt:"Le test ELISA en microbiologie peut détecter :",choices:["Uniquement des bactéries vivantes","Des antigènes ou des anticorps (toxines, protéines microbiennes)","Uniquement de l'ADN","Uniquement des spores"],answer:1,diff:2,explication:"ELISA : réaction Ag-Ac + enzyme. Détection toxines (ex: toxine cholérique), Ag de surface, Ac anti-microbiens.",tags:["Microbiologie","Immunologie"]},
  {id:"mic33",prompt:"Un milieu d'enrichissement sert à :",choices:["Identifier directement les bactéries","Favoriser la multiplication d'un micro-organisme cible minoritaire","Quantifier précisément","Stocker les échantillons"],answer:1,diff:2,explication:"Enrichissement : milieu sélectif liquide qui favorise la cible. Ex: eau peptonée tamponnée pour Salmonella.",tags:["Microbiologie","Milieux"]},
  {id:"mic34",prompt:"Le bioréacteur de paillasse permet de contrôler :",choices:["Uniquement la température","Température, pH, pO₂, agitation, débit d'alimentation","Uniquement la pression","Le niveau sonore"],answer:1,diff:2,explication:"Bioréacteur : contrôle en ligne (T°, pH, pO₂, agitation) + mesures hors ligne (DO, substrats, métabolites).",tags:["Microbiologie","Bioréacteur"]},
  {id:"mic35",prompt:"Le suivi de la biomasse en bioréacteur peut se faire par :",choices:["Mesure de DO600 uniquement","DO600, poids sec, dénombrement UFC, mesure CO₂ produit","Observation visuelle uniquement","Mesure du pH uniquement"],answer:1,diff:2,explication:"Multi-paramètres : DO (en ligne), poids sec (hors ligne), UFC (hors ligne), CO₂ dégagé (en ligne).",tags:["Microbiologie","Bioréacteur"]},
];

const QB_BIOCHIMIE = [
  {id:"bio1",prompt:"La loi de Beer-Lambert relie :",choices:["Le pH à la concentration","L'absorbance à la concentration et au trajet optique","La fluorescence à la température","La masse à la vitesse"],answer:1,diff:1,explication:"A = ε × l × c. Absorbance proportionnelle à concentration, coefficient d'absorption molaire et trajet optique.",tags:["Biochimie","Spectrophotométrie"]},
  {id:"bio2",prompt:"Les conditions de validité de Beer-Lambert sont :",choices:["Solutions concentrées, lumière polychromatique","Solutions diluées, lumière monochromatique, pas d'interactions soluté-solvant","Toute concentration, toute lumière","Solutions gazeuses uniquement"],answer:1,diff:2,explication:"Limites : solutions diluées (<A=1), monochromaticité, pas de fluorescence/diffusion, cuve propre.",tags:["Biochimie","Spectrophotométrie"]},
  {id:"bio3",prompt:"En HPLC, la phase mobile est :",choices:["Le gel de la colonne","Le solvant qui entraîne les analytes à travers la colonne","Le détecteur","L'échantillon injecté"],answer:1,diff:1,explication:"Phase mobile = solvant (gradient ou isocratique). Phase stationnaire = remplissage colonne. Séparation par affinité différentielle.",tags:["Biochimie","HPLC"]},
  {id:"bio4",prompt:"Le temps de rétention en chromatographie dépend de :",choices:["La couleur de l'analyte","L'affinité de l'analyte pour la phase stationnaire vs mobile","Le volume injecté uniquement","La température ambiante uniquement"],answer:1,diff:2,explication:"Temps de rétention = temps analyte dans colonne. Plus d'affinité pour phase stationnaire → rétention plus longue.",tags:["Biochimie","Chromatographie"]},
  {id:"bio5",prompt:"L'électrophorèse sur gel de polyacrylamide (SDS-PAGE) sépare les protéines selon :",choices:["Leur charge native","Leur masse moléculaire (en conditions dénaturantes)","Leur couleur","Leur solubilité"],answer:1,diff:2,explication:"SDS dénature et charge négativement uniformément. Migration selon taille : petites protéines migrent plus loin.",tags:["Biochimie","Électrophorèse"]},
  {id:"bio6",prompt:"Le dosage Bradford utilise :",choices:["Le réactif de Folin (phosphomolybdique)","Le bleu de Coomassie G-250 qui se lie aux protéines","L'acide bicinchonique (BCA)","Le réactif de biuret"],answer:1,diff:2,explication:"Bradford : bleu Coomassie se lie aux protéines → décalage λmax 465→595 nm. Rapide, sensible, peu d'interférents.",tags:["Biochimie","Dosage protéique"]},
  {id:"bio7",prompt:"Le dosage BCA (acide bicinchonique) est basé sur :",choices:["La liaison directe du colorant aux protéines","La réduction Cu²⁺→Cu⁺ par les protéines, puis complexation Cu⁺-BCA","La fluorescence intrinsèque des protéines","L'absorption UV à 280 nm"],answer:1,diff:3,explication:"Réaction en 2 étapes : 1) Réduction cuivre par liaison peptidique. 2) Complexe Cu⁺-BCA violet (λ=562nm).",tags:["Biochimie","Dosage protéique"]},
  {id:"bio8",prompt:"La chromatographie d'exclusion (gel filtration) sépare selon :",choices:["La charge","La taille moléculaire (les grosses molécules sortent en premier)","L'hydrophobicité","L'affinité spécifique"],answer:1,diff:2,explication:"Exclusion stérique : grosses molécules exclues des pores → élution rapide. Petites molécules retardées dans les pores.",tags:["Biochimie","Chromatographie"]},
  {id:"bio9",prompt:"La chromatographie d'affinité utilise :",choices:["La différence de taille","Un ligand spécifique immobilisé qui retient sélectivement la cible","La différence de charge","La différence de volatilité"],answer:1,diff:2,explication:"Affinité : ligand sur colonne (Ac, substrat, Ni-NTA pour His-tag). Élution spécifique. Très haute pureté.",tags:["Biochimie","Chromatographie"]},
  {id:"bio10",prompt:"Le Km d'une enzyme représente :",choices:["La vitesse maximale de la réaction","La concentration de substrat pour laquelle V = Vmax/2","L'énergie d'activation","Le nombre de sites actifs"],answer:1,diff:2,explication:"Km = concentration en substrat donnant la demi-vitesse maximale. Km bas = forte affinité enzyme-substrat.",tags:["Biochimie","Enzymologie"]},
  {id:"bio11",prompt:"Un dosage ELISA sandwich comporte :",choices:["Un seul anticorps","Deux anticorps : un de capture fixé + un de détection marqué","Trois anticorps identiques","Aucun anticorps, seulement un antigène"],answer:1,diff:2,explication:"Sandwich ELISA : Ac capture (adsorbé) → Ag cible → Ac détection (conjugué enzyme). Très spécifique.",tags:["Biochimie","Immunologie"]},
  {id:"bio12",prompt:"La spectrophotométrie UV à 260 nm mesure :",choices:["Les protéines","Les acides nucléiques","Les glucides","Les lipides"],answer:1,diff:1,explication:"Bases azotées des AN absorbent à 260 nm. Protéines à 280 nm (Trp, Tyr, Phe).",tags:["Biochimie","Spectrophotométrie"]},
  {id:"bio13",prompt:"Le ratio A260/A280 pour un ADN pur est environ :",choices:["1.0","1.8","2.0","2.5"],answer:1,diff:2,explication:"ADN pur ≈ 1.8. ARN pur ≈ 2.0. Ratio bas = contamination protéique. Ratio élevé = contamination ARN (si ADN attendu).",tags:["Biochimie","Acides nucléiques"]},
  {id:"bio14",prompt:"La CPG (Chromatographie en Phase Gazeuse) nécessite que l'analyte soit :",choices:["Soluble dans l'eau","Volatilisable ou dérivable en composé volatil","Coloré","Chargé électriquement"],answer:1,diff:2,explication:"CPG : analyte en phase gazeuse dans le gaz vecteur (He, N₂, H₂). Composés non volatils = dérivation chimique.",tags:["Biochimie","Chromatographie"]},
  {id:"bio15",prompt:"Un détecteur UV en HPLC mesure :",choices:["La masse des analytes","L'absorbance des analytes à une longueur d'onde donnée","La conductivité","La fluorescence"],answer:1,diff:1,explication:"Détecteur UV(-vis) : mesure A à λ fixe ou variable (DAD = barrette de diodes, spectre complet).",tags:["Biochimie","HPLC"]},
];

const QB_BIOMOL = [
  {id:"bm1",prompt:"La PCR amplifie :",choices:["Des protéines","Un fragment spécifique d'ADN","Des cellules entières","Des anticorps"],answer:1,diff:1,explication:"PCR = Polymerase Chain Reaction. Amplification exponentielle d'une séquence cible d'ADN.",tags:["Bio mol","PCR"]},
  {id:"bm2",prompt:"Les 3 étapes d'un cycle PCR sont :",choices:["Lyse, extraction, purification","Dénaturation, hybridation, élongation","Fixation, coloration, observation","Centrifugation, décantation, filtration"],answer:1,diff:1,explication:"1) Dénaturation (94-98°C). 2) Hybridation amorces (50-65°C). 3) Élongation (72°C). Répéter 25-40 cycles.",tags:["Bio mol","PCR"]},
  {id:"bm3",prompt:"La Taq polymérase est utilisée en PCR car :",choices:["Elle fonctionne à 37°C","Elle est thermorésistante (résiste à 94-98°C)","Elle copie l'ARN","Elle n'a pas besoin d'amorces"],answer:1,diff:1,explication:"Taq (Thermus aquaticus) : stable à haute T°. Pas de relais d'enzyme après chaque cycle de dénaturation.",tags:["Bio mol","PCR"]},
  {id:"bm4",prompt:"La marche en avant en biologie moléculaire signifie :",choices:["Travailler de gauche à droite","Ne jamais revenir d'une zone post-PCR vers pré-PCR","Pipeter du concentré au dilué","Commencer par l'étape la plus longue"],answer:1,diff:1,explication:"Marche en avant : pré-PCR → PCR → post-PCR. Sens unique pour éviter contaminations par amplicons.",tags:["Bio mol","PCR","Contamination"]},
  {id:"bm5",prompt:"En qPCR, le Ct (Cycle threshold) est :",choices:["Le dernier cycle d'amplification","Le cycle où la fluorescence dépasse le seuil de détection","Le cycle de dénaturation","Le temps total de la PCR"],answer:1,diff:2,explication:"Ct = cycle seuil. Fluorescence > bruit de fond. Ct bas = beaucoup de cible initiale. Relation log-linéaire.",tags:["Bio mol","qPCR"]},
  {id:"bm6",prompt:"La SYBR Green en qPCR :",choices:["Se lie spécifiquement à une séquence cible","S'intercale dans tout ADN double brin (non spécifique)","Marque les protéines","Mesure le pH"],answer:1,diff:2,explication:"SYBR Green = intercalant ADN double brin → fluorescence. Non spécifique : détecte aussi dimères d'amorces.",tags:["Bio mol","qPCR"]},
  {id:"bm7",prompt:"Les sondes TaqMan offrent par rapport au SYBR Green :",choices:["Moins de spécificité","Plus de spécificité (sonde complémentaire de la cible)","Un coût moindre","Aucune différence"],answer:1,diff:2,explication:"TaqMan : sonde oligonucléotidique spécifique (fluorophore + quencher). Clivée par activité 5'→3' exonucléase de la Taq.",tags:["Bio mol","qPCR"]},
  {id:"bm8",prompt:"L'extraction d'ADN comprend typiquement :",choices:["Uniquement la centrifugation","Lyse cellulaire → élimination protéines → purification AN → élution","Uniquement l'ébullition","Congélation à -80°C"],answer:1,diff:1,explication:"1) Lyse (détergent/mécanique). 2) Protéinase K / phénol-chloroforme. 3) Adsorption colonne ou précipitation. 4) Élution.",tags:["Bio mol","Extraction"]},
  {id:"bm9",prompt:"Le ratio A260/A230 contrôle la contamination par :",choices:["Les protéines","Les solvants organiques (phénol, guanidine, sels)","Les glucides","Les lipides"],answer:1,diff:2,explication:"A260/A230 attendu : 2.0-2.2. Ratio bas = contamination par phénol, guanidine, EDTA, sels co-précipités.",tags:["Bio mol","Qualité AN"]},
  {id:"bm10",prompt:"L'électrophorèse sur gel d'agarose sépare les fragments d'ADN selon :",choices:["Leur séquence","Leur taille (les petits fragments migrent plus loin)","Leur charge spécifique","Leur degré de méthylation"],answer:1,diff:1,explication:"ADN chargé négativement (phosphates) migre vers +. Gel d'agarose tamise selon la taille. Marqueur de PM pour calibration.",tags:["Bio mol","Électrophorèse"]},
  {id:"bm11",prompt:"Les enzymes de restriction coupent l'ADN :",choices:["De manière aléatoire","Au niveau de séquences palindromiques spécifiques","Uniquement en 5'","Uniquement les ARN"],answer:1,diff:2,explication:"Enzymes de restriction (endonucléases) : reconnaissance séquence palindromique (4-8 pb). Coupure bouts francs ou cohésifs.",tags:["Bio mol","Restriction"]},
  {id:"bm12",prompt:"Le bromure d'éthidium (BET) est utilisé pour :",choices:["Colorer les protéines","Révéler l'ADN dans les gels par fluorescence UV (intercalant)","Mesurer le pH","Dénaturer l'ADN"],answer:1,diff:1,explication:"BET s'intercale entre les bases. Fluorescent sous UV. Mutagène → SYBR Safe comme alternative plus sûre.",tags:["Bio mol","Électrophorèse"]},
  {id:"bm13",prompt:"La RT-PCR (Reverse Transcription PCR) permet de :",choices:["Amplifier directement de l'ARN","Convertir l'ARN en ADNc puis amplifier par PCR","Séquencer de l'ADN","Faire une PCR plus rapide"],answer:1,diff:2,explication:"RT (reverse transcriptase) : ARN → ADNc. Puis PCR classique sur ADNc. Quantifie l'expression des gènes (ARNm).",tags:["Bio mol","RT-PCR"]},
  {id:"bm14",prompt:"La DNase dégrade :",choices:["L'ARN","L'ADN","Les protéines","Les lipides"],answer:1,diff:1,explication:"DNase = désoxyribonucléase. Dégrade ADN. RNase dégrade ARN. Protéase dégrade protéines.",tags:["Bio mol","Nucléases"]},
  {id:"bm15",prompt:"Pour travailler avec de l'ARN, il faut impérativement :",choices:["Travailler en conditions RNase-free (gants, matériel traité DEPC)","Utiliser du BET","Travailler à 42°C","Utiliser uniquement des pipettes en verre"],answer:0,diff:2,explication:"ARN très sensible aux RNases (ubiquitaires, résistantes). Gants, matériel RNase-free, DEPC, pointes à filtre.",tags:["Bio mol","ARN"]},
];

const QB_BIOCELL = [
  {id:"bc1",prompt:"La culture de cellules eucaryotes nécessite :",choices:["Un simple incubateur bactériologique","Un incubateur à CO₂ (5%), PSM II, milieu complet + SVF","Uniquement une hotte chimique","Un bioréacteur obligatoirement"],answer:1,diff:1,explication:"Cellules eucaryotes : 37°C, 5% CO₂ (tampon carbonate), PSM II (asepsie), milieu DMEM/RPMI + 10% SVF + antibiotiques.",tags:["Bio cell","Culture"]},
  {id:"bc2",prompt:"Le SVF (Sérum de Veau Fœtal) apporte :",choices:["Uniquement des antibiotiques","Facteurs de croissance, hormones, protéines d'attachement","De l'ADN viral","Du glucose uniquement"],answer:1,diff:2,explication:"SVF : facteurs de croissance, fibronectine (adhésion), albumine (transport), hormones. 5-20% selon lignée.",tags:["Bio cell","Culture"]},
  {id:"bc3",prompt:"La confluence cellulaire est :",choices:["Le nombre total de cellules","Le pourcentage de surface de culture recouvert par les cellules","Le ratio cellules vivantes/mortes","La vitesse de division"],answer:1,diff:1,explication:"Confluence : estimation visuelle du recouvrement. Passage (trypsine) quand 80-90% de confluence.",tags:["Bio cell","Culture"]},
  {id:"bc4",prompt:"La trypsine-EDTA sert à :",choices:["Colorer les cellules","Détacher les cellules adhérentes de leur support","Fixer les cellules","Congeler les cellules"],answer:1,diff:1,explication:"Trypsine (protéase) + EDTA (chélateur Ca²⁺) : clivent les protéines d'adhésion. Inactivée par ajout de SVF.",tags:["Bio cell","Culture"]},
  {id:"bc5",prompt:"Le test au bleu trypan évalue :",choices:["La croissance cellulaire","La viabilité (cellules mortes colorées en bleu, vivantes réfringentes)","L'activité métabolique","La concentration en protéines"],answer:1,diff:1,explication:"Bleu trypan : colorant d'exclusion. Membranes intactes (vivantes) excluent le colorant. Mortes = bleues.",tags:["Bio cell","Viabilité"]},
  {id:"bc6",prompt:"Le test MTT mesure :",choices:["La viabilité membranaire","L'activité métabolique mitochondriale (cellules viables)","La concentration ADN","Le nombre de divisions"],answer:1,diff:2,explication:"MTT réduit par enzymes mitochondriales → formazan violet. Absorbance proportionnelle aux cellules métaboliquement actives.",tags:["Bio cell","Viabilité"]},
  {id:"bc7",prompt:"La congélation des cellules eucaryotes utilise comme cryoprotecteur :",choices:["Le glycérol uniquement","Le DMSO (diméthylsulfoxyde) ou le glycérol","L'éthanol 70%","La formaldéhyde"],answer:1,diff:2,explication:"DMSO 5-10% : pénètre les cellules, empêche formation cristaux de glace. Congélation lente (-1°C/min) puis -80°C → azote liquide.",tags:["Bio cell","Conservation"]},
  {id:"bc8",prompt:"Le nombre de passages (P) d'une lignée cellulaire :",choices:["N'a pas d'importance","Doit être suivi car les cellules peuvent dériver génétiquement","Ne change jamais les propriétés","Est limité à 2"],answer:1,diff:2,explication:"Passages élevés → dérive génétique, modification phénotype, sénescence. Utiliser passages bas, banque de travail.",tags:["Bio cell","Culture"]},
  {id:"bc9",prompt:"La cellule de Malassez ou Thoma permet de :",choices:["Colorer les cellules","Compter les cellules sous microscope (dénombrement en cellule de comptage)","Centrifuger les cellules","Congeler les cellules"],answer:1,diff:1,explication:"Hémocytomètre : volume connu sous lamelle. Comptage au microscope. Calcul : N cellules × facteur dilution × 10⁴/mL.",tags:["Bio cell","Dénombrement"]},
  {id:"bc10",prompt:"La cytotoxicité d'une molécule est évaluée par :",choices:["La coloration de Gram","Des tests de viabilité cellulaire (MTT, bleu trypan, LDH)","La PCR","L'antibiogramme"],answer:1,diff:2,explication:"Tests in vitro sur lignées cellulaires : dose-réponse → IC50 (concentration inhibant 50% de la viabilité).",tags:["Bio cell","Toxicologie"]},
];

const QB_CQ = [
  {id:"cq1",prompt:"Le CQI (Contrôle Qualité Interne) surveille :",choices:["La conformité des produits finis","La stabilité du processus analytique au fil du temps","La satisfaction client","Les délais de livraison"],answer:1,diff:1,explication:"CQI : étalons-contrôle passés dans chaque série. Suivi sur carte de contrôle. Détecte dérives et erreurs.",tags:["CQ"]},
  {id:"cq2",prompt:"Le CQA (Contrôle Qualité Externe) évalue :",choices:["La fidélité intra-labo","L'exactitude par comparaison inter-laboratoires (EEQ)","La vitesse d'analyse","Le coût par analyse"],answer:1,diff:1,explication:"CQA/EEQ : échantillon aveugle envoyé par organisme externe. Résultat comparé à la valeur consensuelle.",tags:["CQ","EEQ"]},
  {id:"cq3",prompt:"Sur une carte de Levey-Jennings, ±2σ correspond à :",choices:["Zone d'alerte (avertissement)","Zone de rejet","Zone de conformité","Limite de détection"],answer:0,diff:2,explication:"±1σ : acceptable. ±2σ : avertissement (warning). ±3σ : rejet. Règles de Westgard combinent ces zones.",tags:["CQ","Westgard"]},
  {id:"cq4",prompt:"La règle de Westgard 1-3s signifie :",choices:["1 valeur dépasse ±2σ","1 valeur dépasse ±3σ → rejet de la série","3 valeurs consécutives au-delà de ±1σ","Le premier contrôle de la journée"],answer:1,diff:2,explication:"1-3s : 1 valeur au-delà de ±3σ = erreur aléatoire probable. Rejet de la série, investigation obligatoire.",tags:["CQ","Westgard"]},
  {id:"cq5",prompt:"La règle 2-2s de Westgard indique :",choices:["2 valeurs dans les ±2σ","2 valeurs consécutives dépassent ±2σ du même côté → erreur systématique","2 valeurs consécutives quelconques","2 séries en 2 jours"],answer:1,diff:3,explication:"2-2s : 2 CQ consécutifs > +2σ ou < -2σ. Suggère erreur systématique (biais). Investigation du processus.",tags:["CQ","Westgard"]},
  {id:"cq6",prompt:"La règle R-4s détecte :",choices:["Une erreur systématique","Une erreur aléatoire (dispersion entre 2 CQ > 4σ)","Un problème de stockage","Une erreur de pipetage"],answer:1,diff:3,explication:"R-4s : différence entre 2 CQ de la même série > 4σ. Erreur aléatoire majeure.",tags:["CQ","Westgard"]},
  {id:"cq7",prompt:"La règle 10x de Westgard signifie :",choices:["10 valeurs consécutives du même côté de la moyenne → biais","10 valeurs dans les ±2σ","10 analyses en 10 minutes","10% d'erreur acceptable"],answer:0,diff:3,explication:"10x : 10 CQ consécutifs tous au-dessus ou en-dessous de la moyenne. Biais systématique évident.",tags:["CQ","Westgard"]},
  {id:"cq8",prompt:"Si un CQ est hors limites, la première action est :",choices:["Ignorer et continuer","Bloquer la série, vérifier (recalibration, réactifs, pipettes), repassage","Valider si les résultats patients semblent corrects","Changer de méthode"],answer:1,diff:1,explication:"CQ hors limites → STOP. Investiguer (5M). Recalibrer si nécessaire. Repasser les CQ. Ne libérer qu'après validation CQ.",tags:["CQ"]},
  {id:"cq9",prompt:"L'écart-type (σ) en CQ représente :",choices:["La valeur moyenne des contrôles","La dispersion des valeurs autour de la moyenne","Le nombre de contrôles","L'erreur maximale tolérée"],answer:1,diff:1,explication:"σ = mesure de la dispersion. Plus σ est petit, plus le processus est fidèle (reproductible).",tags:["CQ","Statistiques"]},
  {id:"cq10",prompt:"Le CV% (Coefficient de Variation) exprime :",choices:["La justesse","La fidélité relative (σ/moyenne × 100)","La linéarité","La sensibilité"],answer:1,diff:2,explication:"CV% = (σ/moyenne) × 100. Permet de comparer la fidélité entre différents niveaux de concentration.",tags:["CQ","Statistiques"]},
  {id:"cq11",prompt:"La norme ISO 5725 traite de :",choices:["La sécurité des produits chimiques","L'exactitude (justesse + fidélité) des méthodes de mesure","La gestion environnementale","La sécurité alimentaire"],answer:1,diff:2,explication:"ISO 5725 : 6 parties. Principes, méthodes de détermination, mesures intermédiaires de fidélité, justesse.",tags:["CQ","ISO"]},
  {id:"cq12",prompt:"La validation d'une méthode alternative selon ISO 16140 comprend :",choices:["Un simple test sur 5 échantillons","Une étude de comparaison avec la méthode de référence (sensibilité, spécificité)","Uniquement une revue de la littérature","L'avis d'un seul expert"],answer:1,diff:2,explication:"ISO 16140 : étude préliminaire + étude de validation (sensibilité, spécificité, inclusivité, exclusivité).",tags:["CQ","Validation","ISO"]},
];

const QB_ANNALE_2024_MICRO = [
  {id:"a24m1",prompt:"Cronobacter sakazakii est classé comme :",choices:["Bacille Gram+, sporulant","Bacille Gram-, aéro-anaérobie facultatif, non sporulant, Enterobacteriaceae","Coque Gram+, catalase positive","Bacille Gram-, aérobie strict, oxydase positif"],answer:1,diff:2,explication:"C. sakazakii : bacille Gram-, famille Enterobacteriaceae, aéro-anaérobie facultatif, non sporulant. Pousse entre 6 et 45°C, optimum 37-43°C.",tags:["Microbiologie","Cronobacter","Annale 2024"]},
  {id:"a24m2",prompt:"Les populations cibles de Cronobacter sakazakii sont principalement :",choices:["Les adultes en bonne santé","Les nourrissons de moins de 6 mois et les prématurés","Les personnes âgées uniquement","Les animaux d'élevage"],answer:1,diff:1,explication:"C. sakazakii : pathogène opportuniste, touche principalement nourrissons <6 mois et prématurés. Méningite néonatale, entérocolite nécrosante, septicémie. Mortalité 15-80%.",tags:["Microbiologie","Cronobacter","Annale 2024"]},
  {id:"a24m3",prompt:"Le mécanisme infectieux de C. sakazakii implique dans l'ordre :",choices:["Sporulation → germination → invasion","Attachement apical → invasion apicale → disruption des jonctions → invasion basolatérale","Toxine → lyse cellulaire → hémorragie","Adhésion → conjugaison → transfert de plasmide"],answer:1,diff:3,explication:"D'après le document 1 du sujet : attachement apical aux cellules épithéliales, invasion apicale, rupture des jonctions serrées (tight) et adhérentes, puis invasion basolatérale.",tags:["Microbiologie","Cronobacter","Pouvoir pathogène","Annale 2024"]},
  {id:"a24m4",prompt:"L'Aw (activité de l'eau) des préparations en poudre pour nourrissons est de l'ordre de :",choices:["0,99 (très élevée)","0,85 (intermédiaire)","0,20 (très faible)","0,50 (modérée)"],answer:2,diff:2,explication:"Aw ≈ 0,2 pour les poudres déshydratées. C. sakazakii peut survivre jusqu'à 2 ans à Aw de 0,14-0,27 grâce à des mécanismes d'osmorégulation.",tags:["Microbiologie","Cronobacter","Aw","Annale 2024"]},
  {id:"a24m5",prompt:"Pour résister au stress osmotique de la dessiccation, Cronobacter accumule :",choices:["Des lipides de réserve","Du potassium intracellulaire (K⁺) et des solutés compatibles (tréhalose, proline, glycine)","De l'ADN circulaire","Des pigments caroténoïdes"],answer:1,diff:3,explication:"Osmorégulation : accumulation K⁺ intracellulaire + synthèse solutés compatibles (tréhalose, proline, glycine bétaïne). Maintien de la turgescence et protection des protéines.",tags:["Microbiologie","Cronobacter","Physiologie","Annale 2024"]},
  {id:"a24m6",prompt:"Le temps de génération de Cronobacter à 23°C dans une préparation reconstituée est de 40 min. Cela signifie :",choices:["La bactérie meurt toutes les 40 minutes","La population bactérienne double toutes les 40 minutes","Il faut 40 minutes pour identifier la bactérie","La bactérie produit une toxine en 40 minutes"],answer:1,diff:1,explication:"Temps de génération (g) = temps de doublement de la population. À 23°C, g = 40 min. À 10°C, g = 300 min. La température basse ralentit considérablement la multiplication.",tags:["Microbiologie","Croissance","Temps de génération","Annale 2024"]},
  {id:"a24m7",prompt:"À 10°C, le temps de génération de Cronobacter passe à 300 min (vs 40 min à 23°C). Quelle conclusion pour la conservation du biberon reconstitué ?",choices:["La température n'a pas d'impact sur la croissance","La réfrigération ralentit considérablement la multiplication, le biberon doit être conservé au froid","L'ébullition est la seule solution","La congélation est obligatoire"],answer:1,diff:2,explication:"g passe de 40 min (23°C) à 300 min (10°C) : facteur ×7,5 de ralentissement. Conservation au froid indispensable pour limiter la prolifération si le biberon n'est pas consommé immédiatement.",tags:["Microbiologie","Cronobacter","Conservation","Annale 2024"]},
  {id:"a24m8",prompt:"L'OMS recommande de reconstituer les préparations en poudre avec de l'eau à plus de :",choices:["37°C","50°C","70°C","100°C"],answer:2,diff:1,explication:"OMS : eau > 70°C pour reconstitution. Réduit significativement la charge en Cronobacter. Consommation dans les 2h après préparation.",tags:["Microbiologie","Cronobacter","OMS","Annale 2024"]},
  {id:"a24m9",prompt:"D'après les courbes de thermotolérance du sujet (doc 5), à quelle température Cronobacter est-il éliminé le plus rapidement ?",choices:["48°C","52°C","56°C","66°C"],answer:3,diff:2,explication:"À 66°C : chute rapide de log UFC/mL (de ~9 à <1 en quelques minutes). À 48°C : pratiquement pas d'effet. À 52°C : réduction lente. La recommandation OMS (>70°C) est justifiée.",tags:["Microbiologie","Cronobacter","Thermotolérance","Annale 2024"]},

  {id:"a24m10",prompt:"Dans le diagramme de fabrication (doc 6), le CCP (Critical Control Point) est :",choices:["La réception du lait","La pasteurisation","Le conditionnement","Le stockage vrac"],answer:1,diff:2,explication:"La pasteurisation est identifiée comme CCP : étape de traitement thermique maîtrisant le danger biologique. Mais elle ne suffit pas seule car des contaminations post-pasteurisation sont possibles.",tags:["Microbiologie","HACCP","CCP","Annale 2024"]},
  {id:"a24m11",prompt:"Pourquoi la pasteurisation seule ne garantit-elle pas la sécurité du produit fini ?",choices:["Parce qu'elle détruit les vitamines","Parce que des contaminations post-pasteurisation sont possibles (zone sèche, conditionnement, ajout d'ingrédients)","Parce qu'elle est trop chaude","Parce qu'elle ne fonctionne que sur les virus"],answer:1,diff:2,explication:"Contaminations possibles après pasteurisation : ajout d'ingrédients secs (non pasteurisés), zone de séchage, conditionnement, environnement de production. D'où la nécessité de PRP/PMS.",tags:["Microbiologie","HACCP","Contamination","Annale 2024"]},
  {id:"a24m12",prompt:"Les étapes de formation d'un biofilm sont dans l'ordre :",choices:["Adhésion → matrice → quorum sensing → dispersion","Déposition cellulaire → adsorption → quorum sensing → sécrétion matrice → détachement/dispersion","Sporulation → germination → colonisation","Multiplication → adhésion → résistance"],answer:1,diff:3,explication:"D'après doc 4 : 1) Cell deposition, 2) Cell adsorption, 3) Quorum sensing, 4) Secretion of matrix, 5) Detachment/erosion, 6) Dispersion of planktonic bacteria.",tags:["Microbiologie","Biofilm","Annale 2024"]},
  {id:"a24m13",prompt:"Le quorum sensing dans la formation d'un biofilm implique :",choices:["La détection de la lumière","La production de molécules signal (AHL chez Gram-, peptides auto-inducteurs chez Gram+)","La sporulation","La conjugaison bactérienne"],answer:1,diff:3,explication:"Quorum sensing : communication intercellulaire densité-dépendante. Gram- : N-acyl homosérine lactones (AHL). Gram+ : peptides auto-inducteurs. Déclenche la formation de la matrice.",tags:["Microbiologie","Biofilm","Quorum sensing","Annale 2024"]},
  {id:"a24m14",prompt:"Deux stratégies de lutte contre les biofilms en industrie sont :",choices:["Augmenter la température ambiante et ajouter du sucre","Nettoyage/désinfection régulier avec agents anti-biofilm + choix de matériaux limitant l'adhésion","Utiliser des antibiotiques dans le produit + UV","Congeler les installations + irradiation gamma"],answer:1,diff:2,explication:"Stratégies : 1) NEP (Nettoyage En Place) avec agents enzymatiques/oxydants anti-biofilm, alternance acide/base. 2) Matériaux à faible adhérence (inox poli, surfaces hydrophobes). Aussi : rinçage fréquent, séchage.",tags:["Microbiologie","Biofilm","NEP","Annale 2024"]},
  {id:"a24m15",prompt:"La différence entre nettoyage et désinfection est :",choices:["Ce sont des synonymes","Le nettoyage élimine les souillures visibles, la désinfection réduit la charge microbienne à un niveau acceptable","Le nettoyage utilise des biocides, la désinfection du savon","Le nettoyage est chimique, la désinfection est physique"],answer:1,diff:1,explication:"Nettoyage = élimination physico-chimique des résidus organiques et minéraux. Désinfection = réduction des micro-organismes (biocides). Toujours nettoyer AVANT de désinfecter.",tags:["Microbiologie","Nettoyage","Désinfection","Annale 2024"]},
  {id:"a24m16",prompt:"Le NEP (Nettoyage En Place) a pour avantage par rapport au nettoyage manuel :",choices:["Il est moins cher","Il est standardisé, reproductible, traçable et adapté aux circuits fermés","Il n'utilise pas de produits chimiques","Il ne nécessite aucun contrôle"],answer:1,diff:2,explication:"NEP (CIP) : automatisé, standardisé (temps, T°, concentration, débit). Reproductibilité et traçabilité supérieures au nettoyage manuel. Adapté aux tuyauteries, cuves, échangeurs.",tags:["Microbiologie","NEP","Annale 2024"]},
  {id:"a24m17",prompt:"L'ANSES recommande de vérifier l'efficacité du séchage des installations car :",choices:["L'eau résiduelle n'a aucun impact","L'eau résiduelle favorise la multiplication microbienne et la formation de biofilms","Le séchage améliore le goût du produit","C'est une obligation légale uniquement"],answer:1,diff:2,explication:"Eau résiduelle = conditions favorables à la prolifération microbienne, surtout en zones de haute hygiène. Suivi hygrométrie en continu recommandé.",tags:["Microbiologie","ANSES","Hygiène","Annale 2024"]},

  {id:"a24m18",prompt:"La norme NF EN ISO 18593 décrit les méthodes de prélèvement de surface. La boîte contact (impression sur gélose) est adaptée pour :",choices:["Les surfaces planes et lisses","Les surfaces irrégulières et les recoins","Les liquides","Les poudres"],answer:0,diff:2,explication:"Boîte contact : surfaces planes et lisses. Écouvillonnage : surfaces irrégulières, recoins, joints. Chiffonnette : grandes surfaces. Chaque méthode a ses avantages et limites.",tags:["Microbiologie","Prélèvement surface","ISO 18593","Annale 2024"]},
  {id:"a24m19",prompt:"L'écouvillonnage est préféré à la boîte contact pour :",choices:["Les surfaces planes uniquement","Les surfaces irrégulières, les recoins, les joints, les équipements complexes","Les analyses d'air","Le contrôle des eaux"],answer:1,diff:2,explication:"Écouvillon (sec ou humide) : accès aux zones difficiles, recoins, joints, tapis convoyeurs. Limite : moins standardisé que boîte contact (pression, surface variable).",tags:["Microbiologie","Prélèvement surface","Annale 2024"]},
  {id:"a24m20",prompt:"Pour le contrôle microbiologique d'un tapis convoyeur en sortie d'atomiseur, la méthode la plus adaptée serait :",choices:["La boîte contact (surface plane non démontable)","L'écouvillonnage humide (surface complexe, recoins)","La filtration sur membrane","Le biocollecteur"],answer:1,diff:3,explication:"Tapis convoyeur = surface irrégulière avec joints et bords. L'écouvillonnage humide permet d'accéder aux zones critiques. La chiffonnette pour les grandes surfaces planes serait aussi envisageable.",tags:["Microbiologie","Prélèvement surface","Annale 2024"]},
  {id:"a24m21",prompt:"Dans le règlement (CE) 2073/2005, un « critère de sécurité » se distingue d'un « critère d'hygiène » car :",choices:["Le critère de sécurité concerne la conformité du produit mis sur le marché (danger pour le consommateur), le critère d'hygiène vérifie le bon fonctionnement du procédé","Ce sont des synonymes","Le critère de sécurité est moins strict","Le critère d'hygiène concerne uniquement les mains du personnel"],answer:0,diff:2,explication:"Critère sécurité : pathogènes dans le produit fini (Listeria, Salmonella, Cronobacter) → retrait si non conforme. Critère hygiène : indicateurs de process (entérobactéries, B. cereus) → actions correctives sur le procédé.",tags:["Microbiologie","Réglementation","CE 2073/2005","Annale 2024"]},
  {id:"a24m22",prompt:"Dans le plan d'échantillonnage du règlement 2073/2005, n = 30 et c = 0 pour Salmonella dans les préparations pour nourrissons signifie :",choices:["30 échantillons testés, aucun ne doit être positif (tolérance zéro)","30 grammes analysés, 0 colonie attendue","3 échantillons sur 10 peuvent être positifs","Le test est facultatif"],answer:0,diff:2,explication:"n = nombre d'unités à analyser (30), c = nombre maximum d'unités pouvant dépasser la limite (0). c=0 = tolérance zéro : tous les échantillons doivent être conformes.",tags:["Microbiologie","Échantillonnage","Réglementation","Annale 2024"]},
  {id:"a24m23",prompt:"La méthode horizontale de recherche de Cronobacter spp. (NF EN ISO 22964) comprend les étapes :",choices:["Enrichissement en eau peptonée tamponnée → enrichissement sélectif (CSB) → isolement chromogène (CCI) → repiquage TSA → confirmation biochimique","Ensemencement direct sur gélose → lecture","Filtration sur membrane → incubation","PCR directe sur le produit"],answer:0,diff:3,explication:"5 étapes : 1) Pré-enrichissement non sélectif (EPT, 18h, 34-38°C), 2) Enrichissement sélectif (CSB, 24h, 41.5°C), 3) Isolement sur gélose chromogène CCI (24h, 41.5°C), 4) Repiquage colonies sur TSA, 5) Confirmation biochimique.",tags:["Microbiologie","Cronobacter","ISO 22964","Méthode horizontale","Annale 2024"]},
  {id:"a24m24",prompt:"L'intérêt des deux premières étapes du protocole de recherche de Cronobacter (pré-enrichissement + enrichissement sélectif) est de :",choices:["Identifier directement la bactérie","Revivifier les bactéries stressées puis favoriser sélectivement Cronobacter avant isolement","Quantifier précisément la contamination","Détruire les bactéries concurrentes par UV"],answer:1,diff:2,explication:"1) Pré-enrichissement (EPT) : revivification des bactéries sublétalement stressées (dessiccation). 2) Enrichissement sélectif (CSB, 41.5°C) : multiplication sélective de Cronobacter tout en inhibant la flore compétitrice.",tags:["Microbiologie","Cronobacter","Enrichissement","Annale 2024"]},

  {id:"a24m25",prompt:"Le principe du MALDI-TOF pour l'identification bactérienne repose sur :",choices:["La coloration différentielle des protéines","La désorption/ionisation laser des protéines bactériennes suivie de séparation par temps de vol (m/z)","L'amplification de l'ADN ribosomal","La culture sur milieu chromogène"],answer:1,diff:3,explication:"MALDI-TOF : échantillon co-cristallisé avec matrice → désorption/ionisation par laser UV → accélération → séparation par temps de vol (TOF) selon rapport m/z → spectre protéique comparé à une base de données.",tags:["Microbiologie","MALDI-TOF","Identification","Annale 2024"]},
  {id:"a24m26",prompt:"L'avantage principal du MALDI-TOF par rapport aux méthodes biochimiques traditionnelles (galeries API) est :",choices:["Il est moins cher","Il permet une identification rapide (minutes vs 24-48h) à partir d'une seule colonie","Il ne nécessite aucun équipement","Il fonctionne sans culture préalable"],answer:1,diff:2,explication:"MALDI-TOF : identification en quelques minutes à partir d'une colonie isolée. API/automates : 18-48h supplémentaires. Coût par analyse faible malgré investissement initial élevé.",tags:["Microbiologie","MALDI-TOF","Annale 2024"]},
  {id:"a24m27",prompt:"Le MALDI-TOF identifie les bactéries en comparant le spectre protéique obtenu à :",choices:["Une table de Gram","Une base de données de spectres de référence","Un antibiogramme","Un arbre phylogénétique ADN"],answer:1,diff:2,explication:"Le spectre de masse (fingerprint protéique, principalement protéines ribosomiques) est comparé à une base de données de spectres de référence (Biotyper de Bruker, VITEK MS de bioMérieux).",tags:["Microbiologie","MALDI-TOF","Annale 2024"]},
  {id:"a24m28",prompt:"La validation du MALDI-TOF comme méthode alternative de confirmation sur milieu CCI est régie par :",choices:["La norme ISO 17025","La norme ISO 16140-6","La norme ISO 9001","Aucune norme, c'est empirique"],answer:1,diff:3,explication:"ISO 16140-6 : validation des méthodes alternatives propriétaires (MicroVal). Le MALDI-TOF Bruker est validé pour confirmation des colonies suspectes sur CCI.",tags:["Microbiologie","MALDI-TOF","ISO 16140","Validation","Annale 2024"]},
  {id:"a24m29",prompt:"En appliquant la règle des 5M au danger Cronobacter dans les poudres, la cause « Milieu » inclurait :",choices:["La formation du personnel","L'hygrométrie, la température, le zonage (zones sèches/humides), la présence de biofilms","Le choix du milieu de culture","La date de péremption"],answer:1,diff:2,explication:"5M appliqué à Cronobacter : Milieu = environnement de production (hygrométrie, zonage, biofilms, circuits d'eau, air). Matière = MP contaminées, Méthode = barèmes pasteurisation, Main-d'œuvre = hygiène personnel, Matériel = état surfaces.",tags:["Microbiologie","5M","HACCP","Cronobacter","Annale 2024"]},
  {id:"a24m30",prompt:"C. sakazakii peut adhérer à de nombreux matériaux abiotiques. Lequel n'est PAS cité dans le sujet ?",choices:["Silicone et latex","Acier inoxydable et verre","Bois et coton","Polycarbonate et PVC"],answer:2,diff:2,explication:"D'après le document 2 : silicone, latex, polycarbonate, acier inoxydable, verre, PVC. Le bois et le coton ne sont pas cités (et sont d'ailleurs proscrits en industrie alimentaire).",tags:["Microbiologie","Cronobacter","Biofilm","Matériaux","Annale 2024"]},
  {id:"a24m31",prompt:"Les structures bactériennes impliquées dans la formation d'un biofilm sont principalement :",choices:["Le noyau et les mitochondries","Les pili/fimbriae (adhésion), les flagelles (déplacement), les exopolysaccharides (matrice)","Les plasmides et les transposons","Les endospores"],answer:1,diff:3,explication:"Adhésion initiale : pili/fimbriae, adhésines de surface. Déplacement vers la surface : flagelles. Formation matrice : exopolysaccharides (EPS), ADN extracellulaire, protéines. Nature biochimique : glucides (EPS), protéines, ADN.",tags:["Microbiologie","Biofilm","Structures bactériennes","Annale 2024"]},
  {id:"a24m32",prompt:"La thermotolérance de Cronobacter est un facteur majeur car :",choices:["Elle permet à la bactérie de survivre aux traitements thermiques modérés (pasteurisation basse)","Elle empêche toute méthode de stérilisation","Elle rend les antibiotiques inefficaces","Elle n'a pas d'impact sur la sécurité"],answer:0,diff:2,explication:"Certaines souches résistent à 56°C pendant >10 min. La pasteurisation flash (72°C/15s) élimine mais des contaminations post-pasteurisation restent le risque principal.",tags:["Microbiologie","Cronobacter","Thermotolérance","Annale 2024"]},
];

const QB_ANNALE_2024_STBI = [
  {id:"stbi1",prompt:"Le diagramme de Pareto (règle des 80/20) en industrie alimentaire est utilisé pour :",choices:["Classer les fournisseurs par prix","Identifier les 20% de causes qui génèrent 80% des problèmes (réclamations, non-conformités), pour prioriser les actions correctives","Planifier les audits annuels","Calculer la valeur pasteurisatrice"],answer:1,diff:1,explication:"Pareto (Vilfredo Pareto, 1848-1923) : principe d'optimisation. En qualité : 20% des causes → 80% des effets. Représentation graphique (histogramme trié + courbe cumulative). Permet de focaliser les efforts sur les causes les plus impactantes.",tags:["Qualité","Pareto","80/20","Réclamations","Annale 2024 STBI"]},
  {id:"stbi2",prompt:"La différence entre un CCP (Critical Control Point) et un PRPop (Programme Prérequis Opérationnel) selon la méthode HACCP est :",choices:["Ce sont des synonymes","Le CCP élimine ou réduit le danger à un niveau acceptable (mesure de maîtrise critique), le PRPop maîtrise la probabilité d'introduction du danger sans être le dernier recours","Le PRPop est plus strict que le CCP","Un CCP concerne uniquement les dangers microbiologiques"],answer:1,diff:2,explication:"CCP : point de maîtrise critique dont la perte entraîne un danger inacceptable pour le consommateur (ex : pasteurisation). PRPop : mesure importante mais pas ultime (ex : refroidissement contrôlant les moisissures — si défaillance, d'autres contrôles existent). Arbre décisionnel Codex Alimentarius.",tags:["HACCP","CCP","PRPop","Sécurité alimentaire","Annale 2024 STBI"]},
  {id:"stbi3",prompt:"La méthode des 5M (Ishikawa) permet d'identifier les causes potentielles d'une non-conformité selon :",choices:["Méthode, Matière, Matériel, Main-d'œuvre, Milieu","Mesure, Machine, Microbe, Matière, Management","Méthode, Maintenance, Masse, Milieu, Métal","Procédé, Personne, Produit, Plan, Prix"],answer:0,diff:1,explication:"5M (diagramme d'Ishikawa / arête de poisson) : Main-d'œuvre (compétences), Matière (MP, ingrédients), Matériel (équipements), Milieu (environnement, T°, hygrométrie), Méthode (procédure). Outil d'analyse de causes racines pour toute NC.",tags:["Qualité","5M","Ishikawa","HACCP","Annale 2024 STBI"]},
  {id:"stbi4",prompt:"Les farines de type 55 (T55) et T45 se différencient principalement par :",choices:["Leur couleur (blanche vs marron)","Leur taux de cendres (T45 < T55 < T65 < T80 < T110 < T150) reflet du taux d'extraction : plus le type est élevé, plus la farine contient de son","Leur teneur en gluten","Leur granulométrie uniquement"],answer:1,diff:2,explication:"Type de farine = taux de cendres × 1000. T45 : très blanche, faible extraction. T55 : standard pâtisserie. T65 : boulangerie. T80 : semi-complète. T110/T150 : complète/intégrale. Plus le type ↑ → plus de son (enveloppe) → plus de minéraux, fibres, mais moins de gluten actif.",tags:["Bioindustriel","Farine","Types de farines","Cendres","Annale 2024 STBI"]},
  {id:"stbi5",prompt:"La valeur pasteurisatrice (VP) est calculée par :",choices:["VP = T × t","VP = t × 10^((T - Tréf)/z)","VP = Log(UFC) / temps","VP = T / z"],answer:1,diff:2,explication:"VP = t × 10^((T - Tréf)/z). t = durée en secondes/minutes, T = température de traitement, Tréf = température de référence du microorganisme cible, z = facteur de résistance thermique (élévation de T pour réduire D d'un facteur 10). Ex : Tréf = 70°C, z = 7°C pour Enterococcus faecalis (ovoproduits).",tags:["Bioindustriel","Pasteurisation","Valeur pasteurisatrice","Thermique","Annale 2024 STBI"]},
  {id:"stbi6",prompt:"Pour une pasteurisation à 64,4°C pendant 2,5 min avec Tréf = 70°C et z = 7°C, la valeur pasteurisatrice est :",choices:["VP ≈ 0,16","VP ≈ 0,50","VP ≈ 2,5","VP ≈ 16"],answer:0,diff:3,explication:"VP = 2,5 × 10^((64,4 - 70)/7) = 2,5 × 10^(-0,8) = 2,5 × 0,158 ≈ 0,40. Barème de référence (Codex) : 20s à 70°C → VP = 0,33. Ce traitement est équivalent (VP ≈ 0,40 > 0,33 → efficace). NB : la réponse exacte dépend du calcul précis.",tags:["Bioindustriel","Pasteurisation","Calcul VP","Annale 2024 STBI"]},
  {id:"stbi7",prompt:"L'Aw (activité de l'eau) d'une madeleine spécifiée à 0,65 signifie :",choices:["La teneur en eau est de 65%","L'eau disponible pour les micro-organismes est réduite (rapport pression vapeur eau / pression vapeur eau pure). Aw = 0,65 limite la croissance des bactéries (minimum ~0,90) et moisissures (minimum ~0,70-0,80)","L'humidité relative de l'air autour est 65%","65% de l'eau est évaporée lors de la cuisson"],answer:1,diff:2,explication:"Aw (Water Activity) = p/p₀. Aw = 1 (eau pure). Limites de croissance : bactéries > 0,90 ; levures > 0,85 ; moisissures > 0,70-0,80 (Aspergillus > 0,70). Madeleine Aw 0,65 → croissance microbienne très limitée. Contrôle par dessiccation, sucre (confiture), sel (salaison).",tags:["Bioindustriel","Aw","Activité de l'eau","Sécurité alimentaire","Annale 2024 STBI"]},
  {id:"stbi8",prompt:"Dans un pasteurisateur à plaques, le principe d'échange thermique est :",choices:["Chauffage par micro-ondes","Échange indirect par convection : le fluide chaud et le fluide froid circulent en sens contraires (contre-courant) de part et d'autre de plaques métalliques (acier inox) — jamais en contact direct","Refroidissement par évaporation","Échange par rayonnement infrarouge"],answer:1,diff:2,explication:"Pasteurisateur à plaques (PHE) : fluide alimentaire et fluide caloporteur (eau chaude ou vapeur) circulent en contre-courant de part et d'autre de plaques inox ondulées (grande surface d'échange). Sections : chauffage → chambreur (maintien T°) → refroidissement. Économie d'énergie par régénération.",tags:["Bioindustriel","Pasteurisation","Échangeur à plaques","Thermique","Annale 2024 STBI"]},
  {id:"stbi9",prompt:"Le chambreur (holding tube) dans un pasteurisateur a pour rôle de :",choices:["Refroidir le produit rapidement","Maintenir le produit à la température de pasteurisation pendant la durée requise (garantit que tous les points du produit atteignent T° × t minimum)","Concentrer le produit","Filtrer les impuretés"],answer:1,diff:2,explication:"Chambreur : tube de maintien de longueur calculée pour que le produit reste à T° pendant la durée t. Garantit l'atteinte de la valeur pasteurisatrice cible pour toutes les particules (y compris le centre du tube). Dimensionné selon le débit et la viscosité du produit.",tags:["Bioindustriel","Pasteurisation","Chambreur","Thermique","Annale 2024 STBI"]},
  {id:"stbi10",prompt:"Les autocontrôles en cours de fabrication de biscuits incluent le contrôle de l'humidité car :",choices:["L'humidité augmente la valeur nutritive","Une humidité résiduelle trop élevée favorise le développement de moisissures (Aw trop haute) et réduit la durée de vie du produit","L'humidité améliore la texture uniquement","La réglementation l'interdit au-dessus de 5%"],answer:1,diff:1,explication:"Humidité résiduelle (spécification : 8,0 ± 0,2% pour les madeleines) → détermine l'Aw → conditionne la stabilité microbiologique. Contrôle par étuvage (méthode de référence) ou NIR (mesure en ligne, rapide). Dépassement → risque de moisissures pendant le stockage.",tags:["Bioindustriel","Humidité","Autocontrôle","Moisissures","Annale 2024 STBI"]},
  {id:"stbi11",prompt:"La pasteurisation est préférable à la stérilisation pour les ovoproduits (coule d'œuf) car :",choices:["Elle est moins efficace","Les protéines de l'œuf (ovalbumine, conalbumine) sont dénaturées et les propriétés fonctionnelles (foisonnement, gélification) sont détruites à des températures trop élevées","Elle coûte moins cher","Les œufs sont déjà stériles"],answer:1,diff:2,explication:"Œuf : protéines fonctionnelles sensibles à la chaleur (Td ovalbumine ~84°C, conalbumine ~60°C). Pasteurisation douce (64,4°C/2,5 min ou 60°C/3,5 min) : inactivation Salmonella + conservation des propriétés technologiques (émulsification, foisonnement). Stérilisation : dénaturation protéique totale.",tags:["Bioindustriel","Ovoproduits","Pasteurisation","Protéines de l'œuf","Annale 2024 STBI"]},
  {id:"stbi12",prompt:"Le cahier des charges (CdC) d'un produit alimentaire définit :",choices:["Uniquement le prix de vente","L'ensemble des spécifications techniques (composition, propriétés physico-chimiques, microbiologiques, sensorielles, emballage, étiquetage) auxquelles le produit doit répondre","Les recettes de fabrication uniquement","Le planning de production"],answer:1,diff:1,explication:"Cahier des charges : document contractuel entre producteur et donneur d'ordre. Contient : composition (formule), physico-chimie (pH, Aw, humidité), critères microbiologiques, propriétés organoleptiques, emballage, étiquetage réglementaire, DLC/DLUO. Référence pour les autocontrôles et la traçabilité.",tags:["Qualité","Cahier des charges","Spécifications","Bioindustriel","Annale 2024 STBI"]},
];

const QB_ANNALE_2024_BICM = [
  {id:"a24bc1",prompt:"L'EPO (érythropoïétine) est une cytokine produite principalement par :",choices:["Le foie chez l'adulte","Le rein (cellules péritubulaires interstitielles du cortex) en réponse à l'hypoxie","Les lymphocytes T","La moelle osseuse elle-même"],answer:1,diff:1,explication:"EPO : glycoprotéine (hormone) produite à 90% par les cellules péritubulaires du cortex rénal. Stimulus : hypoxie (détectée par le facteur HIF-1α). Stimule l'érythropoïèse : prolifération des progéniteurs érythroïdes dans la moelle osseuse.",tags:["Biologie cellulaire","EPO","Erythropoïèse","Dopage","Annale 2024"]},
  {id:"a24bc2",prompt:"La voie de signalisation intracellulaire activée par la fixation de l'EPO sur son récepteur EPOR fait intervenir :",choices:["La voie MAPK/ERK uniquement","La kinase JAK2 et le facteur de transcription STAT5 (voie JAK2/STAT5)","La voie PKA/AMPc","Le récepteur tyrosine kinase RET"],answer:1,diff:2,explication:"EPOR est un récepteur sans activité enzymatique intrinsèque. Fixation EPO → dimérisation EPOR → activation JAK2 (Janus kinase 2) → phosphorylation STAT5 → translocation nucléaire → transcription gènes de survie et prolifération (Bcl-xL, cyclines).",tags:["Biologie cellulaire","EPO","JAK2","STAT5","Signal transduction","Annale 2024"]},
  {id:"a24bc3",prompt:"L'inhibition de l'apoptose par l'EPO dans les précurseurs érythroïdes est importante car :",choices:["Elle ralentit la différenciation des globules rouges","Elle permet aux précurseurs de survivre assez longtemps pour se différencier en érythrocytes matures (effet synergique avec la prolifération)","Elle augmente la masse osseuse","Elle bloque la synthèse d'hémoglobine"],answer:1,diff:2,explication:"EPO → activation Bcl-xL (anti-apoptotique) → survie des précurseurs érythroïdes. Combiné à la stimulation de la prolifération → augmentation nette de la production d'érythrocytes. En dopage, cet effet est exploité pour augmenter le transport en O₂.",tags:["Biologie cellulaire","Apoptose","EPO","Erythropoïèse","Annale 2024"]},
  {id:"a24bc4",prompt:"La darbépoétine (Aranesp™) se distingue de l'EPO endogène par :",choices:["Une masse moléculaire identique (30 kDa)","Une masse moléculaire plus élevée (38 kDa), 5 N-glycanes (vs 3), une affinité réduite pour EPOR (÷5) mais une demi-vie 5 fois plus longue (25h vs 4-5h)","Une structure identique à l'EPO naturelle","Une absence de glycosylations"],answer:1,diff:3,explication:"Darbépoétine : 5 mutations + 2 N-glycanes supplémentaires → Mw 38 kDa. Affinité EPOR divisée par 5 mais demi-vie prolongée (25h vs 4-5h) → administration 1 à 2 fois par mois (vs 3×/semaine pour époétine). Avantage clinique et pour le dopage.",tags:["Biologie cellulaire","Darbépoétine","ERA","Dopage","Annale 2024"]},
  {id:"a24bc5",prompt:"Le Western Blot (immunoempreinte) permet de :",choices:["Amplifier un fragment d'ADN spécifique","Séparer des protéines par électrophorèse SDS-PAGE puis les détecter par des anticorps spécifiques après transfert sur membrane","Séquencer une protéine","Quantifier une enzyme par activité catalytique"],answer:1,diff:1,explication:"Western Blot : 1) SDS-PAGE (séparation taille) 2) Transfert sur membrane (nitrocellulose/PVDF) 3) Blocage (lait/BSA) 4) Anticorps primaire (anti-protéine cible) 5) Anticorps secondaire conjugué (HRP ou fluorescence) 6) Révélation (ECL ou fluorescence).",tags:["Biologie cellulaire","Western Blot","Protéines","Immunodétection","Annale 2024"]},
  {id:"a24bc6",prompt:"Les Dried Blood Spots (DBS — gouttes de sang séchées sur papier buvard) présentent l'avantage par rapport aux échantillons d'urine pour le contrôle antidopage :",choices:["Ils contiennent plus d'EPO","Ils sont plus stables dans le temps et permettent un prélèvement moins invasif (doigt piqué)","Ils sont moins coûteux à analyser","Ils ne nécessitent aucune réfrigération"],answer:1,diff:2,explication:"DBS : meilleure stabilité des ERAs dans le temps (moindre dégradation protéique), prélèvement simplifié, facilité de transport/stockage. Inconvénient : volume d'échantillon limité → méthode très sensible requise. Utilisé pour les JO Paris 2024.",tags:["Biologie cellulaire","DBS","Anti-dopage","EPO","Annale 2024"]},
  {id:"a24bc7",prompt:"Dans le milieu DMEM utilisé pour la culture de cellules musculaires, le sérum de veau fœtal (SVF) est ajouté car il contient :",choices:["Un agent bactériostatique","Des facteurs de croissance, hormones, vitamines et protéines de transport indispensables à la prolifération et survie cellulaire","Du glucose uniquement","Un tampon pH"],answer:1,diff:2,explication:"SVF (FBS) : source complexe de facteurs de croissance (EGF, IGF, FGF), hormones (insuline, cortisol), protéines de transport (albumine, transferrine), lipides et minéraux. À 10% généralement. Alternative : SVF défini/sérum sans SVF (xénofree) pour productions biopharmaceutiques.",tags:["Biologie cellulaire","Culture cellulaire","DMEM","SVF","Annale 2024"]},
  {id:"a24bc8",prompt:"Lors d'un passage cellulaire (sub-culture), la trypsine-EDTA est utilisée pour :",choices:["Tuer les cellules contaminées","Détacher les cellules adhérentes en hydrolysant les protéines membranaires et en chélatant le calcium (EDTA)","Stériliser le milieu","Marquer les cellules mortes"],answer:1,diff:1,explication:"Trypsine (protéase sérine) : clive les protéines d'adhésion (fibronectine, intégrines). EDTA (chélateur Ca²⁺) : inhibe les cadhérines calcium-dépendantes. Traitement court (1-5 min à 37°C) suivi de neutralisation par milieu complet (inhibiteurs sériques).",tags:["Biologie cellulaire","Culture cellulaire","Passage","Trypsine","Annale 2024"]},
  {id:"a24bc9",prompt:"Si la concentration en cellules est 2,2 × 10⁶ cellules/mL et qu'on veut ensemencer un flacon T-75 à 4,4 × 10⁴ cellules/cm², le volume à prélever est :",choices:["0,15 mL","1,5 mL","15 mL","0,015 mL"],answer:1,diff:2,explication:"Nombre total de cellules requis : 4,4 × 10⁴ × 75 = 3,3 × 10⁶ cellules. Volume = n_cellules / concentration = 3,3 × 10⁶ / 2,2 × 10⁶ = 1,5 mL.",tags:["Biologie cellulaire","Culture cellulaire","Calcul","Ensemencement","Annale 2024"]},
  {id:"a24bc10",prompt:"Le dopage génétique à l'EPO consiste à :",choices:["Injecter de l'EPO recombinante exogène","Modifier génétiquement des cellules musculaires autologues pour les rendre hyperproductrices d'EPO endogène, puis les réinjecter","Augmenter la production de globules rouges par hypoxie en altitude","Transfuser du sang autologue"],answer:1,diff:2,explication:"Dopage génétique : biopsie musculaire → culture primaire → modification génétique (vecteur viral ou non viral) → cellules deviennent productrices d'EPO → réinjection intramusculaire → production continue d'EPO endogène indétectable par méthodes classiques.",tags:["Biologie cellulaire","Dopage génétique","EPO","Annale 2024"]},
  {id:"a24bc11",prompt:"La sonde xGen utilisée pour la détection du dopage génétique est un outil de :",choices:["PCR quantitative directe","Capture hybridation : sonde biotinylée (hybride à la séquence d'intérêt) + billes streptavidine (capture) → enrichissement de l'ADN cible avant séquençage","Immunodétection des protéines","Électrophorèse capillaire"],answer:1,diff:3,explication:"xGen probes : oligonucléotides biotinylés qui hybrident avec les séquences d'ADN cibles. Les complexes hybride-biotine sont capturés par billes magnétiques couplées à la streptavidine → élution → ADN enrichi → PCR → séquençage. Utilisé pour le NGS ciblé.",tags:["Biologie moléculaire","xGen","Capture hybridation","NGS","Annale 2024"]},
  {id:"a24bc12",prompt:"La loi française n° 2023-380 du 19 mai 2023 relative aux JO Paris 2024 autorise dans le cadre antidopage :",choices:["Le séquençage du génome complet de tous les sportifs","Des tests ADN ciblés sur les prélèvements biologiques pour détecter : sang homologue, substitution d'échantillon, mutations génétiques, manipulation génétique somatique","L'utilisation d'ERA non détectables","Le dopage à l'EPO endogène uniquement"],answer:1,diff:2,explication:"Loi 2023-380 : 4 cas autorisés pour comparaison génétique antidopage (article L232-12-2) : 1) administration sang homologue, 2) substitution d'échantillon, 3) mutation génétique induisant production endogène substance interdite, 4) manipulation génétique somatique pour augmenter la performance.",tags:["Biologie cellulaire","Dopage génétique","Législation","JO 2024","Annale 2024"]},
  {id:"a24bc13",prompt:"Pour une détection fiable du dopage par Western Blot sur DBS, les critères de validation de la méthode incluent notamment :",choices:["Uniquement la spécificité","La sensibilité (limite de détection), la spécificité (pas de faux positifs), la répétabilité, et la stabilité des analytes dans la matrice","Uniquement le prix de revient","Le nombre d'échantillons traités par heure"],answer:1,diff:2,explication:"Validation d'une méthode de détection : spécificité (pas de réaction croisée), sensibilité/LOD (plus petite quantité détectable), répétabilité, reproductibilité, linéarité, stabilité. Selon ISO 17025 / WADA Technical Document.",tags:["Biologie cellulaire","Validation méthode","Western Blot","Anti-dopage","Annale 2024"]},
  {id:"a24bc14",prompt:"Les cellules primaires issues d'une biopsie musculaire se distinguent des lignées cellulaires établies (ex : HEK293) par :",choices:["Leur capacité de multiplication illimitée","Leur durée de vie limitée en culture (vieillissement, sénescence), leur meilleur reflet du tissu d'origine, et l'absence d'immortalisation","Leur résistance aux antibiotiques","Leur absence de noyau"],answer:1,diff:2,explication:"Cellules primaires : directement issues d'un tissu, non immortalisées → durée de vie limitée (vieillissement = sénescence réplicative après ~50 passages selon la loi de Hayflick). Avantage : réponse physiologique plus réaliste. Inconvénient : variabilité inter-donneurs, durée de vie courte.",tags:["Biologie cellulaire","Cellules primaires","Culture cellulaire","Annale 2024"]},
  {id:"a24bc15",prompt:"Le contrôle de la qualité de l'eau ultrapure utilisée dans les milieux de culture et les solutions tampon se fait notamment par mesure de :",choices:["L'absorbance à 280 nm","La résistivité électrique (eau ultrapure : ≥ 18,2 MΩ·cm à 25°C) et l'absence de contaminants biologiques (endotoxines)","La densité optique","La viscosité"],answer:1,diff:2,explication:"Eau ultrapure (type I selon ISO 3696) : résistivité ≥ 18.2 MΩ·cm (absence d'ions). Contrôles : résistivité en continu, COT (carbone organique total), endotoxines (LAL test), bactéries (filtration 0.22 µm). Essentielle pour la culture cellulaire et la biologie moléculaire.",tags:["Biologie cellulaire","Eau ultrapure","Qualité","Culture cellulaire","Annale 2024"]},
];

const QB_ANNALE_2023_BIO = [
  {id:"a23b1",prompt:"Le PLA (PolyLactic Acid) est un bioplastique produit à partir de :",choices:["Pétrole brut","Acide lactique issu de la fermentation de biodéchets (cellulose, déchets organiques)","Protéines animales","Acide acétique"],answer:1,diff:1,explication:"PLA = polymère de l'acide lactique, biosourcé et biodégradable. Produit à partir de biodéchets agro-industriels (cellulose hydrolysée → glucose → fermentation lactique → acide lactique). Applications : emballages, filaments impression 3D.",tags:["Biochimie","PLA","Bioplastique","Annale 2023"]},
  {id:"a23b2",prompt:"La cellulase hydrolyse la cellulose en clivant :",choices:["Les liaisons α-1,4 osidiques","Les liaisons β-1,4 osidiques entre les résidus β-D-glucopyranose","Les liaisons peptidiques","Les liaisons phosphodiester"],answer:1,diff:2,explication:"Cellulose : polymère de β-D-glucopyranose reliés par des liaisons β-1,4 osidiques. La cellulase (endoglucanase) hydrolyse ces liaisons → libération de glucose. Différence avec l'amidon (liaisons α-1,4, hydrolysé par les amylases).",tags:["Biochimie","Cellulase","Cellulose","Annale 2023"]},
  {id:"a23b3",prompt:"Dans la voie de fermentation lactique, le pyruvate est réduit en lactate afin de :",choices:["Produire de l'ATP supplémentaire","Régénérer le NAD⁺ consommé par la glycolyse (maintien du flux glycolytique en anaérobie)","Produire du CO₂","Former de l'acétyl-CoA"],answer:1,diff:2,explication:"Bilan fermentation lactique : glucose → 2 pyruvate → 2 lactate. La réduction pyruvate → lactate (LDH) régénère le NAD⁺ → la glycolyse peut continuer en absence d'O₂. Bilan énergétique : 2 ATP nets par glucose (uniquement glycolyse).",tags:["Biochimie","Fermentation lactique","NAD+","Glycolyse","Annale 2023"]},
  {id:"a23b4",prompt:"La production de PLA nécessite un acide lactique optiquement pur car :",choices:["Le D-lactate est toxique","Les propriétés mécaniques et de dégradation du PLA dépendent de la stéréochimie (poly-D-LA vs poly-L-LA)","Le L-lactate est moins stable","Les deux isomères sont identiques en pratique"],answer:1,diff:2,explication:"PLA stéréochimie : PLLA (poly-L-lactide), PDLA, PDLLA (mélange). Les polymères stéréopurs ont des propriétés différentes : Tm (point de fusion), cristallinité, vitesse de biodégradation. Un mélange racémique donne un amorphe inférieur.",tags:["Biochimie","PLA","Stéréochimie","Isomères optiques","Annale 2023"]},
  {id:"a23b5",prompt:"La colonne HPLC Aminex utilisée dans l'annale 2023 sépare les acides organiques selon :",choices:["Uniquement l'hydrophobicité","La taille moléculaire (exclusion-diffusion) ET les charges (échange d'ions)","Uniquement la charge ionique","La polarité"],answer:1,diff:3,explication:"Colonne Aminex HP-87H (Bio-Rad) : résine échangeuse de cations H⁺. Séparation combinant exclusion diffusion (steric exclusion) + échange ionique + partition. Utilisée pour glucides et acides organiques (acide lactique, acétique...). Détecteur réfractométrique.",tags:["Biochimie","HPLC","Aminex","Chromatographie","Annale 2023"]},
  {id:"a23b6",prompt:"Dans le dosage enzymatique de l'acide lactique, la variation d'absorbance à 340 nm reflète :",choices:["La concentration en protéines","La production ou consommation de NADH (ε = 6300 L·mol⁻¹·cm⁻¹ à 340 nm)","La turbidité de la solution","La concentration en glucose"],answer:1,diff:2,explication:"NADH absorbe à 340 nm (ε = 6300 L·mol⁻¹·cm⁻¹). Dans le dosage enzymatique : lactate + NAD⁺ ← LDH → pyruvate + NADH. ΔA₃₄₀ ∝ Δ[NADH] ∝ [lactate]. Beer-Lambert : A = ε·l·c → calcul de la concentration.",tags:["Biochimie","NADH","340 nm","Dosage enzymatique","Annale 2023"]},
  {id:"a23b7",prompt:"Une colonne HPLC chirale (type Chirex-D-pénicillamine avec CuSO₄) est utilisée pour :",choices:["Séparer les molécules par taille","Séparer les énantiomères (isomères optiques D et L) d'une même molécule","Séparer les protéines des glucides","Séparer par masse moléculaire"],answer:1,diff:3,explication:"Colonne chirale : phase stationnaire asymétrique (ligand chiral). Séparation des énantiomères par formation de complexes diastéréomères (différentes affinités). Nécessaire pour dosage séparé des isomères D- et L-lactate quand les enzymes ne sont pas disponibles.",tags:["Biochimie","Chromatographie chirale","Énantiomères","HPLC","Annale 2023"]},
  {id:"a23b8",prompt:"Listeria monocytogenes est classée dans les critères de sécurité (règlement CE 2073/2005) plutôt que d'hygiène car :",choices:["Elle est rare","Elle présente un danger direct pour le consommateur (pathogène à déclaration obligatoire) → retrait/rappel si non conforme","Elle est difficile à cultiver","Les critères d'hygiène sont réservés aux virus"],answer:1,diff:2,explication:"Critère de sécurité : micro-organisme pathogène dont la présence dans le produit fini constitue un danger pour le consommateur (zoonose, méningite listérienne). Non-conformité → retrait de marché. Critère d'hygiène : indicateur de procédé (actions correctives si dépassement).",tags:["Microbiologie","Listeria","Règlement 2073/2005","Sécurité alimentaire","Annale 2023"]},
  {id:"a23b9",prompt:"La gélose ALOA (Agar Listeria selon Ottaviani et Agosti) est qualifiée de :",choices:["Non sélective et non différentielle","Sélective ET différentielle : sélective par antibiotiques, différentielle par réaction enzymatique (β-glucosidase) donnant des colonies bleues-vertes avec halo opaque pour L. monocytogenes","Milieu d'enrichissement","Milieu d'isolement non chromogène"],answer:1,diff:2,explication:"ALOA : sélective (agents inhibiteurs : acide nalidixique, acriflavine, ceftazidime) + différentielle par chromogène enzymatique. L. monocytogenes : β-glucosidase (colonie bleue-verte) + phosphatidylinositol phospholipase C (PIPLC → halo opaque blanchâtre).",tags:["Microbiologie","Listeria","ALOA","Milieu chromogène","Annale 2023"]},
  {id:"a23b10",prompt:"L'utilisation de bactériophages pour décontaminer les surfaces en industrie alimentaire présente l'avantage :",choices:["De détruire tous les micro-organismes indistinctement","D'être très spécifique (un phage cible une bactérie particulière) et d'être d'origine naturelle (acceptable en bio)","D'être moins efficace que les ammoniums quaternaires","D'être inerte sur les biofilms"],answer:1,diff:2,explication:"Phages : spécificité hôte (phage anti-Listeria ne cible que Listeria). Naturels, biodégradables, sans résidu chimique. Limitation : coût de production, spectre étroit, résistance bactérienne possible, réglementation (utilisation limitée en Europe comme additif).",tags:["Microbiologie","Bactériophages","Listeria","Décontamination","Annale 2023"]},
  {id:"a23b11",prompt:"Le titre d'une suspension de phages est exprimé en :",choices:["UFC/mL","UFP/mL (Unités Formatrices de Plages de lyse par mL)","DO à 600 nm","Nombre d'anticorps/mL"],answer:1,diff:2,explication:"UFP/mL (ou PFU/mL en anglais : Plaque Forming Units). Titrage : dépôt de dilutions de suspension phagique sur une culture bactérienne en milieu gélosé → comptage des plages de lyse (zones de clairance circulaires).",tags:["Microbiologie","Bactériophages","Titre","Annale 2023"]},
  {id:"a23b12",prompt:"Le potentiel de croissance (Δ) selon la norme NF EN ISO 20976-1 est calculé par :",choices:["Δ = log UFC/mL initial - log UFC/mL final","Δ = log UFC/mL final - log UFC/mL initial (variation de population bactérienne au cours du test de croissance)","Δ = DO finale/DO initiale","Δ = taux de mortalité"],answer:1,diff:2,explication:"Potentiel de croissance : Δ = log N_max - log N_0. Si Δ < 0.5 log UFC/g → non favorisant la croissance (NFC). Si Δ ≥ 0.5 log UFC/g → favorisant la croissance (FC). Utilisé pour évaluer si un aliment favorise ou non la multiplication d'un pathogène.",tags:["Microbiologie","Potentiel de croissance","ISO 20976","Listeria","Annale 2023"]},
  {id:"a23b13",prompt:"L'extrait de levure dans un milieu de culture microbiologique est ajouté pour :",choices:["Sa sélectivité anti-fongique","Apporter des facteurs de croissance (vitamines B, acides aminés, minéraux) que certaines bactéries ne peuvent pas synthétiser","Augmenter la viscosité","Inhiber les Gram-positifs"],answer:1,diff:2,explication:"Extrait de levure : source de vitamines B (biotine, riboflavine, B12...), acides aminés, purines/pyrimidines. Complète les digestats protéiques (qui apportent acides aminés et peptides). Essentiel pour les bactéries auxotrophes (incapables de synthétiser certains métabolites).",tags:["Microbiologie","Milieux de culture","Listeria","Annale 2023"]},
  {id:"a23b14",prompt:"Bacillus coagulans utilisé pour la production d'acide lactique est un thermophile. Son avantage dans ce contexte est :",choices:["Il est plus pathogène","Il peut fermenter à des températures élevées (50-55°C) permettant l'utilisation simultanée de cellulases thermostables et limitant les contaminations","Il produit exclusivement du L-lactate","Il n'utilise que le glucose"],answer:1,diff:3,explication:"B. coagulans (sporulant, thermotolérant) : optimum 50-55°C. Avantages : T° élevée compatible avec les cellulases thermostables + réduit le risque de contamination de la culture. Production d'acide L ou D-lactique selon la souche.",tags:["Microbiologie","Bacillus coagulans","Thermophile","Fermentation lactique","Annale 2023"]},
  {id:"a23b15",prompt:"La loi française du 10 février 2020 (anti-gaspillage) impose le tri des biodéchets depuis :",choices:["Janvier 2022","Janvier 2024","Janvier 2026","Janvier 2020"],answer:1,diff:1,explication:"Loi AGEC (Anti-Gaspillage pour une Économie Circulaire) du 10 février 2020 : obligation de tri à la source des biodéchets pour tous les producteurs depuis le 1er janvier 2024. Objectif : valorisation (compostage, méthanisation, production de biomolécules).",tags:["Biochimie","Réglementation","Biodéchets","Annale 2023"]},
];

const QB_FERMENTATION = [
  {id:"ferm1",prompt:"La fermentation alcoolique (levures) suit la réaction :",choices:["Glucose → acide lactique + NADH","Glucose → 2 éthanol + 2 CO₂ (voie Embden-Meyerhof + décarboxylation du pyruvate par la pyruvate décarboxylase + ADH)","Glucose → acétyl-CoA + NADH","Glucose → 2 pyruvate + 4 NADH"],answer:1,diff:1,explication:"Fermentation alcoolique : glycolyse → pyruvate + CO₂ → acétaldéhyde (PDC) + NADH → éthanol (ADH). Bilan : glucose + 2 Pi + 2 ADP → 2 éthanol + 2 CO₂ + 2 ATP. Levures : Saccharomyces cerevisiae. Substrats : saccharose (invertase), amidon (amylases).",tags:["Fermentation","Alcoolique","Saccharomyces","Éthanol"]},
  {id:"ferm2",prompt:"La fermentation lactique homofermentaire produit uniquement :",choices:["Éthanol + CO₂","Acide lactique (2 moles par mole de glucose, bilan 2 ATP)","Acide acétique + éthanol","Acide lactique + CO₂ + éthanol"],answer:1,diff:1,explication:"Fermentation lactique homofermentaire (Lactobacillus delbrueckii, Streptococcus thermophilus) : glucose → 2 pyruvate (glycolyse) → 2 lactate (LDH, régénère NAD⁺). 2 ATP nets. Homofermentaire = un seul produit final principal. Hétérofermentaire (Leuconostoc, Lactobacillus brevis) : lactate + éthanol + CO₂.",tags:["Fermentation","Lactique","Homofermentaire","Lactobacillus"]},
  {id:"ferm3",prompt:"Dans un bioréacteur industriel fed-batch, l'alimentation continue du substrat permet :",choices:["D'atteindre un volume illimité","De maintenir le substrat en concentration limitante → limitation de l'effet de Crabtree → maximisation de la biomasse (mode semi-continu)","De maximiser la production de CO₂","D'éliminer la phase lag"],answer:1,diff:2,explication:"Fed-batch : alimentation continue (ou par pulses) de substrat dans le réacteur, sans soutirage. Avantage : contrôle de la concentration en substrat → évite l'effet de Crabtree (répression catabolique par excès de glucose) → optimise le rendement biomasse/substrat. Utilisé en production de levures, antibiotiques, protéines recombinantes.",tags:["Bioréacteur","Fed-batch","Biomasse","Substrate feeding"]},
  {id:"ferm4",prompt:"Le modèle de Monod décrit la croissance microbienne par :",choices:["μ = μmax (modèle linéaire)","μ = μmax × S / (Ks + S) — similaire à l'équation de Michaelis-Menten pour la cinétique enzymatique"],answer:1,diff:2,explication:"Équation de Monod : μ (taux de croissance spécifique) = μmax × S / (Ks + S). S = concentration en substrat limitant. Ks = constante de demi-saturation (valeur de S pour μ = μmax/2). Faible Ks → forte affinité pour le substrat. Analogie avec Michaelis-Menten (Km).",tags:["Monod","Cinétique","Croissance microbienne","Bioréacteur"]},
  {id:"ferm5",prompt:"La SIP (Stérilisation en Place) d'un bioréacteur est réalisée avec :",choices:["Eau froide circulante","Vapeur saturée à 121°C, 1 bar de surpression, pendant 20-30 min (standard industrie pharmaceutique)","UV pendant 60 min","Éthanol à 70%"],answer:1,diff:2,explication:"SIP (Sterilization in Place) : vapeur saturée 121°C / 15-20 min dans tous les volumes morts du bioréacteur (capteurs, vannes, tubulures). Valeur stérilisatrice F₀ ≥ 12 (réduction 12 log de spores de Bacillus stearothermophilus). Contrôle : indicateurs biologiques (spores) + physicochimiques.",tags:["Bioréacteur","SIP","Stérilisation","Vapeur"]},
  {id:"ferm6",prompt:"La Dissolved Oxygen Tension (DOT) dans un fermenteur aérobie est régulée en ajustant :",choices:["Uniquement la température","La vitesse d'agitation ET le débit d'aération (cascade DO : agitation d'abord, puis débit d'air, puis enrichissement O₂)"],answer:1,diff:2,explication:"Oxygène dissous (pO₂ / DOT) : paramètre critique en fermentation aérobie. Régulation en cascade : (1) augmentation de l'agitation (kLa↑), (2) augmentation du débit d'aération, (3) enrichissement en O₂ pur si nécessaire. Seuil critique : pO₂ > 20-30% pour la plupart des souches industrielles.",tags:["Bioréacteur","Oxygène dissous","DOT","Fermentation aérobie"]},
  {id:"ferm7",prompt:"Le coefficient de transfert d'oxygène kLa (h⁻¹) dans un bioréacteur dépend principalement de :",choices:["Uniquement du pH","La vitesse d'agitation, la géométrie des turbines (Rushton), la coalescence des bulles et la présence de moussant (antimoussant)"],answer:1,diff:3,explication:"kLa : coefficient de transfert de l'O₂ du gaz vers le liquide. kLa ↑ si : agitation ↑ (turbines Rushton vs marine), débit d'air ↑, diamètre de bulle ↓ (sparger fin), antimoussant. Dans les moûts visqueux (fermentations fongiques), kLa chute significativement → adaptation des turbines.",tags:["Bioréacteur","kLa","Transfert d'oxygène","Agitation"]},
  {id:"ferm8",prompt:"La production d'éthanol en France (filière biocarburant) utilise principalement comme matière première :",choices:["Le pétrole","Les betteraves sucrières et les céréales (blé, maïs) → saccharification + fermentation alcoolique → distillation","Le bois","Les algues"],answer:1,diff:1,explication:"Bioéthanol 1G (1ère génération) : betteraves (sucrose direct) ou céréales (amidon → glucoamylase → glucose → S. cerevisiae). Bioéthanol 2G : lignocellulose (paille, bois) après prétraitement + hydrolyse enzymatique + fermentation. Mix E10 (10% éthanol) : carburant standard en France.",tags:["Fermentation","Bioéthanol","Betterave","Biocarburant"]},
  {id:"ferm9",prompt:"Le rendement maximum théorique de la fermentation alcoolique (rendement de Gay-Lussac) est :",choices:["100 g d'éthanol pour 100 g de glucose","51.1 g d'éthanol pour 100 g de glucose (et 48.9 g de CO₂)","25 g d'éthanol pour 100 g de glucose","75 g d'éthanol pour 100 g de glucose"],answer:1,diff:2,explication:"C₆H₁₂O₆ → 2C₂H₅OH + 2CO₂. Masses molaires : glucose = 180 g/mol, 2 × éthanol = 92 g/mol. Rendement Gay-Lussac = 92/180 × 100 = 51.1%. En pratique : 45-48% car une partie est utilisée pour la croissance cellulaire.",tags:["Fermentation","Gay-Lussac","Rendement","Éthanol"]},
  {id:"ferm10",prompt:"L'inhibition de la fermentation alcoolique par l'éthanol (auto-inhibition) est importante car :",choices:["L'éthanol est un nutriment pour les levures","L'éthanol est toxique pour les levures au-delà d'un certain seuil (> 10-15% v/v), désorganisant la membrane cellulaire et inhibant les enzymes"],answer:1,diff:2,explication:"Auto-inhibition par l'éthanol : au-delà de 10-15% v/v, l'éthanol déstabilise la bicouche lipidique des levures (↑ perméabilité membranaire) et inhibe les enzymes glycolytiques. Levures tolérantes à l'éthanol sélectionnées pour la production de vin fort ou de whisky (> 15%). Implications : alimentation graduée en substrat en fed-batch.",tags:["Fermentation","Éthanol","Auto-inhibition","Tolérance"]},
  {id:"ferm11",prompt:"La croissance microbienne en batch présente 4 phases successives. La phase d'accélération (lag) correspond à :",choices:["La mort exponentielle des cellules","L'adaptation métabolique au nouveau milieu (induction d'enzymes, synthèse de facteurs de croissance) sans multiplication visible"],answer:1,diff:1,explication:"Phase lag (latence/accélération) : les cellules s'adaptent au milieu frais (pH, T°, nutriments). Inducton des enzymes cataboliques si nouveau substrat. Pas ou peu de divisions. Durée variable : quelques minutes à plusieurs heures. Suivi par phase exponentielle (μ = μmax), puis stationnaire (nutriments épuisés), puis déclin.",tags:["Cinétique microbienne","Phase lag","Croissance","Batch"]},
  {id:"ferm12",prompt:"La productivité volumétrique d'un fermenteur (g/L/h) peut être améliorée en :",choices:["Diminuant le volume du réacteur","Utilisant un mode continu (chemostat) avec un taux de dilution proche du μmax, ou un fed-batch avec alimentation optimisée","Stoppant l'aération pour économiser l'énergie","Augmentant le pH à 9"],answer:1,diff:2,explication:"Chemostat (continu) : le taux de dilution D = taux de croissance μ en régime permanent. Productivité = biomasse × D. Optimum : D proche de μmax mais en dessous (risque de wash-out si D > μmax). Avantages : flux constant, état physiologique stable. Fed-batch : excellent compromis en industrie (flexibilité, haute productivité).",tags:["Bioréacteur","Chemostat","Productivité","Continu"]},
];

const QB_ENZYMOLOGIE = [
  {id:"enz1",prompt:"L'équation de Michaelis-Menten décrit la cinétique enzymatique. La constante Km représente :",choices:["La vitesse maximale de la réaction","La concentration en substrat [S] pour laquelle la vitesse est égale à Vmax/2"],answer:1,diff:1,explication:"Km (constante de Michaelis) = [S] pour V = Vmax/2. Km faible → forte affinité enzyme-substrat. Km élevé → faible affinité. Km et Vmax mesurés graphiquement (Lineweaver-Burk : 1/V vs 1/[S], intercepts sur les axes → 1/Vmax et -1/Km).",tags:["Enzymologie","Michaelis-Menten","Km","Vmax"]},
  {id:"enz2",prompt:"L'inhibition compétitive se caractérise par :",choices:["Diminution de la Vmax sans modification du Km","Augmentation apparente du Km (l'inhibiteur entre en compétition avec le substrat sur le site actif) sans modification de la Vmax"],answer:1,diff:2,explication:"Inhibition compétitive : l'inhibiteur (I) ressemble structurellement au substrat → se fixe sur le site actif → compétition avec S. Conséquence : Km apparent ↑ (affinité apparente pour S ↓), Vmax inchangée (si [S] >> [I], la réaction atteint Vmax). Levée par excès de substrat. Ex : méthotrexate (inhibiteur DHFR).",tags:["Enzymologie","Inhibition compétitive","Km","Site actif"]},
  {id:"enz3",prompt:"L'inhibition non-compétitive (mixte) se caractérise par :",choices:["Augmentation du Km uniquement","Diminution de la Vmax (l'inhibiteur se fixe sur un site allostérique ou sur le complexe ES, pas sur le site actif — ne lève pas avec [S])"],answer:1,diff:2,explication:"Inhibition non-compétitive pure : l'inhibiteur se fixe sur le site allostérique (site de régulation) ≠ site actif → altère la conformation ou l'activité catalytique. Vmax↓, Km inchangé. Exemple : cyanure (inhibe cytochrome c oxydase). Irréversible parfois (poison enzymatique).",tags:["Enzymologie","Inhibition non-compétitive","Vmax","Allostérie"]},
  {id:"enz4",prompt:"Le test ELISA (Enzyme-Linked ImmunoSorbent Assay) utilise une enzyme comme :",choices:["Substrate de la réaction immunologique","Marqueur/révélateur (HRP ou phosphatase alcaline conjuguées à l'anticorps détecteur) pour amplifier et visualiser la réaction antigène-anticorps"],answer:1,diff:1,explication:"Dans l'ELISA, l'enzyme (HRP = horseradish peroxidase ou AP = alkaline phosphatase) est conjuguée à l'Ac secondaire. Elle catalyse la conversion d'un substrat chromogène ou chimioluminescent en produit coloré/lumineux. La réaction enzymatique amplifie le signal → haute sensibilité (détection picomolaire).",tags:["ELISA","Enzymologie","HRP","Immunodosage"]},
  {id:"enz5",prompt:"Les isoenzymes de la lactate déshydrogénase (LDH) sont utiles en diagnostic car :",choices:["Elles ont toutes la même activité quel que soit le tissu","LDH-1 (H₄) domine dans le cœur (élévation post-IDM), LDH-5 (M₄) domine dans le foie et les muscles (hépatite, rhabdomyolyse)"],answer:1,diff:2,explication:"LDH (tétramère de sous-unités H et M) : 5 isoenzymes. LDH-1 (H₄) : cœur, rein, GR. LDH-5 (M₄) : foie, muscles squelettiques. Électrophorèse permet de séparer les isoenzymes et d'identifier l'organe source (complément au dosage total LDH qui monte dans plusieurs situations).",tags:["Isoenzymes","LDH","Diagnostic","Marqueurs"]},
  {id:"enz6",prompt:"La cellulase industrielle (production de bioéthanol 2G) est produite par :",choices:["Saccharomyces cerevisiae","Trichoderma reesei (champignon filamenteux) — producteur naturel de cellulases et hémicellulases excrétées dans le milieu"],answer:1,diff:2,explication:"T. reesei (= Hypocrea jecorina) : champignon filamenteux sécrétant un cocktail de cellulases (endoglucanases, cellobiohydrolases, β-glucosidases) et hémicellulases. Optimisation par mutagenèse / génie génétique → souches hyperproductrices. Applications : bioéthanol 2G, industrie papetière, alimentation animale.",tags:["Cellulase","Trichoderma","Bioéthanol 2G","Enzymes industrielles"]},
  {id:"enz7",prompt:"L'amylase pancréatique (α-amylase) hydrolyse l'amidon en clivant :",choices:["Les liaisons β-1,4 (comme la cellulase)","Les liaisons α-1,4 osidiques internes de l'amylose et de l'amylopectine → maltose + dextrines limites"],answer:1,diff:1,explication:"α-amylase (endoenzyme) : clive les liaisons α-1,4 aléatoirement → oligosaccharides + maltose. Les liaisons α-1,6 (branchements de l'amylopectine) résistent. L'amyloglucosidase (glucoamylase, exoenzyme) clive aussi les α-1,6 → glucose. Utilisation industrielle : brasserie (saccharification des malts), boulangerie, bioéthanol.",tags:["Amylase","Amidon","Enzymologie","Bioéthanol"]},
  {id:"enz8",prompt:"La protéase utilisée dans la maturation du fromage (ex : présure) est :",choices:["La pepsine gastrique","La chymosine (= rennine), extraite de la caillette de veau ou produite par levures recombinantes (chymosine fermentale)"],answer:1,diff:2,explication:"Chymosine : protéase aspartique qui coagule spécifiquement la caséine κ (clive la liaison Phe105-Met106) → micelle déstabilisée → gel → caillé. 90% du présure utilisé est aujourd'hui de la chymosine fermentale (production dans Aspergillus niger var. awamori ou Kluyveromyces lactis par génie génétique).",tags:["Enzymologie","Chymosine","Présure","Fromage"]},
  {id:"enz9",prompt:"L'enzyme de restriction EcoRI reconnaît et coupe la séquence :",choices:["5'-AAGCTT-3' (HindIII)","5'-GAATTC-3' (palindromique) → bouts cohésifs 5'-AATT-3'"],answer:1,diff:2,explication:"EcoRI (Escherichia coli) : endonucléase de type II. Séquence 5'-GAATTC-3' (palindrome). Coupure décalée → bouts cohésifs 5'-AATT-3'. Compatible avec elle-même (ligation directe). EcoRI est l'une des enzymes de restriction les plus utilisées en biologie moléculaire (clonage, RFLP).",tags:["Restriction","EcoRI","Enzymologie","Biologie moléculaire"]},
  {id:"enz10",prompt:"Une enzyme allostérique présente une cinétique sigmoïde plutôt qu'hyperbolique car :",choices:["Elle n'a qu'un seul site de fixation","Elle a plusieurs sites de fixation (coopérativité) : liaison d'un substrat sur un site facilite/inhibe la liaison sur les autres sites (modèle MWC ou KNF)"],answer:1,diff:3,explication:"Enzymes allostériques (ex: ATCase, hémoglobine pour l'O₂) : oligomériques avec plusieurs sous-unités. Coopérativité positive → courbe sigmoïde V vs [S]. Régulées par effecteurs allostériques (activateurs et inhibiteurs). L'Hill coefficient (nH > 1) mesure la coopérativité. Rôle : régulation métabolique fine (feedback inhibition).",tags:["Allostérie","Sigmoïde","Coopérativité","Régulation métabolique"]},
  {id:"enz11",prompt:"La laccase est une oxydoréductase utilisée en agroalimentaire et en industrie textile pour :",choices:["Hydrolyser les protéines","Oxyder des composés phénoliques (en présence d'O₂) → quinones → polymérisation → coloration, clarification des jus, blanchiment des effluents textiles"],answer:1,diff:3,explication:"Laccase (Trametes versicolor et autres champignons) : oxydase multi-cuivre, catalyse l'oxydation de phénols par O₂ → eau. Applications : clarification des jus de fruits (oxydation tanins), blanchiment de la pâte à papier, décoloration d'effluents textiles, biosenseurs. Avantage : co-substrat = O₂ de l'air (pas H₂O₂).",tags:["Laccase","Enzymes industrielles","Oxydoréductase","Champignons"]},
  {id:"enz12",prompt:"Le Lineweaver-Burk (double réciproque) représente 1/V en fonction de 1/[S]. Les ordonnées à l'origine donnent :",choices:["La valeur de Km directement","1/Vmax (ordonnée à l'origine) et -1/Km (abscisse à l'origine)"],answer:1,diff:2,explication:"Graphique de Lineweaver-Burk (1934) : 1/V = (Km/Vmax) × 1/[S] + 1/Vmax. Forme y = ax + b. Ordonnée à l'origine (1/[S]=0) = 1/Vmax → Vmax. Abscisse à l'origine (1/V=0) = -1/Km → Km. Identification du type d'inhibition : parallèles = non-compétitif ; convergence sur l'axe Y = compétitif.",tags:["Lineweaver-Burk","Enzymologie","Vmax","Km"]},
];

const QB_QUALITE_ISO = [
  {id:"qi1",prompt:"La norme ISO 9001:2015 exige une approche par :",choices:["Les procédures documentées uniquement","Le risque (risk-based thinking) et les processus, avec la direction comme moteur (leadership), dans un contexte stratégique (parties intéressées)"],answer:1,diff:2,explication:"ISO 9001:2015 (structure HLS) : 10 chapitres. Innovations 2015 : approche par les risques et opportunités (≥ chapitre 6.1), contexte de l'organisme (parties intéressées, enjeux), leadership de la direction, knowledge organizational. L'exigence de Manuel qualité n'est plus obligatoire.",tags:["ISO 9001","Qualité","Approche par les risques","SMQ"]},
  {id:"qi2",prompt:"Le cycle PDCA (roue de Deming) se décompose en :",choices:["Planifier, Décider, Contrôler, Adapter","Plan (planifier) → Do (faire) → Check (vérifier) → Act (agir/améliorer) — itératif pour l'amélioration continue"],answer:1,diff:1,explication:"PDCA (Deming / Shewhart) : Plan = analyser le problème et planifier les actions. Do = mettre en œuvre. Check = mesurer et vérifier les résultats. Act = standardiser si réussi ou recommencer. Fondement de l'amélioration continue dans les normes ISO. Applicable à tous les niveaux.",tags:["PDCA","Deming","Amélioration continue","ISO 9001"]},
  {id:"qi3",prompt:"La méthode HACCP (Hazard Analysis Critical Control Point) est obligatoire pour :",choices:["Uniquement les grandes entreprises alimentaires","Tous les établissements du secteur alimentaire (règlement CE 852/2004) — sauf certaines petites structures directement au consommateur"],answer:1,diff:1,explication:"HACCP (7 principes du Codex Alimentarius) : obligatoire dans l'UE pour toutes les IAA (règlement CE 852/2004). 7 principes : identification des dangers, CCPs, limites critiques, surveillance, mesures correctives, vérification, documentation. Les restaurants et commerces de détail peuvent appliquer des GHP/PRPs à la place si dérogation nationale.",tags:["HACCP","Sécurité alimentaire","CCPs","Règlement CE"]},
  {id:"qi4",prompt:"La norme ISO 22000 se distingue de HACCP car :",choices:["Elle remplace totalement HACCP","Elle intègre HACCP + un SMQ (système de management qualité) + les PRP (programmes prérequis), permettant une certification reconnaissable internationalement"],answer:1,diff:2,explication:"ISO 22000 : norme de système de management de la sécurité des aliments (SMSA). Combine HACCP (analise des dangers + CCP) + SMQ (approche processus, amélioration continue, leadership) + PRP (hygiène de base). Structure compatible HLS (alignée ISO 9001/14001). Certification par organisme tiers.",tags:["ISO 22000","HACCP","Sécurité alimentaire","SMQ"]},
  {id:"qi5",prompt:"Les BPF (Bonnes Pratiques de Fabrication) en industrie pharmaceutique correspondent à :",choices:["Un guide de fabrication non contraignant","Un ensemble de lignes directrices réglementaires (ICH Q7, BPF ANSM/EMA) définissant les exigences de qualité pour la fabrication de médicaments (personnel, locaux, équipements, production, contrôle, libération)"],answer:1,diff:2,explication:"BPF (GMP : Good Manufacturing Practice) : règlement obligatoire. En France : BPF ANSM (transposition directive 2003/94/CE). Lignes directrices : ICH Q7 (API), ICH Q10 (système qualité pharmaceutique). Couvre tout le cycle de fabrication : personnel qualifié, locaux et équipements qualifiés, validation des procédés, contrôle qualité, audit, traçabilité.",tags:["BPF","GMP","Pharmaceutique","ICH"]},
  {id:"qi6",prompt:"L'outil 5S (méthode japonaise) vise principalement à :",choices:["5 étapes pour résoudre les non-conformités","Organiser et améliorer l'environnement de travail : Seiri (Trier), Seiton (Ranger), Seiso (Nettoyer), Seiketsu (Standardiser), Shitsuke (Maintenir/Respecter)"],answer:1,diff:1,explication:"5S (Lean management, Toyota Production System) : démarche d'organisation du poste de travail. Résultats : réduction du gaspillage (muda), amélioration de la sécurité, visibilité des anomalies, réduction du temps de recherche. Prérequis à d'autres outils Lean (VSM, SMED, Kanban). Applicable dans les laboratoires.",tags:["5S","Lean","Organisation","Poste de travail"]},
  {id:"qi7",prompt:"Une non-conformité (NC) est une :",choices:["Simple observation lors d'un audit","Non-satisfaction d'une exigence (ISO 9000) — peut être interne (processus) ou externe (produit client)"],answer:1,diff:1,explication:"ISO 9000 : non-conformité = non-satisfaction d'une exigence (réglementaire, contractuelle, normative, client). Classification : NC critique (sécurité), majeure (défaillance système), mineure (écart ponctuel). Traitement : enregistrement → correction immédiate → action corrective → vérification d'efficacité (CAPA).",tags:["Non-conformité","ISO 9001","CAPA","Audit"]},
  {id:"qi8",prompt:"L'audit qualité se distingue d'une inspection car :",choices:["L'audit cherche à sanctionner, l'inspection cherche à améliorer","L'audit est un processus indépendant et systématique pour évaluer l'adéquation et l'efficacité du SMQ (pas pour sanctionner mais pour identifier les opportunités d'amélioration)"],answer:1,diff:2,explication:"Audit (ISO 19011) : évaluation indépendante, systématique, documentée et objective d'un système de management. Types : audit interne (1ère partie), audit client (2ème partie), audit de certification (3ème partie). L'auditeur ne peut pas auditer son propre travail. Rapport d'audit → NC + observations + points forts.",tags:["Audit","ISO 19011","Qualité","SMQ"]},
  {id:"qi9",prompt:"La traçabilité en HACCP permet notamment de :",choices:["Remplacer les contrôles analytiques","Identifier et retirer rapidement un lot défectueux du marché (rappel de produits) et déterminer l'origine d'une contamination"],answer:1,diff:1,explication:"Traçabilité (règlement CE 178/2002) : obligation de tracer les denrées 'un pas en amont, un pas en aval'. Permet en cas de crise : identification précise du lot contaminé, retrait ciblé (vs rappel de masse), communication avec les autorités (DGAL, ANSES). Outil central de la gestion des crises alimentaires.",tags:["Traçabilité","HACCP","Rappel produits","Règlement CE 178"]},
  {id:"qi10",prompt:"Les indicateurs clés de performance (KPI) d'un laboratoire de contrôle qualité incluent :",choices:["Uniquement le nombre de non-conformités par mois","Délai de rendu des résultats, taux de non-conformités, taux de rejets pré-analytiques, coût par analyse, taux de satisfaction client"],answer:1,diff:2,explication:"KPI (Key Performance Indicators) du laboratoire : (1) Délai TAT (Turn Around Time) = délai réception → rendu résultats. (2) Taux NC analytiques. (3) Taux NC pré-analytiques (tubes non conformes). (4) Coût par test. (5) Satisfaction client (questionnaire). Suivi mensuel en tableau de bord qualité → revue de direction (ISO 9001).",tags:["KPI","Laboratoire","Tableau de bord","Qualité"]},
  {id:"qi11",prompt:"La validation d'une méthode analytique comprend la détermination de :",choices:["Uniquement la spécificité","Spécificité, linéarité, exactitude (justesse + fidélité), limites de détection (LD) et de quantification (LQ), robustesse — critères harmonisés ICH Q2(R1)"],answer:1,diff:2,explication:"Validation analytique (ICH Q2R1, NF EN ISO 5725) : (1) Spécificité/sélectivité. (2) Linéarité/gamme de mesure. (3) Exactitude (justesse = biais vs référence ; fidélité = répétabilité + reproductibilité). (4) LD (signal/bruit > 3) et LQ (S/N > 10). (5) Robustesse (variations délibérées des paramètres opératoires).",tags:["Validation analytique","ICH Q2","Spécificité","LD","LQ"]},
  {id:"qi12",prompt:"L'analyse des modes de défaillance et de leurs effets (AMDEC / FMEA) est utilisée pour :",choices:["Calculer le coût des non-conformités","Identifier proactivement les défaillances potentielles d'un procédé (criticité = Gravité × Fréquence × Détectabilité) et prioriser les actions préventives"],answer:1,diff:2,explication:"AMDEC (FMEA en anglais) : outil préventif. Pour chaque mode de défaillance : G (gravité 1-10) × F (fréquence/occurrence 1-10) × D (détectabilité 1-10) = IPR (Indice de Priorité du Risque). IPR > 100 (ou selon seuil défini) → action corrective prioritaire. Utilisé en: industrie agroalimentaire, pharmaceutique, automobile. Relation avec HACCP (analyse des dangers).",tags:["AMDEC","FMEA","Analyse des risques","Qualité"]},
];

// ─── THEME ───
const T={bg:"#07060B",surface:"#12101B",card:"#161325",accent:"#C57AFF",accent2:"#902EDB",yellow:"#F0E547",green:"#4AEAAC",red:"#FF6370",blue:"#5EB5FF",orange:"#FFB259",pink:"#FF5DA0",text:"#EDE9F5",text2:"#A199B2",text3:"#6B6280",border:"rgba(255,255,255,0.05)",border2:"rgba(255,255,255,0.09)",r:16};

const QB_CR = [
  {id:"cr1",prompt:"Quelle est la différence entre une feuille d'enregistrement et un rapport d'essai ?",choices:["Ce sont deux noms pour le même document","La feuille d'enregistrement contient les résultats bruts en temps réel ; le rapport d'essai est un document formalisé transmis au client avec les résultats traités et la déclaration de conformité","Le rapport d'essai est rempli pendant la manipulation","La feuille d'enregistrement est destinée au client"],answer:1,diff:1,explication:"Feuille d'enregistrement = traçabilité interne, remplie en temps réel, résultats bruts. Rapport d'essai = document formalisé (ISO 17025), résultats traités + incertitude + déclaration de conformité, signé par un approbateur. Le compte-rendu de TP simule le rapport d'essai.",tags:["Compte-rendu","Feuille enregistrement","Rapport d'essai","ISO 17025"]},
  {id:"cr2",prompt:"Selon l'indicateur S2.8.2, quelle information est obligatoire dans l'expression d'un résultat de mesure ?",choices:["La couleur du réactif utilisé","L'incertitude de mesure (résultat ± u, avec unité et niveau de confiance)","Le nom du fournisseur de l'équipement","La durée de la manipulation"],answer:1,diff:1,explication:"S2.8.2 exige explicitement que 'le résultat de mesure est rendu avec son incertitude'. Écrire '4,2 g/L' sans incertitude est un indicateur non atteint. La forme correcte est : C = 4,2 ± 0,1 g/L (k=2, p=95%).",tags:["Incertitude","S2.8.2","Résultat de mesure","Compte-rendu"]},
  {id:"cr3",prompt:"Dans un compte-rendu professionnel, comment doit être rédigée la section 'Méthode' ?",choices:["En recopiant intégralement le protocole fourni","Par une référence à la norme normalisée (ex : ISO 4833-1:2013) + principe en 2-3 phrases reformulées + conditions opératoires spécifiques","Par une description de chaque geste effectué","En citant le cours comme source"],answer:1,diff:2,explication:"La méthode ne se recopie JAMAIS. Elle se résume : référence de la norme (numéro + année), principe reformulé en 2-3 phrases, et uniquement les déviations par rapport à la procédure standard. Recopier le protocole est explicitement pénalisé (S4.3.2).",tags:["Section méthode","Norme","Protocole","Compte-rendu"]},
  {id:"cr4",prompt:"Quelle est la séquence correcte de traitement d'un résultat de mesure (S2.8.2 / T2.3) ?",choices:["Résultat final → calcul → conclusion","Indication brute → modèle de mesure → application numérique → sources d'erreur → incertitude → résultat final (valeur ± u) → comparaison aux spécifications → déclaration de conformité","Application numérique → résultat → incertitude → conclusion","Conclusion → calcul → sources d'erreur"],answer:1,diff:2,explication:"La séquence ISO : ① indication brute ② équation aux grandeurs ③ application numérique ④ sources d'erreur ⑤ incertitude u ⑥ résultat = valeur ± U (unité, k=2) ⑦ comparaison aux spécifications ⑧ déclaration CONFORME/NON CONFORME. Chaque étape doit apparaître dans le compte-rendu.",tags:["Séquence calcul","T2.3","Incertitude","Application numérique"]},
  {id:"cr5",prompt:"Pour une droite d'étalonnage dans un graphique, quels éléments DOIVENT être présents ?",choices:["Titre uniquement","Titre complet + axes légendés (grandeur + symbole + unité) + équation de régression y=ax+b + coefficient R² ≥ 0,99 + points expérimentaux distingués de la courbe","R² uniquement","Axes légendés + titre, sans R²"],answer:1,diff:2,explication:"Check-list graphique obligatoire : titre explicite, axes (grandeur+symbole+[unité]), équation de régression affichée, R² ≥ 0,99 pour valider la linéarité, points expérimentaux en symboles distincts de la courbe théorique. Un graphique sans R² est incomplet selon S2.8.2.",tags:["Droite étalonnage","Graphique","R²","S2.8.2"]},
  {id:"cr6",prompt:"Dans un compte-rendu, quelle formulation de conclusion est correcte selon S2.8.3 ?",choices:["'Le résultat semble correct.'","'La concentration en protéines totales (4,2 ± 0,1 g/L) est inférieure à la limite maximale de spécification (5,0 g/L). Le lot est CONFORME à la norme PRO-BIOCH-012 v3.2.'","'Nous concluons que l'analyse s'est bien passée.'","'Le résultat est dans la norme.'"],answer:1,diff:1,explication:"S2.8.3 exige : ① réponse directe à l'objectif ② comparaison chiffrée résultat vs spécification ③ déclaration CONFORME/NON CONFORME avec justification chiffrée ④ si NC : actions correctives. Les conclusions floues ('semble correct', 'dans la norme') sont explicitement pénalisées.",tags:["Conclusion","Conformité","S2.8.3","Déclaration de conformité"]},
  {id:"cr7",prompt:"Quelle est la règle de citation d'une norme ISO dans un compte-rendu (S4.3.2 — normes APA) ?",choices:["ISO 4833 suffit","ISO 4833-1:2013. Microbiologie de la chaîne alimentaire — [titre complet]. Organisation internationale de normalisation. (numéro + année + titre + organisme)","'Selon la norme ISO en vigueur'","ISO (2013), méthode de dénombrement"],answer:1,diff:2,explication:"S4.3.2 exige que les sources soient correctement citées. Pour une norme ISO : numéro complet (ex : ISO 4833-1:2013) + titre complet + organisme émetteur. L'année est obligatoire car les normes sont révisées. Écrire 'ISO 4833' sans l'année = source non vérifiable.",tags:["Citation norme","ISO","S4.3.2","Bibliographie APA"]},
  {id:"cr8",prompt:"Pourquoi une rature sur une feuille d'enregistrement doit-elle être barrée d'un trait, paraphée et datée ?",choices:["Pour des raisons esthétiques","Pour garantir la traçabilité et éviter toute suspicion de falsification — une rature effacée ou illisible est considérée comme falsification potentielle (S2.8.1 + ISO 17025)","Pour faciliter la lecture par le formateur","Parce que c'est la règle du lycée"],answer:1,diff:1,explication:"ISO 17025 et S2.8.1 : tout document d'enregistrement doit permettre la traçabilité. Utiliser du blanc correcteur, effacer, ou rendre illisible une valeur est assimilé à une tentative de falsification. La correction valide = un trait unique barrant la valeur erronée + paraphe + date.",tags:["Rature","Traçabilité","S2.8.1","ISO 17025","Falsification"]},
  {id:"cr9",prompt:"Quelle confusion terminologique est explicitement pénalisée dans le référentiel BIOALC ?",choices:["Confondre 'essai' et 'test'","Confondre 'fidélité', 'justesse' et 'exactitude' — trois concepts métrologiques distincts (T2.3)","Confondre 'tableau' et 'graphique'","Confondre 'résultat' et 'données'"],answer:1,diff:2,explication:"T2.3 : Fidélité = dispersion des mesures répétées (reproductibilité/répétabilité) ; Justesse = écart entre la moyenne et la valeur vraie (biais) ; Exactitude = combinaison fidélité + justesse. Ces trois termes sont souvent confondus en français courant et leur usage incorrect est pénalisé.",tags:["Fidélité","Justesse","Exactitude","T2.3","Métrologie"]},
  {id:"cr10",prompt:"Quel type de graphique est adapté pour représenter l'évolution d'une population bactérienne dans le temps (cinétique de croissance) ?",choices:["Histogramme (barres)","Nuage de points non reliés","Courbe (points reliés ou courbe de régression) — car la variable est continue dans le temps","Camembert (diagramme circulaire)"],answer:2,diff:1,explication:"Règle S2.8.2 : évolution dans le temps = courbe (variable temporelle continue). Un histogramme est inadapté car il perd l'information temporelle. Un camembert = répartition de proportions. Un nuage non relié ne montre pas la cinétique. Les règles de choix du graphique sont évaluées.",tags:["Graphique","Cinétique","Croissance bactérienne","S2.8.2"]}
];

const QB_BLOC2_PRAT = [
  {id:"b2p1",prompt:"Avant toute manipulation en microbiologie, quelle est la première action à réaliser dans le poste de sécurité microbiologique (PSM II) ?",choices:["Allumer la centrifugeuse","Réaliser le bionettoyage : désinfection de la surface + allumage UV si prévu + attente avant manipulation","Préparer les milieux de culture","Remplir la feuille de traçabilité"],answer:1,diff:1,explication:"C2.4 (S2.4.1) : le bionettoyage du PSM II est TOUJOURS la première étape avant toute manipulation microbiologique. Séquence : spray désinfectant → essuyage → UV (si prévu) → attente. Manipuler dans un PSM non désinfecté = risque de contamination croisée.",tags:["PSM II","Bionettoyage","Microbiologie","C2.4","Asepsie"]},
  {id:"b2p2",prompt:"En biologie moléculaire (C2.5), pourquoi la règle de 'marche en avant' est-elle absolument critique ?",choices:["Pour économiser les réactifs","Pour éviter la contamination des réactions pré-PCR par des produits amplifiés post-PCR, ce qui fausserait tous les résultats (faux positifs)","Pour respecter l'ordre des postes de travail","Pour les normes d'accréditation uniquement"],answer:1,diff:2,explication:"S2.5.1 : la contamination pré→post-PCR est la plus grave erreur en biologie moléculaire. Les amplicons (post-PCR) sont en quantité astronomique — une seule molécule dans la zone pré-PCR génère un faux positif. La règle de marche en avant (pré-PCR → post-PCR, jamais l'inverse) est donc impérative et non négociable.",tags:["Marche en avant","PCR","Contamination","C2.5","Faux positif"]},
  {id:"b2p3",prompt:"Lors d'un dosage quantitatif (C2.3, S2.3.5), quels éléments doivent impérativement figurer dans les calculs rendus ?",choices:["Résultat final uniquement","Équation aux grandeurs + application numérique avec valeurs ET unités + résultat intermédiaire + résultat final ± incertitude","Application numérique seule","Résultat final + R²"],answer:1,diff:2,explication:"S2.3.5 + T2.3 : 'Les objectifs de qualité en termes d'exactitude sont atteints' exige une démonstration complète. Le jury vérifie chaque étape : équation posée, valeurs substituées avec unités, résultat intermédiaire si multi-étapes, résultat final ± incertitude. Un calcul sans équation posée = indicateur non atteint.",tags:["Dosage quantitatif","Calcul","Incertitude","C2.3","S2.3.5"]},
  {id:"b2p4",prompt:"Pour valider une série analytique (C2.7, S2.7.4), dans quel ordre doit-on procéder ?",choices:["Valider la série, puis lire les contrôles","Lire et exploiter les résultats des contrôles qualité (CIQ) AVANT de valider la série — la série n'est pas libérée tant que les contrôles ne sont pas conformes","Valider la série si les résultats des échantillons semblent cohérents","Demander au formateur avant de valider"],answer:1,diff:1,explication:"C2.7 (S2.7.4) : 'Les résultats obtenus pour les contrôles sont lus et exploités' AVANT validation. Libérer une série sans avoir vérifié les contrôles = erreur grave de posture professionnelle. Si un contrôle est hors limites : déclenchement de l'alerte + règle des 5M avant toute nouvelle analyse.",tags:["Validation de série","CIQ","Contrôle qualité","C2.7","S2.7.4"]},
  {id:"b2p5",prompt:"En biologie cellulaire (C2.6, S2.6.3), comment distinguer une cellule vivante d'une cellule morte au bleu trypan ?",choices:["Cellule vivante = bleue (colorée) ; cellule morte = réfringente (non colorée)","Cellule vivante = réfringente/blanche (exclut le colorant) ; cellule morte = bleue (membrane perméable, colorant pénètre)","Les deux apparaissent identiques","Cellule vivante = colorée en rouge"],answer:1,diff:1,explication:"Le bleu trypan est exclu des cellules VIVANTES (membrane intacte = imperméable). Les cellules MORTES ont une membrane perméable = le colorant pénètre = bleu. Règle mnémotechnique : 'Vivant = blanc, Mort = bleu'. Confondre les deux = taux de viabilité erroné.",tags:["Bleu trypan","Viabilité cellulaire","C2.6","Dénombrement","Exclusion colorant"]},
  {id:"b2p6",prompt:"Lors de l'extraction d'acides nucléiques (C2.5, S2.5.2), quels ratios de pureté sont attendus pour un extrait d'ADN de qualité ?",choices:["A260/A280 ≈ 2,0 et A260/A230 ≈ 1,8","A260/A280 ≈ 1,8 et A260/A230 ≈ 2,0 (contamination protéique si < 1,8 ; contamination par solvants si A260/A230 < 1,8)","A260/A280 < 1,0","A280/A260 ≈ 2,0"],answer:1,diff:2,explication:"S2.5.2 : A260/A280 ≈ 1,8 pour ADN (≈ 2,0 pour ARN). Si < 1,8 → contamination par protéines ou phénol. A260/A230 ≈ 2,0 pour un extrait pur. Si < 1,8 → contamination par solvants organiques (isopropanol, EDTA). Ces ratios sont mesurés au NanoDrop et doivent figurer dans la traçabilité.",tags:["Pureté ADN","NanoDrop","A260/A280","C2.5","Extraction"]},
  {id:"b2p7",prompt:"En cas de non-conformité d'un contrôle qualité (C2.7, S2.7.5), quelle est la démarche attendue ?",choices:["Relancer l'analyse immédiatement sans chercher la cause","Appliquer la règle des 5M (Matière, Matériel, Méthode, Main-d'œuvre, Milieu) pour identifier la cause racine, puis mettre en œuvre les actions correctives avant de libérer la série","Ignorer le contrôle si les résultats des échantillons semblent corrects","Augmenter la concentration du contrôle"],answer:1,diff:2,explication:"S2.7.5 : 'La règle des 5M est utilisée pour trouver des sources d'erreurs' + 'des actions correctives adaptées sont effectuées'. On ne libère JAMAIS une série avec un contrôle hors limites. L'objectif est de trouver la cause racine (pas juste relancer) : réactif périmé ? appareil déréglé ? erreur opérateur ? contamination ?",tags:["Non-conformité","5M","Action corrective","C2.7","Règle des 5M"]},
  {id:"b2p8",prompt:"Quelle est la règle concernant le remplissage de la feuille d'enregistrement en cours de TP ?",choices:["Elle peut être remplie après la manipulation de mémoire","Elle doit être remplie en temps réel, pendant la manipulation — toute reconstitution a posteriori est considérée comme une falsification (S2.8.1 + C2.8)","Elle est facultative si le compte-rendu est complet","Elle est remplie par le formateur"],answer:1,diff:1,explication:"S2.8.1 : 'Le document d'enregistrement est complété de façon rigoureuse' signifie EN TEMPS RÉEL. Remplir après = données reconstitués de mémoire = traçabilité impossible. ISO 17025 exige la traçabilité jusqu'au rapport d'analyse. C'est le premier critère observé par le jury E4.",tags:["Feuille enregistrement","Temps réel","Traçabilité","S2.8.1","C2.8"]},
  {id:"b2p9",prompt:"Pour préparer une gamme étalon (C2.3, S2.3.5), quelles sont les deux exigences minimales attendues en autonomie ?",choices:["Préparer les solutions et noter les résultats","Démonstration des calculs de dilution (équation avec valeurs et unités) + traçabilité de chaque étalon (numéro de lot, concentration, date)","Préparer les solutions sans démonstration de calcul","Copier la gamme d'un autre étudiant"],answer:1,diff:2,explication:"S2.3.5 : 'La préparation des étalons est menée en autonomie' + 'Les objectifs de qualité sont atteints'. Le jury vérifie la démonstration des calculs (C = C0 × V0/Vtotal avec substitution numérique) et la traçabilité de chaque étalon. Une gamme préparée sans calcul démontré = indicateur non atteint.",tags:["Gamme étalon","Dilution","Calcul","C2.3","Traçabilité"]},
  {id:"b2p10",prompt:"Dans le cadre d'un contrôle en bioréacteur de paillasse (C2.4, S2.4.6), quels paramètres doit-on suivre en autonomie ?",choices:["Uniquement la DO (densité optique) pour la biomasse","Les paramètres physico-chimiques en ligne (pH, T°, O2 dissous, agitation) + suivi de la biomasse (DO) + suivi des métabolites — un suivi incomplet est pénalisé","Uniquement la température","La biomasse une seule fois en fin de culture"],answer:1,diff:2,explication:"S2.4.6 : 'Le suivi de production de biomasse est réalisé en autonomie' ET 'Le suivi de production de métabolites est réalisé en autonomie'. Se limiter à la DO = suivi incomplet. Il faut suivre en parallèle : biomasse (DO ou comptage), métabolites (glucose consommé, éthanol produit...) et paramètres physico-chimiques en ligne.",tags:["Bioréacteur","Biomasse","Métabolites","C2.4","S2.4.6"]}
];

const QB_BLOC3_EXPERT = [
  {id:"b3e1",prompt:"En Bloc 3 (E5), comment est formulée une hypothèse scientifique valide (C3.4, S3.4.1) ?",choices:["'Je pense que les résultats seront meilleurs'","'Si [paramètre X] est modifié [de telle façon], alors [indicateur de performance Y] sera amélioré, car [justification scientifique]' — hypothèse testable et reliée aux données du dossier","'L'expérience permettra de vérifier la méthode'","Une hypothèse n'est pas attendue en BTS"],answer:1,diff:2,explication:"S3.4.1 : l'hypothèse doit être testable (vérifiable expérimentalement), pertinente (reliée aux données du dossier) et construite selon le modèle : Si → Alors → Car. Une hypothèse non testable ou sans lien avec le dossier est explicitement pénalisée.",tags:["Hypothèse scientifique","C3.4","S3.4.1","Plan d'expérience","E5"]},
  {id:"b3e2",prompt:"Quelle est la différence entre 'validation' et 'vérification' de méthode (C3.3) ?",choices:["Ce sont des synonymes","Validation = établir les performances d'une méthode nouvelle ou modifiée (étude complète) ; Vérification = confirmer que les performances d'une méthode existante sont toujours atteintes dans les conditions locales","Validation = vérification par le responsable qualité","Vérification = plus complète que la validation"],answer:1,diff:3,explication:"C3.3 : distinction critique évaluée à l'E5. Validation = processus qui prouve qu'une méthode est adaptée à l'usage prévu (études de linéarité, LD, LQ, répétabilité, reproductibilité, justesse, spécificité, robustesse). Vérification = confirmation que la méthode validée donne les performances attendues dans les conditions du laboratoire.",tags:["Validation","Vérification","C3.3","Métrologie","Méthode analytique"]},
  {id:"b3e3",prompt:"Pour analyser une procédure (C3.2, S3.2.2), quel outil de représentation est attendu ?",choices:["Un résumé rédigé","Un organigramme opérationnel identifiant chaque étape avec son rôle, ses entrées, ses sorties, et les paramètres critiques","Un tableau de données","Une liste de matériel"],answer:1,diff:2,explication:"S3.2.2 : 'Un organigramme opérationnel est correctement conçu' + 'Le rôle de chaque étape est expliqué'. L'organigramme est l'outil attendu à l'E5 pour analyser une procédure. Il doit distinguer les étapes critiques (paramètres dont la variation affecte le résultat) des étapes opératoires ordinaires.",tags:["Organigramme","Analyse procédure","C3.2","S3.2.2","Points critiques"]},
  {id:"b3e4",prompt:"Lors de la conception d'un plan d'expérience (C3.4, S3.4.2), quelle est la règle fondamentale sur le nombre de paramètres modifiés simultanément ?",choices:["On peut modifier autant de paramètres que nécessaire","Un seul paramètre à la fois (sauf si plan d'expérience factoriel justifié) — modifier plusieurs paramètres simultanément empêche d'identifier la cause de la variation observée","Deux paramètres maximum en permanence","Au moins trois paramètres pour être rigoureux"],answer:1,diff:2,explication:"S3.4.2 : 'Le choix du matériel et des réactifs est judicieux' + rigueur du plan. La règle est : un paramètre variable à la fois, tous les autres fixes. Si on modifie deux paramètres en même temps, on ne peut pas attribuer le résultat à l'un ou à l'autre. Exception : plan d'expérience factoriel (mais doit être justifié).",tags:["Plan d'expérience","Paramètre variable","C3.4","S3.4.2","Rigueur expérimentale"]},
  {id:"b3e5",prompt:"Quels indicateurs métrologiques sont systématiquement attendus dans un rapport de validation de méthode (C3.3, S3.3.2) ?",choices:["Uniquement la sensibilité","Linéarité, répétabilité, reproductibilité, justesse (biais), limite de détection (LD), limite de quantification (LQ), spécificité, robustesse — tous nécessaires pour valider une méthode","Uniquement LD et LQ","R² de la droite d'étalonnage uniquement"],answer:1,diff:2,explication:"S3.3.2 + VIM : un rapport de validation doit documenter TOUS les indicateurs : linéarité (domaine de validité), répétabilité (même opérateur, même jour), reproductibilité (conditions variées), justesse (biais vs valeur vraie), LD (signal/bruit 3:1), LQ (quantification fiable), spécificité (absence d'interférents), robustesse (stabilité face aux variations mineures).",tags:["Validation de méthode","Indicateurs métrologiques","LD","LQ","C3.3","S3.3.2"]},
  {id:"b3e6",prompt:"Pourquoi est-il indispensable d'inclure des témoins dans tout plan d'expérience (C3.4) ?",choices:["Pour des raisons réglementaires uniquement","Les témoins (méthode initiale, blancs, étalons) permettent de valider les conditions expérimentales et de comparer objectivement la méthode adaptée à la méthode initiale — un plan sans témoin est scientifiquement invalide","Pour gagner du temps","Les témoins sont facultatifs si la méthode est bien décrite"],answer:1,diff:1,explication:"S3.4.2 : 'Prévoir des témoins (méthode initiale, blancs, étalons) dans le plan d'expérience' est une exigence explicite. Sans témoin, il est impossible de distinguer un effet réel d'une variation aléatoire. La comparaison méthode initiale vs méthode adaptée est elle-même un indicateur d'évaluation de l'E5.",tags:["Témoins","Plan d'expérience","C3.4","Comparaison méthodes","S3.4.4"]},
  {id:"b3e7",prompt:"En Bloc 3, comment hiérarchiser les paramètres d'amélioration d'une méthode (C3.1, S3.1.3) ?",choices:["Par ordre alphabétique","En fonction de leur impact potentiel sur les indicateurs de performance ET de leur faisabilité technique dans les contraintes du laboratoire — les outils d'analyse utilisés sont adaptés (5M, AMDEC)","En commençant par les plus simples à modifier","Par ordre d'apparition dans le dossier"],answer:1,diff:3,explication:"S3.1.3 : 'Les données sélectionnées sont hiérarchisées' + 'Les paramètres d'amélioration sont identifiés'. La hiérarchisation doit combiner : impact sur la performance (criticité) ET faisabilité (ressources disponibles). Les outils attendus : diagramme causes-effets (5M d'Ishikawa), AMDEC, arbre des causes.",tags:["Hiérarchisation","AMDEC","5M","C3.1","S3.1.3","Amélioration méthode"]},
  {id:"b3e8",prompt:"Comment exprimer un résultat avec incertitude dans le cadre d'une démarche expérimentale Bloc 3 (S3.4.4) ?",choices:["Valeur + unité suffit","Valeur ± incertitude élargie U (unité), avec facteur d'élargissement k=2 et niveau de confiance 95% — ex : C = 4,2 ± 0,3 g/L (k=2, p=95%)","Valeur ± 5% arbitrairement","L'incertitude n'est pas demandée en Bloc 3"],answer:1,diff:2,explication:"S3.4.4 exige explicitement : 'Les résultats sont exprimés avec leur incertitude'. La forme normalisée (GUM) est : résultat = valeur ± U (unité), avec U = k × u (incertitude élargie). Pour k=2 : niveau de confiance ≈ 95%. Le nombre de décimales du résultat doit être cohérent avec l'incertitude.",tags:["Incertitude élargie","S3.4.4","GUM","k=2","C3.4"]},
  {id:"b3e9",prompt:"Quelle est la différence entre un 'paramètre d'influence' et un 'critère de performance' d'une méthode (C3.1) ?",choices:["Ce sont des synonymes","Paramètre d'influence = variable opératoire qui peut affecter le résultat (ex : température d'incubation, pH) ; critère de performance = indicateur métrologique mesurable (sensibilité, LD, répétabilité)","Critère de performance = paramètre d'influence amélioré","Paramètre d'influence = résultat de la méthode"],answer:1,diff:3,explication:"C3.1 (S3.1.2) : confusion explicitement pénalisée. Un paramètre d'influence agit sur la méthode (ex : concentration en sel, durée d'incubation, température). Un critère de performance mesure la qualité du résultat de la méthode (LD, LQ, justesse, répétabilité). On modifie un paramètre pour améliorer un critère.",tags:["Paramètre d'influence","Critère de performance","C3.1","S3.1.2","Analyse méthode"]},
  {id:"b3e10",prompt:"Pour la rédaction d'un rapport de synthèse en Bloc 3 (C3.2, S3.2.4 ; C3.3, S3.3.3), quel plan structuré est attendu ?",choices:["Introduction, développement, conclusion (plan scolaire standard)","Objectif → Protocole/Procédure analysée → Résultats → Discussion critique (points forts, limites) → Conclusion argumentée avec comparaison aux spécifications","Résultats seuls, sans analyse critique","Description de chaque étape sans synthèse"],answer:1,diff:2,explication:"S3.2.4 + S3.3.3 : 'La synthèse est claire et concise', 'Les performances des deux méthodes sont confrontées', 'Le rapport de synthèse de validation est rédigé'. Le plan attendu : objectif → procédure → résultats → discussion (avantages/limites/comparaison) → conclusion. La discussion doit confronter les résultats aux spécifications du cahier des charges.",tags:["Rapport de synthèse","C3.2","C3.3","S3.3.3","Rédaction professionnelle"]}
];


// ─── E-Book QBs ───
const QB_GENETIQUE = [
  {id:"gen1",prompt:"Lors de l'extraction d'ADN chromosomique, quel rôle joue le SDS ?",choices:["Il précipite l'ADN à l'éthanol","Il désorganise la double couche phospholipidique et lyse la cellule","Il élimine les ARN résiduels","Il neutralise la protéinase K"],answer:1,diff:1,explication:"Le SDS (dodécylsulfate de sodium) est un détergent ionique qui désorganise les membranes et lyse les cellules. Il solubilise les protéines membranaires, permettant la libération du contenu cellulaire.",tags:["Extraction ADN","SDS","Lyse cellulaire"]},
  {id:"gen2",prompt:"Quelle enzyme dissocie les protéines histoniques lors de l'extraction d'ADN ?",choices:["RNase A","Lysozyme","Protéinase K","Taq polymérase"],answer:2,diff:1,explication:"La protéinase K dégrade les protéines histoniques associées à l'ADN chromosomique, permettant de libérer l'ADN nu. Elle est utilisée après la lyse par le SDS.",tags:["Extraction ADN","Protéinase K","Histones"]},
  {id:"gen3",prompt:"Une mutation ponctuelle de type délétion entraîne principalement :",choices:["Une substitution d'un acide aminé (mutation faux sens)","Un décalage du cadre de lecture (frameshift)","L'apparition prématurée d'un codon stop uniquement","Aucune conséquence si elle touche un intron"],answer:1,diff:2,explication:"Une délétion (perte d'une paire de base) décale le cadre de lecture en aval, rendant la protéine non fonctionnelle. C'est différent d'une substitution qui modifie un seul codon.",tags:["Mutations","Délétion","Cadre de lecture"]},
  {id:"gen4",prompt:"La réplication de l'ADN se produit pendant quelle phase du cycle cellulaire ?",choices:["Phase G1","Phase S","Phase G2","Phase M (mitose)"],answer:1,diff:1,explication:"La phase S (Synthesis) correspond à la réplication de l'ADN. Elle dure 6 à 8 h dans les cellules eucaryotes et précède la phase G2 puis la mitose.",tags:["Réplication","Cycle cellulaire","Phase S"]},
  {id:"gen5",prompt:"Les fragments d'Okazaki correspondent à :",choices:["Des amorces d'ARN synthétisées par la primase","De courtes séquences d'ADN synthétisées sur le brin retardé","Des fragments d'ADN phagique","Des copies d'ARNm produites par transcription"],answer:1,diff:2,explication:"Sur le brin retardé (synthèse en sens opposé à la fourche), l'ADN ne peut être synthétisé que par petites séquences de 1000-2000 nucléotides appelées fragments d'Okazaki, ensuite ligués par la DNA ligase.",tags:["Réplication","Fragments d'Okazaki","Brin retardé"]},
  {id:"gen6",prompt:"Une banque d'ADNc (complémentaire) se distingue d'une banque génomique car :",choices:["Elle contient tous les introns et exons","Elle ne contient que les séquences codantes (issues des ARNm)","Elle est identique chez tous les tissus d'un même organisme","Elle est construite sans transcriptase inverse"],answer:1,diff:2,explication:"La banque d'ADNc est construite à partir des ARNm d'un tissu donné (via la transcriptase inverse) et ne contient donc que les séquences codantes, sans introns. Elle est tissu-spécifique.",tags:["Banques ADN","ADNc","Transcriptase inverse"]},
  {id:"gen7",prompt:"En électrophorèse sur gel d'agarose, les fragments d'ADN migrent :",choices:["Vers la cathode, les plus grands en tête","Vers l'anode, les plus petits migrant le plus loin","Vers la cathode, les plus petits migrant le plus loin","Vers l'anode, les plus grands migrant le plus loin"],answer:1,diff:1,explication:"L'ADN, chargé négativement, migre vers l'anode (+). Les petits fragments passent plus facilement dans les mailles du gel et migrent donc plus loin. La distance de migration est inversement proportionnelle au log(taille).",tags:["Électrophorèse","ADN","Migration"]},
  {id:"gen8",prompt:"Quel anticoagulant est contre-indiqué pour une PCR sur sang total ?",choices:["EDTA","Citrate de sodium","Héparine","Fluorure de sodium"],answer:2,diff:2,explication:"L'héparine inhibe la Taq polymérase et invalide la PCR. Les prélèvements sur tube EDTA (tube violet) sont préconisés pour la biologie moléculaire.",tags:["PCR","Héparine","Préanalytique"]},
  {id:"gen9",prompt:"Le marqueur fluorescent SYBR Green utilisé en PCR temps réel :",choices:["S'intercale dans les doubles brins d'ADN et émet une fluorescence","Est un anticorps couplé à une enzyme","Est une sonde Taqman complémentaire d'une séquence cible","Détecte uniquement les ARNm"],answer:0,diff:2,explication:"SYBR Green s'intercale de façon non spécifique dans tout ADN double brin formé lors de l'amplification. L'augmentation de fluorescence est proportionnelle à la quantité d'ADN synthétisé.",tags:["PCR temps réel","SYBR Green","Fluorescence"]},
  {id:"gen10",prompt:"Le Cp (Crossing Point) en PCR quantitative correspond à :",choices:["La fin de la phase plateau","Le nombre de cycles nécessaires pour que la fluorescence dépasse le seuil","La température d'hybridation des amorces","Le nombre total d'amplicons produits"],answer:1,diff:2,explication:"Le Cp est le nombre de cycles au-delà duquel la fluorescence dépasse le seuil fixé. Plus la quantité initiale d'ADN cible est élevée, plus le Cp est bas (atteint rapidement).",tags:["PCR temps réel","Cp","Quantification"]}
];

const QB_PROTEINES = [
  {id:"prot1",prompt:"La structure primaire d'une protéine correspond à :",choices:["Son repliement tridimensionnel dans l'espace","La séquence d'enchaînement des acides aminés liés par des liaisons peptidiques","L'association de plusieurs sous-unités","Son organisation en hélice alpha ou feuillet bêta"],answer:1,diff:1,explication:"La structure primaire est la séquence linéaire des acides aminés reliés par des liaisons covalentes peptidiques (entre le COOH d'un AA et le NH2 du suivant). Elle détermine toutes les structures supérieures.",tags:["Protéines","Structure primaire","Acides aminés"]},
  {id:"prot2",prompt:"L'hélice alpha est une structure secondaire stabilisée par :",choices:["Des liaisons disulfure entre cystéines","Des liaisons hydrogène intrachaîne parallèles à l'axe de l'hélice","Des liaisons ioniques entre radicaux chargés","Des interactions hydrophobes entre chaînes latérales"],answer:1,diff:2,explication:"L'hélice alpha est stabilisée par des liaisons hydrogène entre le C=O d'un résidu et le NH du résidu en position n+4 (intrachaîne, parallèles à l'axe). Ce sont des liaisons faibles mais nombreuses.",tags:["Protéines","Hélice alpha","Structure secondaire"]},
  {id:"prot3",prompt:"La dénaturation d'une protéine correspond à :",choices:["L'hydrolyse de toutes ses liaisons peptidiques","La désorganisation de sa structure 3D sans rupture des liaisons peptidiques","Sa dégradation en acides aminés libres","Sa précipitation par les sels de calcium"],answer:1,diff:1,explication:"La dénaturation = désorganisation des structures secondaire, tertiaire et quaternaire (rupture des liaisons faibles) SANS hydrolyse des liaisons peptidiques. La protéine n'est pas hydrolysée mais perd son activité biologique.",tags:["Dénaturation","Protéines","Structure"]},
  {id:"prot4",prompt:"Quel acide aminé aromatique absorbe à 280 nm en spectrophotométrie ?",choices:["Glycine","Alanine","Tyrosine et tryptophane","Lysine"],answer:2,diff:2,explication:"Les acides aminés aromatiques (Tyr, Trp) absorbent à 280 nm. La phénylalanine absorbe à 260 nm. C'est la base du dosage des protéines par absorbance à 280 nm.",tags:["Acides aminés","Spectrophotométrie","280 nm"]},
  {id:"prot5",prompt:"Le pHi (point isoélectrique) d'un acide aminé correspond au pH auquel :",choices:["L'acide aminé est totalement chargé positivement","La charge globale de la molécule est nulle (zwitterion)","L'acide aminé précipite","La dissociation est maximale"],answer:1,diff:2,explication:"Au pHi, l'acide aminé existe sous forme zwitterionique (NH3+ et COO-) avec une charge globale nulle. Il ne migre pas en électrophorèse. pHi = (pKa1 + pKa2) / 2.",tags:["Acides aminés","pHi","Électrophorèse"]},
  {id:"prot6",prompt:"Une holoprotéine se distingue d'une hétéroprotéine car :",choices:["Elle est plus grande en masse moléculaire","Elle est uniquement composée d'acides aminés, sans groupement prosthétique","Elle contient un groupement porphyrinique","Elle ne peut pas être dénaturée"],answer:1,diff:1,explication:"Holoprotéine = uniquement des acides aminés (ex : albumine). Hétéroprotéine = acides aminés + groupement non-protidique ou prosthétique (ex : hémoglobine avec hème, glycoprotéines avec glucides).",tags:["Classification protéines","Holoprotéine","Hétéroprotéine"]},
  {id:"prot7",prompt:"La réaction du biuret est une méthode de dosage basée sur :",choices:["La réaction entre les fonctions SH et le cuivre","La réaction des liaisons peptidiques avec le Cu2+ en milieu alcalin (couleur violette)","La fluorescence des acides aminés aromatiques","La précipitation par l'acide sulfosalicylique"],answer:1,diff:2,explication:"La réaction du biuret : en milieu alcalin, les liaisons peptidiques réagissent avec le Cu2+ pour former un complexe violet. Elle nécessite au moins 2 liaisons peptidiques (donc ≥ 3 AA).",tags:["Biuret","Dosage protéines","Liaison peptidique"]},
  {id:"prot8",prompt:"La structure quaternaire d'une protéine correspond à :",choices:["L'arrangement spatial d'une seule chaîne polypeptidique","L'association d'au moins 2 chaînes polypeptidiques (sous-unités ou protomères)","La séquence des acides aminés","L'organisation en hélices et feuillets"],answer:1,diff:1,explication:"La structure quaternaire est l'association non covalente de plusieurs chaînes (sous-unités). Exemple classique : l'hémoglobine (tétramère α2β2). Un dimère = 2 sous-unités, un tétramère = 4 sous-unités.",tags:["Protéines","Structure quaternaire","Sous-unités"]},
  {id:"prot9",prompt:"En électrophorèse, un acide aminé de pHi = 6 migre vers quelle électrode à pH 8 ?",choices:["Vers la cathode (−)","Vers l'anode (+) car chargé négativement à pH > pHi","Il ne migre pas car pH = 2 × pHi","Vers la cathode car chargé positivement"],answer:1,diff:3,explication:"À pH > pHi, la molécule perd des H+ et devient chargée négativement (anion) → migration vers l'anode (+). À pH < pHi, elle est chargée positivement → cathode (−).",tags:["Électrophorèse","pHi","Migration"]},
  {id:"prot10",prompt:"La collagène est une protéine fibrillaire présente principalement dans :",choices:["Les membranes mitochondriales","La matrice extracellulaire et le tissu conjonctif","Le cytoplasme des cellules musculaires","Les ribosomes"],answer:1,diff:1,explication:"Le collagène est la principale protéine de la matrice extracellulaire, synthétisée par les fibroblastes. Il assure la résistance mécanique des tendons, ligaments, peau et os. Sa structure est une triple hélice.",tags:["Collagène","Protéines fibrillaires","Tissu conjonctif"]}
];

const QB_THYROIDE_PCR = [
  {id:"thy1",prompt:"Quelle est la forme biologiquement active des hormones thyroïdiennes ?",choices:["T4 (thyroxine)","T3 (triiodothyronine)","TSH","TRH"],answer:1,diff:1,explication:"T3 est 3 à 5 fois plus active que T4. Les cellules cibles convertissent T4 en T3 par désiodation. T4 est la forme de transport principale dans le sang.",tags:["Thyroïde","T3","T4"]},
  {id:"thy2",prompt:"La TSH est produite par :",choices:["L'hypothalamus","L'anté-hypophyse","La thyroïde","La surrénale"],answer:1,diff:1,explication:"La TSH (Thyroid Stimulating Hormone) est une glycoprotéine (2 sous-unités α et β) sécrétée par l'anté-hypophyse sous stimulation de la TRH hypothalamique.",tags:["TSH","Anté-hypophyse","Axe thyroïdien"]},
  {id:"thy3",prompt:"En cas d'hypothyroïdie primaire, les taux de TSH sont :",choices:["Effondrés car la thyroïde ne répond pas","Élevés car le rétrocontrôle négatif de T3/T4 est levé","Normaux","Élevés puis effondrés"],answer:1,diff:2,explication:"Rétrocontrôle négatif : si T3/T4 sont bas (hypothyroïdie), l'hypophyse n'est plus freinée → TSH augmente pour stimuler la thyroïde. TSH élevée = signe d'hypothyroïdie primaire.",tags:["Hypothyroïdie","TSH","Rétrocontrôle négatif"]},
  {id:"thy4",prompt:"L'hormone TRH est produite par :",choices:["L'anté-hypophyse","L'hypothalamus","La thyroïde","Le pancréas"],answer:1,diff:1,explication:"La TRH (Thyrotropin-Releasing Hormone) est un tripeptide sécrété par l'hypothalamus qui stimule la sécrétion de TSH par l'anté-hypophyse.",tags:["TRH","Hypothalamus","Axe thyroïdien"]},
  {id:"thy5",prompt:"Quel est le rôle du froid sur l'axe thyroïdien ?",choices:["Il inhibe la sécrétion de TRH","Il stimule l'hypothalamus → augmentation TRH → TSH → T3/T4 (thermogenèse)","Il bloque la conversion de T4 en T3","Il n'a aucune influence"],answer:1,diff:2,explication:"Le froid stimule l'hypothalamus qui sécrète plus de TRH → plus de TSH → plus de T3/T4. Les hormones thyroïdiennes augmentent le métabolisme de base et la production de chaleur (thermogenèse).",tags:["Thermogenèse","TRH","Froid"]},
  {id:"thy6",prompt:"La température de dénaturation des brins d'ADN en PCR est de :",choices:["37°C","72°C","95°C","50-55°C"],answer:2,diff:1,explication:"L'étape de dénaturation en PCR se réalise à 95°C pour rompre les liaisons hydrogène entre les 2 brins d'ADN et obtenir 2 brins simples accessibles aux amorces.",tags:["PCR","Dénaturation","Thermocycleur"]},
  {id:"thy7",prompt:"La Taq polymérase utilisée en PCR provient de :",choices:["Bacillus subtilis","Thermus aquaticus (bactérie thermophile)","Escherichia coli","Saccharomyces cerevisiae"],answer:1,diff:1,explication:"La Taq polymérase est une ADN polymérase thermostable extraite de Thermus aquaticus, une bactérie vivant dans des sources hydrothermales. Elle résiste aux 95°C de la dénaturation.",tags:["PCR","Taq polymérase","Thermus aquaticus"]},
  {id:"thy8",prompt:"En PCR, les 3 étapes d'un cycle sont dans l'ordre :",choices:["Hybridation → Élongation → Dénaturation","Dénaturation (95°C) → Hybridation (50-55°C) → Élongation (72°C)","Élongation (72°C) → Dénaturation (95°C) → Hybridation","Dénaturation → Élongation → Hybridation"],answer:1,diff:1,explication:"Cycle PCR : 1) Dénaturation 95°C (séparation des brins) ; 2) Hybridation 50-55°C (fixation des amorces) ; 3) Élongation 72°C (extension par Taq polymérase de 5' vers 3').",tags:["PCR","Thermocycleur","Cycle"]},
  {id:"thy9",prompt:"Le contrôle de l'amplification PCR s'effectue par :",choices:["Western blot","Électrophorèse sur gel d'agarose avec marqueur de taille","ELISA","Spectrophotométrie à 260 nm"],answer:1,diff:1,explication:"L'électrophorèse sur gel d'agarose révèle les amplicons après migration et coloration (BrEt ou SYBR Safe). Une seule bande nette à la taille attendue valide l'amplification.",tags:["PCR","Contrôle","Électrophorèse"]},
  {id:"thy10",prompt:"La PCR en temps réel permet de :",choices:["Visualiser les produits après la réaction par gel","Quantifier l'ADN cible en suivant la fluorescence cycle par cycle","Séquencer directement l'ADN amplifié","Détecter uniquement des protéines"],answer:1,diff:1,explication:"La PCR quantitative (qPCR) suit en temps réel l'augmentation de fluorescence proportionnelle à la quantité d'ADN néoformé. Elle permet de quantifier la cible initiale grâce au Cp.",tags:["qPCR","Temps réel","Quantification"]}
];

const QB_FOIE_REIN = [
  {id:"fr1",prompt:"Une augmentation isolée des transaminases ASAT et ALAT signe :",choices:["Une cholestase biliaire","Une cytolyse hépatique (lésions des hépatocytes)","Une insuffisance rénale","Une hypothyroïdie"],answer:1,diff:1,explication:"ASAT (aspartate aminotransférase) et ALAT (alanine aminotransférase) sont libérées lors de la lyse des hépatocytes. Leur augmentation signe une cytolyse hépatique (hépatites, alcool, médicaments).",tags:["Bilan hépatique","ASAT","ALAT","Cytolyse"]},
  {id:"fr2",prompt:"Une augmentation des phosphatases alcalines (PAL) et de la bilirubine conjuguée oriente vers :",choices:["Cytolyse hépatique","Cholestase (obstruction des voies biliaires)","Insuffisance hépatocellulaire","Hémochromatose"],answer:1,diff:2,explication:"PAL + bilirubine conjuguée élevées = cholestase. Les PAL sont libérées lors d'une obstruction biliaire. La bilirubine conjuguée (hydrosoluble) reflue dans le sang en cas de cholestase.",tags:["Bilan hépatique","Cholestase","PAL","Bilirubine"]},
  {id:"fr3",prompt:"L'albumine sérique est synthétisée exclusivement par :",choices:["Les reins","Le foie (hépatocytes)","La rate","Le pancréas"],answer:1,diff:1,explication:"L'albumine est la principale protéine plasmatique (40 g/L) synthétisée par les hépatocytes. Une hypoalbuminémie signe une insuffisance hépatocellulaire sévère ou une dénutrition sévère.",tags:["Albumine","Foie","Protéines sériques"]},
  {id:"fr4",prompt:"Le principal rôle de détoxification du foie concerne la conversion :",choices:["Du glucose en glycogène","De l'ammoniac (NH4+) en urée (cycle de l'urée)","Des acides gras en corps cétoniques","Du CO2 en bicarbonate"],answer:1,diff:1,explication:"Le foie est le seul organe capable de transformer l'ammoniac (toxique) en urée (non toxique) via le cycle de l'urée, permettant son excrétion rénale.",tags:["Foie","Détoxification","Urée","Cycle de l'urée"]},
  {id:"fr5",prompt:"Quelle est la différence entre bilirubine directe et bilirubine indirecte ?",choices:["Aucune différence pratique","Directe = conjuguée (hydrosoluble) ; Indirecte = libre/non conjuguée (liposoluble)","Directe = liposoluble ; Indirecte = hydrosoluble","La bilirubine directe est produite dans les hématies"],answer:1,diff:2,explication:"Bili indirecte (libre) = non conjuguée, liposoluble, liée à l'albumine dans le sang. Bili directe (conjuguée) = conjuguée à l'acide glucuronique par le foie, hydrosoluble, excrétée dans la bile.",tags:["Bilirubine","Conjuguée","Non conjuguée","Foie"]},
  {id:"fr6",prompt:"L'unité fonctionnelle du rein est :",choices:["Le glomérule","Le néphron (glomérule + tubule)","La capsule de Bowman","Le tube collecteur"],answer:1,diff:1,explication:"Le néphron est l'unité fonctionnelle du rein. Il comprend le corpuscule rénal (glomérule + capsule de Bowman) et le système tubulaire (TCP, anse de Henlé, TCD, tube collecteur).",tags:["Rein","Néphron","Anatomie"]},
  {id:"fr7",prompt:"La filtration glomérulaire est un phénomène :",choices:["Actif nécessitant de l'ATP","Passif (osmose et dialyse) sous pression hydrostatique","Actif avec cotransport Na+","Passif mais régulé par l'ADH"],answer:1,diff:2,explication:"La filtration glomérulaire est un phénomène passif. La pression hydrostatique du sang pousse l'eau et les petits solutés à travers la membrane. Les grosses molécules (protéines) ne passent pas.",tags:["Rein","Filtration glomérulaire","Passif"]},
  {id:"fr8",prompt:"L'hormone ADH (vasopressine) agit sur le rein en :",choices:["Augmentant la sécrétion de Na+","Augmentant la perméabilité à l'eau du tube collecteur (réabsorption d'eau)","Stimulant la sécrétion de rénine","Inhibant la réabsorption du glucose"],answer:1,diff:2,explication:"L'ADH (antidiuretic hormone) sécrétée par la neurohypophyse augmente la perméabilité à l'eau du tube collecteur via les aquaporines → réabsorption d'eau → urine concentrée.",tags:["ADH","Vasopressine","Tube collecteur","Réabsorption"]},
  {id:"fr9",prompt:"Le système rénine-angiotensine est activé en cas de :",choices:["Hypertension artérielle et hypervolémie","Baisse de la pression sanguine ou baisse du Na+ dans le TCD","Hyperkaliémie","Alcalose métabolique"],answer:1,diff:2,explication:"L'appareil juxtagloméruaire sécrète de la rénine en réponse à une baisse de pression artérielle ou de Na+ dans le TCD. La rénine → angiotensine I → angiotensine II → aldostérone → rétention Na+/eau → ↑ PA.",tags:["SRAA","Rénine","Pression artérielle"]},
  {id:"fr10",prompt:"La créatinine est un marqueur de la fonction rénale car :",choices:["Elle est synthétisée par le rein et reflète sa production","Elle est filtrée par le glomérule et peu réabsorbée, reflétant le DFG","Elle est réabsorbée à 99% par le TCP","Elle est sécrétée par les tubules uniquement"],answer:1,diff:2,explication:"La créatinine est produite à débit constant par le muscle et librement filtrée par le glomérule avec une réabsorption tubulaire négligeable. Sa concentration plasmatique est inversement proportionnelle au débit de filtration glomérulaire (DFG).",tags:["Créatinine","DFG","Insuffisance rénale"]}
];

const QB_BACTERIES_PP = [
  {id:"bac1",prompt:"La coloration de Gram distingue les bactéries selon :",choices:["Leur forme (cocci vs bacilles)","La structure de leur paroi : Gram+ = paroi épaisse (peptidoglycane) ; Gram- = double membrane","Leur capacité à former des spores","Leur mobilité flagellaire"],answer:1,diff:1,explication:"Gram+ : paroi épaisse en peptidoglycane, retient le cristal violet → violet. Gram- : paroi mince avec membrane externe lipopolysaccharidique, se décolore → rose (contre-coloration safranine).",tags:["Coloration de Gram","Gram+","Gram-","Paroi bactérienne"]},
  {id:"bac2",prompt:"Parmi ces bactéries, lesquelles sont des bacilles Gram négatif de la famille des entérobactéries ?",choices:["Staphylococcus aureus et Streptococcus","E. coli, Salmonella et Klebsiella","Clostridium et Bacillus","Mycobacterium et Listeria"],answer:1,diff:1,explication:"E. coli, Salmonella, Klebsiella, Shigella, Yersinia sont des Entérobactéries (bacilles Gram−, AAF). Staphylococcus/Streptococcus sont des cocci Gram+; Clostridium et Bacillus sont des bacilles Gram+.",tags:["Entérobactéries","Gram-","E. coli","Salmonella"]},
  {id:"bac3",prompt:"Le LPS (lipopolysaccharide) des bactéries Gram négatif est responsable de :",choices:["La formation de spores","Le choc septique/toxique lors de la lyse bactérienne (endotoxine)","La résistance aux antibiotiques par bêta-lactamase","L'adhésion aux cellules épithéliales uniquement"],answer:1,diff:2,explication:"Le LPS de la membrane externe des Gram- est une endotoxine libérée lors de la lyse bactérienne. Il active massivement le système immunitaire et peut provoquer un choc septique.",tags:["LPS","Gram-","Endotoxine","Choc septique"]},
  {id:"bac4",prompt:"La capsule bactérienne favorise la virulence en :",choices:["Augmentant la production de toxines","Inhibant la phagocytose en empêchant la fixation du complément (C3b)","Facilitant la pénétration dans les cellules épithéliales","Neutralisant les antibiotiques"],answer:1,diff:2,explication:"La capsule (polysaccharidique chez Streptococcus pneumoniae, Klebsiella, etc.) constitue un facteur anti-phagocytaire majeur. Elle empêche la fixation des opsonines (C3b, IgG) → résistance à la phagocytose.",tags:["Capsule","Virulence","Anti-phagocytose"]},
  {id:"bac5",prompt:"Les exotoxines bactériennes sont de nature :",choices:["Glucido-lipido-protéique (LPS)","Protéique, sécrétées par la bactérie vivante","Lipidique uniquement","Polysaccharidique"],answer:1,diff:1,explication:"Les exotoxines sont des protéines sécrétées par les bactéries vivantes (Gram+ et Gram-). Elles sont très actives à faible dose et antigéniques. Les endotoxines (LPS) ne sont libérées qu'à la lyse.",tags:["Exotoxines","Protéines","Virulence"]},
  {id:"bac6",prompt:"La bactériémie correspond à :",choices:["La présence de bactéries dans l'urine","La diffusion de bactéries dans le sang (voie lymphatique ou directe)","Une infection localisée à la peau","La présence de toxines dans le sang"],answer:1,diff:1,explication:"La bactériémie = bactéries circulant dans le sang. Elle peut évoluer vers un sepsis (réponse inflammatoire systémique) ou un choc septique si non traitée. Différente de la toxinémie (toxines sans bactéries).",tags:["Bactériémie","Sepsis","Dissémination"]},
  {id:"bac7",prompt:"Staphylococcus aureus produit une toxine superantigène qui :",choices:["Lyse les membranes cellulaires par formation de pores","Active massivement les lymphocytes T → libération de cytokines → choc toxique","Inhibe la synthèse de protéines ribosomales","Bloque les neurotransmetteurs (comme la toxine botulique)"],answer:1,diff:3,explication:"Les superantigènes (toxines du syndrome du choc toxique staphylococcique = TSST-1) se fixent aux CMH II et au TCR sans traitement antigénique classique → activation de 20-30% des LT → cytokines → choc toxique.",tags:["Superantigène","Choc toxique","Staphylocoque"]},
  {id:"bac8",prompt:"Pseudomonas aeruginosa est classé parmi les :",choices:["Entérobactéries","Bacilles Gram− aérobies stricts (non entérobactérie)","Bacilles Gram+ aérobies","Cocci Gram−"],answer:1,diff:2,explication:"Pseudomonas aeruginosa est un bacille Gram−, aérobie strict (non fermentant). Il est très résistant aux antibiotiques et est une cause majeure d'infections nosocomiales, notamment chez les immunodéprimés.",tags:["Pseudomonas","Gram-","Aérobie strict","Nosocomial"]},
  {id:"bac9",prompt:"Les anaérobies stricts sont des bactéries qui :",choices:["Peuvent se développer avec ou sans oxygène","Ne peuvent pas se développer en présence d'oxygène (O2 toxique)","Se développent uniquement à 4°C","Sont toutes sporulées"],answer:1,diff:1,explication:"Les anaérobies stricts (Bacteroides, Clostridium, Fusobacterium...) sont tués par l'O2 car ils manquent de superoxyde dismutase et de catalase. Ils colonisent les sites sans oxygène (côlon, plaies profondes).",tags:["Anaérobies","Clostridium","Bacteroides","Oxygène"]},
  {id:"bac10",prompt:"La toxine botulique (Clostridium botulinum) agit en :",choices:["Lysant les membranes par formation de pores","Bloquant la libération d'acétylcholine à la jonction neuromusculaire (paralysie flasque)","Activant massivement les lymphocytes T","ADP-ribosylant la protéine G (comme le choléra)"],answer:1,diff:2,explication:"La toxine botulique a une activité protéasique qui clive les protéines SNARE nécessaires à la fusion des vésicules synaptiques → blocage de la libération d'acétylcholine → paralysie flasque descandante.",tags:["Toxine botulique","Clostridium","Acétylcholine","Paralysie"]}
];

const QB_LEVURES_LEUCO = [
  {id:"lev1",prompt:"Candida albicans se distingue des autres levures Candida par :",choices:["Sa couleur rose sur milieu chromogène","Sa coloration bleue sur milieu chromogène ET la formation de tubes germinatifs à 37°C en sérum","Sa résistance à tous les antifongiques","Sa forme en bâtonnet"],answer:1,diff:2,explication:"Candida albicans : colonie bleue sur milieu chromogène (ex: CHROMagar) + test de blastèse positif (tubes germinatifs après 2-4h à 37°C en sérum). C. tropicalis est rose, C. glabrata blanc/rose.",tags:["Candida albicans","Milieu chromogène","Test de blastèse"]},
  {id:"lev2",prompt:"Le test de la tréhalase permet d'identifier rapidement :",choices:["Candida albicans","Candida glabrata (résultat en 15 min)","Cryptococcus neoformans","Trichosporon"],answer:1,diff:2,explication:"C. glabrata possède une tréhalase qui hydrolyse rapidement le tréhalose en 15 minutes. Ce test rapide permet son identification directe sans attendre les galeries complètes.",tags:["Candida glabrata","Tréhalase","Identification rapide"]},
  {id:"lev3",prompt:"La réduction du TTC (tétrazolium) par les levures produit un composé coloré nommé formazan. Quel résultat indique Candida albicans ?",choices:["Formazan violet (forte réduction)","Formazan blanc (pas ou peu de réduction)","Formazan rouge","Formazan vert fluorescent"],answer:1,diff:2,explication:"C. albicans produit un formazan blanc (faible réduction du TTC) contrairement à C. tropicalis qui produit un formazan violet intense. Ce test différencie ces 2 espèces importantes.",tags:["TTC","Formazan","Candida albicans","Candida tropicalis"]},
  {id:"lev4",prompt:"Les chlamydospores sont des spores de résistance rondes terminales caractéristiques de :",choices:["Trichosporon (arthrospores)","Candida albicans","Cryptococcus (capsule)","Aspergillus"],answer:1,diff:2,explication:"Les chlamydospores (grosses spores rondes à paroi épaisse, terminales ou latérales) sont caractéristiques de Candida albicans sur milieu pauvre (RAT 25°C, 48h). Elles permettent l'identification morphologique.",tags:["Chlamydospores","Candida albicans","Morphologie"]},
  {id:"lev5",prompt:"Une polynucléose neutrophile (PNN > 7 G/L) avec myélémie oriente vers :",choices:["Une infection parasitaire (toxoplasmose)","Un syndrome myéloprolifératif malin ou une infection bactérienne aiguë","Une mononucléose infectieuse (EBV)","Une leucémie lymphoïde chronique"],answer:1,diff:2,explication:"PNN > 7 G/L = hyperleucocytose à polynucléaires neutrophiles. Avec myélémie (formes jeunes non segmentées dans le sang), on oriente vers un syndrome myéloprolifératif. Sans myélémie = réaction bénigne (infection bactérienne).",tags:["Polynucléose neutrophile","Myélémie","Syndrome myéloprolifératif"]},
  {id:"lev6",prompt:"La mononucléose infectieuse est causée par :",choices:["Toxoplasma gondii","Le virus Epstein-Barr (EBV)","Staphylococcus aureus","Candida albicans"],answer:1,diff:1,explication:"La MNI est due au virus EBV (Herpesvirus). Elle entraîne une hyperlymphocytose avec grands lymphocytes hyperbasophiles, fièvre, angine et fatigue. Diagnostic : MNI-test (monospot) + sérologie EBV.",tags:["Mononucléose infectieuse","EBV","Lymphocytose"]},
  {id:"lev7",prompt:"La polynucléose éosinophile (PNE > 5 G/L) est classiquement associée à :",choices:["Les infections bactériennes sévères","Les infections parasitaires et les allergies","La leucémie myéloïde chronique","La thrombopénie"]  ,answer:1,diff:1,explication:"L'hyperéosinophilie oriente en priorité vers une allergie (asthme, rhinite, urticaire) ou une parasitose (toxocarose, anisakiose, bilharziose). Mémorisé par 'PAPA' : Parasites, Allergies, Pathologies malignes, Atopie.",tags:["Éosinophilie","Allergies","Parasitoses"]},
  {id:"lev8",prompt:"Dans la toxoplasmose, l'hyperimmunoglobuline de type IgM signifie :",choices:["Infection ancienne (sérologie cicatricielle)","Infection récente ou réactivation (primo-infection probable)","Immunité naturelle sans infection","Contamination du prélèvement"],answer:1,diff:2,explication:"IgM anti-toxoplasme = marqueur de primo-infection ou réactivation récente. Les IgG persistent des années (sérologie cicatricielle). En grossesse, la primo-infection à Toxoplasma peut être grave pour le fœtus.",tags:["Toxoplasmose","IgM","Sérologie","Primo-infection"]},
  {id:"lev9",prompt:"La leucémie lymphoïde chronique (LLC) est caractérisée par :",choices:["Une prolifération de cellules myéloïdes immatures","Une prolifération monoclonale de lymphocytes B matures avec hyperlymphocytose > 65 ans","Une thrombocytose importante","Une pancytopénie sans lymphocytose"],answer:1,diff:2,explication:"LLC = accumulation clonale de petits lymphocytes B matures (CD5+, CD19+, CD23+). Pic à 65 ans, souvent asymptomatique. Diagnostic = score de Matutes ≥ 4 sur cytologie + immunophénotypage.",tags:["LLC","Leucémie lymphoïde chronique","Lymphocytes B"]},
  {id:"lev10",prompt:"Une neutropénie sévère (PNN < 0,5 G/L) représente un risque majeur de :",choices:["Thrombose veineuse","Infections bactériennes et fongiques graves","Hémorragies spontanées","Réactions allergiques"],answer:1,diff:1,explication:"Les PNN sont la première ligne de défense contre les infections bactériennes et fongiques. En dessous de 0,5 G/L (neutropénie sévère, ex: chimiothérapie), le risque d'infections graves (Gram−, Candida, Aspergillus) est majeur.",tags:["Neutropénie","Infections","Immunodépression"]}
];

const QB_LCR_PUS = [
  {id:"lcr1",prompt:"L'aspect macroscopique normal du LCR est :",choices:["Jaune citrin (xanthochromique)","Eau de roche (incolore et limpide)","Légèrement trouble","Rose pâle"],answer:1,diff:1,explication:"Le LCR normal est incolore et limpide comme 'eau de roche'. Un LCR trouble = méningite purulente (bactérienne). LCR jaune = xanthochromique (hémorragie ancienne ou hyperbilirubinémie). LCR hémorragique = traumatisme ou hémorragie sous-arachnoïdienne.",tags:["LCR","Aspect macroscopique","Normal"]},
  {id:"lcr2",prompt:"Pour un examen du LCR, le prélèvement doit être acheminé en laboratoire en moins de :",choices:["2 heures à froid","30 minutes à température ambiante","6 heures à 4°C","24 heures après centrifugation"],answer:1,diff:2,explication:"Le LCR doit parvenir au laboratoire en moins de 30 minutes à température ambiante, dans 3 tubes stériles sans anticoagulant. Une attente prolongée dégrade les cellules et peut fausser le résultat cyto-bactériologique.",tags:["LCR","Préanalytique","Transport"]},
  {id:"lcr3",prompt:"Une méningite bactérienne se distingue d'une méningite virale par :",choices:["Aucune différence de LCR","LCR trouble (purulent) + hyperprotéinorachie + hypoglycorachie + prédominance de PNN","LCR clair + lymphocytose + normoglycorachie","LCR jaune avec hématies"],answer:1,diff:2,explication:"Méningite bactérienne : LCR trouble, protéines ↑↑ (> 1 g/L), glucose ↓ (< 0,5 × glycémie), PNN prédominent. Méningite virale : LCR clair, protéines légèrement élevées, glucose normal, lymphocytes prédominent.",tags:["Méningite bactérienne","LCR","Cytologie","Biochimie"]},
  {id:"lcr4",prompt:"Les 3 voies d'invasion des méninges par les agents pathogènes sont :",choices:["Voie orale, cutanée, respiratoire","Directe (traumatisme/chirurgie), hématogène (voie sanguine), et contiguïté (infection ORL)","Uniquement par voie hématogène","Voie urinaire, digestive et respiratoire"],answer:1,diff:2,explication:"Les méningites infectieuses résultent de : 1) Inoculation directe (neurochirurgie, traumatisme crânien) ; 2) Voie indirecte hématogène (bactériémie, infection ORL de voisinage) ; 3) Piqûre de vecteur (tiques → encéphalites).",tags:["Méningites","Voies d'invasion","LCR"]},
  {id:"lcr5",prompt:"Le pus est défini comme :",choices:["Du sang extravase dans les tissus","Un ensemble de cellules phagocytaires et de bactéries dans un foyer infectieux","Du liquide séreux d'une séreuse","Des cellules nécrotiques sans infection"],answer:1,diff:1,explication:"Le pus est constitué de polynucléaires neutrophiles morts et vivants (pyocytes), de bactéries, de débris cellulaires et de sérum. Il signe une infection bactérienne avec réaction inflammatoire locale intense.",tags:["Pus","Suppuration","Pyocytes"]},
  {id:"lcr6",prompt:"Un prélèvement de pus doit être réalisé dans des conditions :",choices:["Sans précautions particulières, en ambulatoire","D'asepsie stricte, avant toute antibiothérapie, transporté en moins de 2h","Après 48h d'antibiothérapie pour évaluer l'efficacité","Dans un tube avec anticoagulant EDTA"],answer:1,diff:1,explication:"Les prélèvements de pus doivent être réalisés en asepsie chirurgicale, AVANT antibiothérapie, transportés dans un système hermétique en moins de 2h à température ambiante pour préserver les germes anaérobies.",tags:["Pus","Préanalytique","Asepsie","Antibiothérapie"]},
  {id:"lcr7",prompt:"Dans une suppuration de classe I, le foyer infectieux se situe dans :",choices:["Une zone en contact avec une flore commensale","Une zone profonde normalement stérile (os, articulation, cerveau)","Le tube digestif","Les voies respiratoires supérieures"],answer:1,diff:2,explication:"Classe I = zone normalement stérile (méningite, abcès cérébral, arthrite septique, ostéomyélite). Classe II = zone en contact avec une flore commensale (abcès dentaire, péritonite par perforation). Implications sur la flore attendue.",tags:["Suppuration","Classe I","Zones stériles"]},
  {id:"lcr8",prompt:"Pour cultiver des germes anaérobies à partir d'un liquide de ponction, on utilise :",choices:["Un tube sec ordinaire (tube rouge)","Des flacons d'hémoculture anaérobie et une mise en culture rapide","Un tube EDTA (violet)","Un tube hépariné (vert)"],answer:1,diff:2,explication:"Les anaérobies sont très sensibles à l'O2. Pour les cultiver : flacons d'hémoculture (flacons aérobie et anaérobie), culture rapide en moins de 2h, milieu anaérobie strict, hotte de manipulation. Le volume minimum est 2-5 mL.",tags:["Anaérobies","Culture","Hémoculture","LCR"]},
  {id:"lcr9",prompt:"L'hémoculture est positive dans quel pourcentage des méningites bactériennes ?",choices:["10-20%","70%","99%","30-40%"],answer:1,diff:2,explication:"L'hémoculture est positive dans environ 70% des méningites bactériennes (bactériémie souvent associée). Elle permet d'identifier le germe et son antibiogramme, complémentant l'analyse du LCR.",tags:["Hémoculture","Méningite bactérienne","Diagnostic"]},
  {id:"lcr10",prompt:"La xanthochromie du LCR indique :",choices:["Une méningite bactérienne aiguë","Une hémorragie ancienne (dégradation de l'hémoglobine en bilirubine/oxyhémoglobine)","Une méningite fongique","Un LCR normal chez le nourrisson"],answer:1,diff:2,explication:"La xanthochromie (teinte jaune) du LCR résulte de la dégradation de l'hémoglobine en oxyhémoglobine (rose/rouge, 2h après hémorragie) puis en bilirubine (jaune, > 12h). Elle signe une hémorragie sous-arachnoïdienne ou intracrânienne ancienne.",tags:["Xanthochromie","LCR","Hémorragie sous-arachnoïdienne"]}
];

const QB_ANEMIES_HEM = [
  {id:"ane1",prompt:"Par définition, l'anémie est diagnostiquée lorsque la concentration en hémoglobine est inférieure à :",choices:["160 g/L","130 g/L chez l'adulte (variante selon âge/sexe)","200 g/L","100 g/L"],answer:1,diff:1,explication:"Seuil OMS : anémie si Hb < 130 g/L chez l'homme adulte, < 120 g/L chez la femme, < 110 g/L chez la femme enceinte. Le nouveau-né a une Hb plus élevée (> 140 g/L).",tags:["Anémie","Hémoglobine","Seuil OMS"]},
  {id:"ane2",prompt:"Une anémie ferriprive (carence martiale) est caractérisée par :",choices:["VGM élevé, CCMH normale, ferritine élevée","VGM bas (microcytose), CCMH basse (hypochromie), ferritine basse et CTF augmentée","VGM normal, CCMH normale, B12 basse","VGM élevé, CCMH normale, réticulocytes élevés"],answer:1,diff:2,explication:"L'anémie ferriprive = manque de fer → défaut de synthèse d'Hb → microcytose (VGM < 80 fL) + hypochromie (CCMH < 320 g/L). Ferritine basse (réserves épuisées) + CTF élevée (transferrine peu saturée).",tags:["Anémie ferriprive","Microcytose","Ferritine","CTF"]},
  {id:"ane3",prompt:"La cause la plus fréquente d'anémie macrocytaire est :",choices:["L'hémolyse","La carence en vitamine B12 ou B9 (acide folique)","La thalassémie","L'insuffisance rénale chronique"],answer:1,diff:1,explication:"Les carences en B12 (cobalamine) ou B9 (folates) bloquent la synthèse d'ADN → érythropoïèse inefficace → mégaloblastes (grandes cellules immatures) → anémie macrocytaire avec VGM > 100 fL.",tags:["Anémie macrocytaire","Vitamine B12","Acide folique","Mégaloblastique"]},
  {id:"ane4",prompt:"La maladie de Biermer est une anémie mégaloblastique due à :",choices:["Un déficit alimentaire en fer","Une maladie auto-immune détruisant les cellules pariétales gastriques → absence de facteur intrinsèque → malabsorption de B12","Une hémolyse chronique","Une dénutrition protéique"],answer:1,diff:2,explication:"La maladie de Biermer = gastrite auto-immune avec Ac anti-cellules pariétales et anti-facteur intrinsèque. Sans facteur intrinsèque, la B12 ne peut pas être absorbée dans l'iléon → anémie mégaloblastique.",tags:["Maladie de Biermer","Facteur intrinsèque","Vitamine B12","Auto-immune"]},
  {id:"ane5",prompt:"Une anémie est dite 'régénérative' lorsque :",choices:["La moelle osseuse ne fonctionne pas","Le nombre de réticulocytes est élevé (> 120 G/L), signe d'une réponse médullaire active","La ferritine est basse","L'ALAT est augmentée"],answer:1,diff:2,explication:"Réticulocytes > 120 G/L = anémie régénérative (hémolyse ou hémorragie aiguë = la moelle compense). Réticulocytes bas = anémie arégénérative (carences, insuffisance médullaire, aplasie).",tags:["Réticulocytes","Anémie régénérative","Érythropoïèse"]},
  {id:"ane6",prompt:"L'adaptation intra-érythrocytaire à l'anémie consiste en :",choices:["Une tachycardie compensatrice","Une augmentation du 2,3-BPG (bisphosphoglycérate) → diminution de l'affinité de l'Hb pour O2 → meilleure cession aux tissus","Une vasodilatation périphérique","Une augmentation de la synthèse d'albumine"],answer:1,diff:3,explication:"En réponse à l'hypoxie, les GR augmentent la production de 2,3-BPG (médiateur allostérique) qui diminue l'affinité de l'Hb pour O2 → décrochage plus facile de l'O2 vers les tissus (effet Bohr).",tags:["2,3-BPG","Hémoglobine","Adaptation","Hypoxie"]},
  {id:"ane7",prompt:"Les hémopathies malignes résultent de :",choices:["Infections virales systématiques","Mutations acquises dans des cellules souches hématopoïétiques → prolifération clonale incontrôlée","Carences nutritionnelles graves","Déficits immunitaires congénitaux"],answer:1,diff:1,explication:"Les hémopathies malignes (leucémies, lymphomes, myélomes) résultent de mutations somatiques acquises dans des progéniteurs hématopoïétiques (activation d'oncogènes, perte de gènes suppresseurs de tumeurs → prolifération clonale).",tags:["Hémopathies malignes","Mutations","Clone cellulaire","Hématopoïèse"]},
  {id:"ane8",prompt:"Les 4 grandes catégories d'hémopathies malignes sont :",choices:["Anémies, thrombopénies, granulopénies et lymphopénies","Syndromes myéloprolifératifs, lymphoprolifératifs, myélodysplasiques et leucémies aiguës","Leucémies, lymphomes, myélomes et anémies","Hémophilies A, B, C et D"],answer:1,diff:2,explication:"Classification des hémopathies malignes : 1) Syndromes myéloprolifératifs (LMC, polyglobulie…) ; 2) Syndromes lymphoprolifératifs (LLC, lymphomes) ; 3) Syndromes myélodysplasiques ; 4) Leucémies aiguës (LAM, LAL).",tags:["Hémopathies malignes","Classification","Leucémies","Lymphomes"]},
  {id:"ane9",prompt:"La cellule souche hématopoïétique est identifiable par le marqueur de surface :",choices:["CD3","CD19","CD34","CD8"],answer:2,diff:2,explication:"CD34 est le marqueur de surface caractéristique des cellules souches et progéniteurs hématopoïétiques. CD3 = lymphocytes T ; CD19/CD20 = lymphocytes B ; CD8 = LT cytotoxiques.",tags:["CD34","Cellule souche hématopoïétique","Immunophénotypage"]},
  {id:"ane10",prompt:"Dans la LLC (leucémie lymphoïde chronique), le score de Matutes diagnostique repose sur :",choices:["La présence de blastes circulants","Des critères cytologiques et immunophénotypiques (score ≥ 4 sur 5 = LLC)","Une translocation chromosomique 9/22 (Philadelphia)","Une hypergammaglobulinémie monoclonale"],answer:1,diff:3,explication:"Le score de Matutes évalue 5 critères immunophénotypiques (CD5+, CD23+, FMC7−, Ig de surface faible, CD22/CD79b faible). Score ≥ 4 = LLC typique. La translocation 9/22 (BCR-ABL) caractérise la LMC, non la LLC.",tags:["LLC","Score de Matutes","Immunophénotypage","Diagnostic"]}
];


const QB_PCR_AVANCEE = [
  {id:"pcrav1",prompt:"Quel est le paramètre CT (Cycle Threshold) en PCR en temps réel ?",choices:["Le nombre total de cycles programmés","Le numéro du cycle où la fluorescence dépasse le seuil de détection","La température d'hybridation optimale","La quantité de Taq polymérase utilisée"],answer:1,diff:1,explication:"Le CT est le numéro du cycle à partir duquel le signal fluorescent devient significativement supérieur au bruit de fond. Un CT faible = séquence cible très abondante initialement (peu de cycles nécessaires pour amplifier).",tags:["qPCR","CT","Fluorescence","Quantification"]},
  {id:"pcrav2",prompt:"Quelle est la différence fondamentale entre la PCR nichée et la PCR classique ?",choices:["La PCR nichée utilise 4 amorces en 2 amplifications successives pour augmenter la spécificité","La PCR nichée ne nécessite pas de Taq polymérase","La PCR nichée amplifie l'ARN directement","La PCR nichée se réalise à température constante (isotherme)"],answer:0,diff:2,explication:"La PCR nichée réalise 2 amplifications : la 1ère avec un couple d'amorces externes, la 2ème avec un couple interne (ciblant l'intérieur du 1er amplicon). 4 amorces au total → spécificité très élevée. Application : diagnostic de Treponema pallidum (syphilis).",tags:["PCR nichée","Spécificité","Amorces"]},
  {id:"pcrav3",prompt:"Dans le test GeneXpert MTB/RIF, quel gène est ciblé pour détecter la résistance à la rifampicine ?",choices:["Gène 16S ARNr","Gène rpoB (sous-unité β de l'ARN polymérase)","Gène mecA","Gène tpp47"],answer:1,diff:3,explication:"Le gène rpoB code la sous-unité bêta de l'ARN polymérase de Mycobacterium tuberculosis. Les mutations dans ce gène confèrent la résistance à la rifampicine. GeneXpert utilise 5 sondes spécifiques du gène rpoB + 1 sonde contrôle (Bacillus globigii).",tags:["GeneXpert","rpoB","Tuberculose","Résistance rifampicine"]},
  {id:"pcrav4",prompt:"La RT-PCR est utilisée pour amplifier des virus à ARN car :",choices:["L'ARN est plus stable que l'ADN","Une transcriptase inverse convertit préalablement l'ARN en ADNc, amplifiable ensuite par PCR","L'ARN peut être directement amplifié par la Taq polymérase","L'ARN est plus facile à extraire que l'ADN"],answer:1,diff:1,explication:"La Taq polymérase ne peut amplifier que l'ADN. Pour les virus à ARN (HIV, HCV, SARS-CoV-2…), une étape préalable de transcription inverse (reverse transcriptase) convertit l'ARN viral en ADNc, qui sera ensuite amplifié classiquement.",tags:["RT-PCR","Transcriptase inverse","ARN","Virus"]},
  {id:"pcrav5",prompt:"La méthode LAMP (Loop-Mediated Isothermal Amplification) se distingue de la PCR car :",choices:["Elle utilise 2 amorces à 95°C","Elle amplifie l'ADN à température constante sans dénaturation thermique par thermocycleur","Elle n'est utilisable que sur les bactéries Gram+","Elle produit des amplicons de taille fixe"],answer:1,diff:2,explication:"LAMP est une amplification isotherme (même température tout au long de la réaction) grâce à une ADN polymérase à déplacement de brin. Pas besoin de thermocycleur. Révélation par fluorescence (calcéine). Limite : nombreux faux positifs.",tags:["LAMP","Isotherme","Amplification","Diagnostic terrain"]},
  {id:"pcrav6",prompt:"Pourquoi l'héparine est-elle contre-indiquée pour les prélèvements destinés à la PCR ?",choices:["Elle dégrade l'ADN par hydrolyse","Elle inhibe la Taq polymérase et bloque l'amplification","Elle coagule l'échantillon dans le thermocycleur","Elle est incompatible avec les dNTP"],answer:1,diff:2,explication:"L'héparine, anticoagulant présent dans les tubes verts, inhibe directement l'activité de la Taq polymérase, rendant la PCR impossible. Les tubes EDTA (violets) sont préconisés pour la biologie moléculaire.",tags:["Héparine","PCR","Préanalytique","Taq polymérase"]},
  {id:"pcrav7",prompt:"En PCR multiplex, plusieurs couples d'amorces sont utilisés simultanément dans le même tube pour :",choices:["Augmenter la sensibilité d'une seule cible","Amplifier plusieurs séquences différentes en une seule réaction","Remplacer les témoins positifs","Éliminer les inhibiteurs de PCR"],answer:1,diff:1,explication:"La PCR multiplex co-amplifie plusieurs cibles ADN dans le même tube. Application majeure : profils d'empreintes génétiques (15 loci STR simultanément), panel de virus respiratoires, détection multi-résistances.",tags:["PCR multiplex","Empreintes génétiques","STR","Multi-cibles"]},
  {id:"pcrav8",prompt:"Kary Mullis a reçu le prix Nobel de chimie en 1993 pour l'invention de la PCR. La Taq polymérase thermostable a été utilisée dès :",choices:["1953","1977","1988","2001"],answer:2,diff:2,explication:"La première publication PCR par Mullis date de 1986. La Taq polymérase (extraite de Thermus aquaticus) a été intégrée en 1988, rendant la technique automatisable dans un thermocycleur sans ajout d'enzyme à chaque cycle.",tags:["Histoire PCR","Taq polymérase","Kary Mullis"]},
  {id:"pcrav9",prompt:"L'analyse des amplicons par électrophorèse en gel d'agarose permet de :",choices:["Séquencer directement l'ADN amplifié","Vérifier la taille et la qualité des amplicons grâce à un marqueur de taille","Quantifier précisément le nombre initial de copies","Identifier les mutations ponctuelles"],answer:1,diff:1,explication:"L'électrophorèse sur gel d'agarose révèle les amplicons par leur taille (distance de migration). Un marqueur de taille permet de confirmer que le fragment obtenu a la taille attendue. Une bande unique et nette valide la spécificité de la PCR.",tags:["Électrophorèse","Agarose","Amplicons","Contrôle"]},
  {id:"pcrav10",prompt:"Dans une PCR classique, les amorces (primers) doivent être complémentaires :",choices:["L'une de l'autre (formation de dimères d'amorces)","Chacune d'un des 2 brins, encadrant la séquence à amplifier","De la Taq polymérase","Du marqueur de taille utilisé en gel"],answer:1,diff:1,explication:"Les 2 amorces sont complémentaires, l'une du brin sens (forward), l'autre du brin antisens (reverse), et définissent les bornes de la séquence à amplifier. Elles ne doivent PAS être complémentaires entre elles (risque de dimères d'amorces qui réduiraient la spécificité).",tags:["Amorces","Primers","Complémentarité","PCR"]}
];

const QB_GENOMIQUE = [
  {id:"gen_adv1",prompt:"Qu'est-ce qu'un STR (Short Tandem Repeat) et pourquoi est-il utilisé pour les empreintes génétiques ?",choices:["Une grande délétion chromosomique","Un motif de 2-4 nucléotides répété en tandem, hautement polymorphe entre individus","Un SNP situé dans un gène codant","Une séquence conservée entre espèces"],answer:1,diff:2,explication:"Un STR (microsatellite) est composé d'un motif court répété en tandem dont le nombre de répétitions varie fortement entre individus. ~15 loci STR non liés sont analysés simultanément par PCR multiplex, permettant une identification quasi unique de chaque individu.",tags:["STR","Empreintes génétiques","Microsatellites","PCR multiplex"]},
  {id:"gen_adv2",prompt:"La technique FISH (Fluorescence In Situ Hybridization) est utilisée en oncologie pour :",choices:["Amplifier des gènes par PCR dans les tissus","Détecter des anomalies chromosomiques (amplification, délétion, translocation) sur coupes tissulaires","Séquencer le génome tumoral entier","Doser les protéines tumorales par immunofluorescence"],answer:1,diff:2,explication:"FISH utilise des sondes fluorescentes complémentaires de séquences chromosomiques cibles. Sur des coupes tissulaires (sans culture cellulaire), elle détecte : amplification HER2 (cancer du sein), délétions chromosomiques (LLC), translocations (lymphome de Burkitt t(8;14)).",tags:["FISH","Oncologie","Anomalies chromosomiques","Sondes fluorescentes"]},
  {id:"gen_adv3",prompt:"Comment la technique FISH détecte-t-elle l'amplification du gène HER2 dans le cancer du sein ?",choices:["Par la présence d'une seule sonde HER2","En comparant le nombre de signaux HER2 vs signaux centromériques CEN17 : ratio HER2/CEN17 > 2 = amplification","Par la couleur de la sonde (rouge = amplifié, vert = normal)","Par la taille des cellules observées"],answer:1,diff:3,explication:"Deux sondes sont co-hybridées : sonde HER2 (gène, un fluorochrome) + sonde CEN17 (centromère chr. 17, autre fluorochrome). Normalement : 2 signaux HER2 / 2 signaux CEN17. Amplification = ratio > 2,2 signaux HER2 par signal CEN17 → indication pour le trastuzumab (Herceptin).",tags:["FISH","HER2","Cancer du sein","CEN17"]},
  {id:"gen_adv4",prompt:"Les puces à ADN (DNA microarrays) reposent sur le principe de :",choices:["L'amplification par PCR de milliers de gènes en parallèle","L'hybridation de cibles marquées (ARNm retrotranscrits) sur des sondes immobilisées sur support solide","Le séquençage direct de fragments chromosomiques","La traduction in vitro des ARNm en protéines"],answer:1,diff:2,explication:"Les puces ADN immobilisent des sondes sur une surface. Les cibles (ADNc issus d'ARNm marqués par fluorochromes) s'y hybrident. Le signal fluorescent révèle quels gènes sont exprimés et en quelle quantité dans le tissu analysé (transcriptome).",tags:["Puces ADN","Transcriptome","Hybridation","Fluorochromes"]},
  {id:"gen_adv5",prompt:"Le séquençage de Sanger utilise des ddNTP (didésoxyribonucléotides) car :",choices:["Ils sont moins chers que les dNTP classiques","Leur absence de groupement 3'OH provoque l'arrêt de la synthèse du brin à chaque incorporation (terminateurs de chaîne)","Ils permettent une amplification plus rapide","Ils sont naturellement fluorescents"],answer:1,diff:2,explication:"Les ddNTP n'ont pas de groupement 3'OH → la polymérisation s'arrête à chaque incorporation. On obtient des fragments de toutes les tailles, chacun terminé par une base connue. La séparation par taille (électrophorèse capillaire) permet de reconstituer la séquence.",tags:["Sanger","ddNTP","Séquençage","Terminateurs de chaîne"]},
  {id:"gen_adv6",prompt:"La principale avancée du NGS (Next Generation Sequencing) par rapport à Sanger est :",choices:["Des séquences plus longues et sans erreurs","Un débit massivement parallèle : jusqu'à 100 millions de fragments séquencés simultanément","La possibilité de séquencer des ARN directement","Un coût de 3 milliards de dollars pour un génome"],answer:1,diff:1,explication:"NGS (Illumina, 454, Ion Torrent…) multiplie le débit par >1 million par rapport à Sanger : 100 millions de fragments en parallèle, 1000 milliards de pb par run. Le coût est passé de 3 milliards $ (projet Génome Humain) à moins de 1000 $ pour un génome humain complet.",tags:["NGS","Illumina","Débit","Génomique"]},
  {id:"gen_adv7",prompt:"La technologie de séquençage par nanopores (MiniON) fonctionne par :",choices:["Détection de terminateurs fluorescents réversibles","Mesure du courant ionique perturbé par chaque base traversant un pore protéique (α-hémolysine)","Pyroséquençage (détection de pyrophosphate)","Potentiométrie avec libération de protons H+"],answer:1,diff:3,explication:"Les nanopores (Oxford Nanopore MiniON) utilisent des canaux protéiques (alpha-hémolysine) dans une membrane artificielle. Chaque base traversant le pore modifie le courant ionique d'une façon caractéristique. Avantage : appareil de la taille d'une clé USB, séquençage en temps réel.",tags:["Nanopores","MiniON","Séquençage","Courant ionique"]},
  {id:"gen_adv8",prompt:"Un SNP (Single Nucleotide Polymorphism) est :",choices:["Un grand réarrangement chromosomique","La variation d'un seul nucléotide dans le génome entre individus","Un STR à motif de 1 nucléotide","Une mutation pathologique toujours associée à une maladie"],answer:1,diff:2,explication:"Un SNP est la variation d'une seule paire de base dans une séquence génomique entre individus (il en existe ~50 millions dans le génome humain). La plupart sont silencieux. Ils servent de marqueurs pour la cartographie de loci morbides, la prédisposition aux cancers et la pharmacogénomique.",tags:["SNP","Polymorphisme","Génomique","Puces ADN"]},
  {id:"gen_adv9",prompt:"Dans le diagnostic de la LLC, la FISH permet de détecter la délétion :",choices:["Translocation t(9;22) Philadelphia","Délétion 17p (gène TP53) ou délétion 11q (gène ATM) — facteurs pronostiques majeurs","Amplification HER2","Insertion du VIH"],answer:1,diff:3,explication:"Dans la LLC, FISH détecte les anomalies chromosomiques pronostiques : délétion 17p13 (gène TP53, mauvais pronostic, résistance aux agents alkylants) et délétion 11q22 (gène ATM, pronostic intermédiaire). Ces résultats guident le choix thérapeutique.",tags:["LLC","FISH","17p","TP53","Pronostic"]},
  {id:"gen_adv10",prompt:"La technique SKY (Spectral Karyotype) permet :",choices:["De séquencer le génome entier en une nuit","De visualiser tous les chromosomes d'une métaphase avec une couleur différente par chromosome grâce à des mélanges de fluorochromes","De mesurer l'expression de tous les gènes simultanément","De détecter les SNP sur puces ADN"],answer:1,diff:3,explication:"SKY utilise des mélanges de 5 fluorochromes en proportions différentes pour chaque chromosome (24 'couleurs' uniques). Un logiciel + interféromètre identifie automatiquement chaque chromosome. Très utile pour détecter les translocations complexes en cytogénétique tumorale.",tags:["SKY","Caryotype spectral","Fluorochromes","Translocations"]}
];


const QB_SAA = [
  {id:"saa1",prompt:"Quel est le principe de la Spectrophotométrie d'Absorption Atomique (SAA) électrothermique ?",choices:["Émission d'un rayonnement par des atomes excités dans une flamme","Absorption d'un rayonnement UV/visible par des atomes libres produits dans un four en graphite (loi de Beer-Lambert)","Diffraction de rayons X par la structure cristalline de l'analyte","Réfraction de la lumière visible par les ions en solution"],answer:1,diff:1,explication:"En SAA électrothermique (four en graphite), l'analyte est atomisé et les atomes libres absorbent un rayonnement à une longueur d'onde caractéristique de l'élément. L'absorbance est proportionnelle à la concentration (Beer-Lambert).",tags:["SAA","Four graphite","Beer-Lambert","Absorption atomique"]},
  {id:"saa2",prompt:"À quoi sert la lampe deutérium (D2) dans un spectrophotomètre SAA ?",choices:["Elle chauffe le four en graphite","Elle corrige l'absorption non spécifique du fond spectral (correction de fond)","Elle fournit la lumière visible pour la détection","Elle étalonne automatiquement l'appareil"],answer:1,diff:2,explication:"La lampe deutérium émet un rayonnement continu. En comparant l'absorption à la lampe à cathode creuse (raie caractéristique) et à la lampe D2 (fond continu), on soustrait l'absorption non spécifique de la matrice (correction de fond).",tags:["SAA","Lampe deutérium","Correction de fond","Matrice"]},
  {id:"saa3",prompt:"Quelles sont les 4 grandes étapes du programme de four en SAA électrothermique ?",choices:["Injection → Rinçage → Mesure → Purge","Séchage → Décomposition/calcination → Atomisation → Nettoyage","Dissolution → Filtration → Dilution → Mesure","Étalonnage → Validation → Mesure → Archivage"],answer:1,diff:1,explication:"Programme four : 1) Séchage (évaporation solvant) ; 2) Décomposition/calcination (destruction matrice organique) ; 3) Atomisation (vaporisation et atomisation de l'analyte à haute T°) ; 4) Nettoyage (élimination résidus) ; suivi du refroidissement.",tags:["SAA","Four graphite","Programme thermique","Atomisation"]},
  {id:"saa4",prompt:"Le test de Dixon est utilisé en métrologie pour :",choices:["Vérifier la linéarité de la gamme d'étalonnage","Détecter les valeurs aberrantes dans une série de résultats","Calculer l'intervalle de confiance","Comparer deux méthodes analytiques"],answer:1,diff:2,explication:"Le test de Dixon teste si la valeur la plus extrême d'une série est significativement écartée de la distribution normale. Q = |x_suspect - x_voisin| / (x_max - x_min). Si Q calculé > Q tabular, la valeur est aberrante et peut être éliminée.",tags:["Dixon","Valeurs aberrantes","Statistiques","Métrologie"]},
  {id:"saa5",prompt:"Pour valider la linéarité d'une gamme d'étalonnage, le coefficient de corrélation r doit être :",choices:["r > 0,70","r > 0,90","r > 0,98","r = 1,00 exactement"],answer:2,diff:1,explication:"En analyse chimique et validation de méthode, r > 0,98 (voire r² > 0,995) est le critère minimal de linéarité acceptable. En dessous, la relation n'est pas suffisamment linéaire pour une quantification fiable.",tags:["Linéarité","Corrélation","Validation","Gamme étalon"]},
  {id:"saa6",prompt:"L'intervalle de confiance bilatéral d'une moyenne se calcule par :",choices:["x̄ ± Z × σ (population connue)","x̄ ± t(α, n-1) × s/√n","x̄ ± 2s","x̄ ± F × s²"],answer:1,diff:2,explication:"Pour une population de variance inconnue, l'IC bilatéral utilise la loi de Student : x̄ ± t(α, n-1) × s/√n. Où t(α, n-1) est la valeur critique pour le risque α et n-1 degrés de liberté.",tags:["Intervalle de confiance","Student","Statistiques","Métrologie"]},
  {id:"saa7",prompt:"Pourquoi mesure-t-on l'inconnue 12 fois en SAA dans ce protocole de validation ?",choices:["Pour réduire le temps d'analyse","Pour disposer d'un nombre suffisant de résultats permettant les tests statistiques (Dixon, IC) et valider la répétabilité","Pour compenser la dérive de l'instrument","Pour avoir une meilleure précision sur un seul résultat"],answer:1,diff:1,explication:"n=12 répétitions permettent : le test de Dixon (détection aberrants), le calcul d'un écart-type représentatif de la répétabilité, un intervalle de confiance robuste, et la validation statistique de la méthode selon les critères de validation métrologique.",tags:["Répétabilité","Validation","SAA","Statistiques"]},
  {id:"saa8",prompt:"En SAA, quelle est la différence entre SAA flamme et SAA four (électrothermique) ?",choices:["Aucune différence de sensibilité","SAA four est 100-1000× plus sensible car l'atomisation est plus efficace et le temps de résidence des atomes est plus long","SAA flamme est plus sensible pour les métaux lourds","SAA flamme est réservée aux non-métaux"],answer:1,diff:2,explication:"SAA four (ETAAS) est 100 à 1000 fois plus sensible que SAA flamme. L'échantillon est atomisé dans un tube fermé (four en graphite) avec un temps de résidence des atomes bien supérieur à celui dans une flamme ouverte. Idéale pour les traces (µg/L) comme le plomb dans l'eau.",tags:["SAA","Flamme","Four graphite","Sensibilité"]}
];

const QB_HPLC = [
  {id:"hplc1",prompt:"Qu'est-ce que le facteur de capacité k' en HPLC et quelle est sa plage optimale ?",choices:["k' = tR/t0, optimal entre 0 et 1","k' = (tR - t0)/t0, optimal entre 2 et 10","k' = RS × w, optimal entre 1 et 5","k' = t0/tR, optimal entre 0,5 et 2"],answer:1,diff:1,explication:"k' = (tR - t0) / t0 mesure la rétention relative. Pour 2 < k' < 10 : bonne séparation sans temps d'analyse excessif. Si k' < 2 : mauvaise résolution avec le pic de solvant. Si k' > 10 : pics trop larges et analyse trop longue.",tags:["HPLC","Facteur de capacité","k'","Rétention"]},
  {id:"hplc2",prompt:"En HPLC phase inverse (colonne C18), que se passe-t-il si on augmente le pourcentage de solvant organique (ex: ACN) dans la phase mobile ?",choices:["La rétention des composés apolaires augmente","La rétention des composés apolaires diminue (élution plus rapide)","La rétention des composés polaires augmente","Aucun effet sur la rétention"],answer:1,diff:2,explication:"En phase inverse (colonne C18 apolaire), augmenter ACN dans la phase mobile rend celle-ci plus apolaire → les composés apolaires sont moins retenus (compétition entre phase mobile et stationnaire). Pour les composés polaires, c'est l'inverse : plus de rétention avec plus d'eau.",tags:["HPLC","Phase inverse","C18","ACN","Élution"]},
  {id:"hplc3",prompt:"La chromatographie HILIC (Hydrophilic Interaction Chromatography) est adaptée pour :",choices:["Séparer des composés très apolaires (hydrocarbures)","Séparer des composés polaires et ioniques","Séparer des protéines par taille","Analyser des mélanges de solvants organiques"],answer:1,diff:2,explication:"HILIC retient préférentiellement les composés polaires/ioniques (acides aminés, sucres, médicaments ionisables comme le Baclofène). La phase stationnaire est polaire et retient une couche d'eau enrichie. Contrairement à la phase inverse : plus on augmente l'eau, plus on élue les composés polaires.",tags:["HPLC","HILIC","Composés polaires","Phase stationnaire"]},
  {id:"hplc4",prompt:"Pourquoi acidifie-t-on la phase mobile (pH 2,1) pour le dosage du Baclofène (pKa1=3,5 ; pKa2=9,2) ?",choices:["Pour améliorer la solubilité de l'ACN","Pour maintenir le Baclofène sous forme protonée (NH3+, COOH) → forme définie et reproductible","Pour éviter la corrosion de la colonne","Pour augmenter la fluorescence du Baclofène"],answer:1,diff:2,explication:"À pH 2,1 < pKa1=3,5 : le groupement COOH et NH2 du Baclofène sont tous deux protonés. Forme ionique définie → pics chromatographiques symétriques et reproductibles. Si le pH variait autour d'un pKa, la forme chimique serait instable → pics asymétriques/dédoublés.",tags:["HPLC","pH","pKa","Baclofène","Ionisation"]},
  {id:"hplc5",prompt:"La résolution RS entre 2 pics chromatographiques se calcule par :",choices:["RS = tR2/tR1","RS = 2(tR2 - tR1)/(w1 + w2)","RS = N × (k'/(1+k'))²","RS = (tR - t0)/σ"],answer:1,diff:2,explication:"RS = 2 × (tR2 - tR1) / (w1 + w2) où tR = temps de rétention et w = largeur du pic à la base. RS ≥ 1,5 = bonne séparation (baseline resolution). RS < 1 = pics co-élués.",tags:["HPLC","Résolution","Séparation","Rs"]},
  {id:"hplc6",prompt:"Pourquoi la colonne HPLC à particules de 2,6 µm travaille-t-elle à pression plus élevée que celle à 5 µm ?",choices:["Car elle est plus longue","Car la résistance hydraulique augmente quand la taille des particules diminue (loi de Darcy)","Car elle nécessite un débit plus lent","Car elle est utilisée à température plus basse"],answer:1,diff:2,explication:"La loi de Darcy dit que ΔP ∝ 1/dp². Des particules plus petites (2,6 µm vs 5 µm) créent plus de résistance hydraulique → pression plus élevée. Avantage : meilleure efficacité (N plus grand) et analyse plus rapide. Ces colonnes nécessitent un système UHPLC.",tags:["HPLC","Pression","Taille particules","Efficacité"]},
  {id:"hplc7",prompt:"En HPLC, la détection UV est choisie pour le Baclofène à 220 nm car :",choices:["Le Baclofène est très coloré (visible)","Le Baclofène ne possède pas de chromophore visible mais absorbe dans l'UV via son cycle aromatique","Le détecteur UV est moins cher que le détecteur fluorimétrique","La loi de Beer-Lambert ne s'applique qu'à 220 nm"],answer:1,diff:1,explication:"Le Baclofène possède un cycle phényle (aromatique) qui absorbe dans l'UV mais pas dans le visible. La détection à 220 nm exploite l'absorption du cycle aromatique. Les solvants (ACN, eau) ont un cut-off UV < 210 nm et n'absorbent pas à 220 nm.",tags:["HPLC","Détection UV","Baclofène","Chromophore"]},
  {id:"hplc8",prompt:"L'étalon de contrôle (CEQ) en HPLC est utilisé pour :",choices:["Préparer la gamme d'étalonnage","Vérifier que la concentration mesurée est dans l'intervalle Cref ± 10 % et valider la série analytique","Nettoyer la colonne chromatographique","Calibrer la pompe"],answer:1,diff:1,explication:"L'étalon de contrôle est une solution de concentration connue (indépendante de la gamme) traitée comme une inconnue. Si sa concentration mesurée (CEQ) est dans Cref ± 10 %, la série est validée. Sinon, les résultats sont rejetés.",tags:["HPLC","Étalon de contrôle","Validation","CEQ"]}
];

const QB_IRTF = [
  {id:"irtf1",prompt:"Quel est le principe de la spectroscopie IRTF-ATR ?",choices:["La molécule émet un rayonnement IR après excitation","L'onde évanescente créée par réflexion totale interne dans un cristal pénètre l'échantillon sur quelques µm et est absorbée par les liaisons moléculaires","La lumière visible est diffractée par la structure de l'échantillon","L'absorbance de l'échantillon est mesurée en transmission directe"],answer:1,diff:2,explication:"En ATR, la lumière IR est guidée par réflexions totales dans un cristal (diamant). À chaque réflexion, une onde évanescente pénètre l'échantillon sur 1-5 µm. Les liaisons vibrent à des fréquences spécifiques et absorbent cette onde. Avantage : pas de préparation de l'échantillon.",tags:["IRTF","ATR","Onde évanescente","Réflexion totale"]},
  {id:"irtf2",prompt:"À quel nombre d'onde se trouve la bande analytique de l'acide ascorbique (Vitamine C) utilisée pour le dosage quantitatif ?",choices:["3330 cm⁻¹","1630 cm⁻¹","1148 cm⁻¹","2900 cm⁻¹"],answer:2,diff:2,explication:"La bande analytique de l'acide ascorbique est à ~1148 cm⁻¹ (vibration d'élongation C-O). Les bandes O-H (3330 cm⁻¹) et C=O (1630 cm⁻¹) sont masquées par les bandes très intenses de l'eau solvant.",tags:["IRTF","Acide ascorbique","1148 cm-1","Vitamine C"]},
  {id:"irtf3",prompt:"Pourquoi les bandes d'élongation O-H et C=O de l'acide ascorbique ne sont-elles pas visibles en solution aqueuse ?",choices:["Car l'acide ascorbique ne possède pas ces fonctions","Car l'eau absorbe très fortement à ces régions spectrales (3330 cm⁻¹ et 1630 cm⁻¹) et les masque","Car ces bandes sont toujours en dessous de la limite de détection","Car le cristal diamant absorbe à ces longueurs d'onde"],answer:1,diff:1,explication:"L'eau est un absorbant IR très puissant. Sa bande d'élongation O-H (~3330 cm⁻¹) et de déformation H-O-H (~1630 cm⁻¹) sont saturées et masquent complètement les bandes correspondantes de l'acide ascorbique dans ces régions.",tags:["IRTF","Eau","Solvant","Masquage spectral"]},
  {id:"irtf4",prompt:"La LOD (Limite de Détection) se calcule par :",choices:["LOD = 3 × s(réf.) / a, où s = écart-type du blanc et a = pente de la droite","LOD = 10 × s(réf.) / a","LOD = signal/bruit = 2","LOD = 0,1 × LOQ"],answer:0,diff:2,explication:"LOD = 3 × s(réf.) / a. s(réf.) = écart-type de n mesures sur le blanc (solution sans analyte). a = pente de la droite d'étalonnage. La LOQ = 10 × s(réf.) / a est toujours supérieure à la LOD.",tags:["LOD","Limite de détection","Blanc","Pente"]},
  {id:"irtf5",prompt:"Les nombres d'onde en spectroscopie IR s'expriment en cm⁻¹. Une grande valeur de nombre d'onde correspond à :",choices:["Une grande longueur d'onde et une faible énergie","Une petite longueur d'onde et une grande énergie de vibration","Une faible fréquence de vibration","Une vibration uniquement de déformation"],answer:1,diff:2,explication:"σ (cm⁻¹) = 1/λ. Plus σ est grand, plus λ est petite et plus l'énergie du photon est grande (E = hcσ). Les élongations (stretching) des liaisons X-H (O-H, N-H, C-H) vers 2500-4000 cm⁻¹ sont très énergétiques. Les déformations angulaires se trouvent à des nombres d'onde plus faibles.",tags:["IR","Nombres d'onde","Énergie","Vibrations"]},
  {id:"irtf6",prompt:"L'appareil IRTF BRUKER ALPHA II utilise un cristal de quelle nature en mode ATR ?",choices:["Saphir","Quartz","Diamant","ZnSe"],answer:2,diff:2,explication:"Le cristal diamant est la référence en ATR car il est transparent sur toute la gamme IR (600-4000 cm⁻¹), très dur (résistant aux solvants et à l'abrasion), et permet l'analyse directe d'échantillons liquides, solides ou pâteux sans préparation.",tags:["IRTF","ATR","Cristal diamant","BRUKER"]},
  {id:"irtf7",prompt:"Quelles sont les fonctions chimiques présentes dans l'acide ascorbique (Vitamine C) visibles en IR ?",choices:["Aldéhyde et amine","Alcool (OH), lactone (C=O cyclique), éther (C-O-C), énol (C=C-OH)","Amide et nitrile","Acide sulfonique et thiol"],answer:1,diff:2,explication:"La structure de l'acide ascorbique (C6H8O6) comporte : fonctions alcool (OH), une lactone (ester cyclique intramolécule), des éthers (C-O-C) et un motif énol (C=C-OH). Les bandes C-O vers 1048, 1116 et 1148 cm⁻¹ sont analytiquement exploitables en solution aqueuse.",tags:["Acide ascorbique","Fonctions chimiques","IRTF","Structure"]},
  {id:"irtf8",prompt:"La résolution spectrale d'un spectromètre IRTF représente :",choices:["La sensibilité minimale de détection","La plus petite différence de nombres d'onde distinguable entre 2 bandes voisines","La durée d'acquisition d'un spectre","Le nombre de scans cumulés"],answer:1,diff:2,explication:"La résolution spectrale (exprimée en cm⁻¹) est la plus petite différence de nombres d'onde entre deux bandes que l'instrument peut distinguer. Une résolution de 2 cm⁻¹ (comme dans ce TP) est standard pour l'analyse quantitative. Plus la valeur est petite, meilleure est la résolution.",tags:["IRTF","Résolution spectrale","cm-1","Spectre"]}
];

const QB_AJOUTS_DOSES = [
  {id:"aj1",prompt:"Quel est l'avantage principal de la méthode des ajouts dosés par rapport à la droite d'étalonnage classique ?",choices:["Elle est plus rapide à mettre en œuvre","Elle corrige les effets matrice car les étalons sont dans la même matrice que l'inconnue","Elle ne nécessite pas d'appareil de mesure","Elle donne toujours une meilleure linéarité"],answer:1,diff:1,explication:"Les effets matrice (composants de l'échantillon qui modifient la réponse analytique) affectent identiquement l'analyte et les ajouts dans la méthode des ajouts dosés. La droite d'étalonnage classique est préparée en solvant pur → les effets matrice faussent les résultats.",tags:["Ajouts dosés","Effets matrice","Méthode analytique","Fluorimétrie"]},
  {id:"aj2",prompt:"En spectrofluorimétrie, comment se distingue la technique de la spectrophotométrie UV-Vis ?",choices:["La fluorimétrie mesure l'absorbance en transmission directe","La fluorimétrie mesure l'émission de lumière perpendiculairement au faisceau incident (plus sensible)","La fluorimétrie ne peut pas être utilisée pour des solutions","La fluorimétrie utilise des rayons X"],answer:1,diff:1,explication:"La fluorimétrie : excitation → émission de fluorescence mesurée à 90° du faisceau incident (bruit de fond très bas). Elle est 100-1000× plus sensible que l'absorbance UV-Vis pour les molécules fluorescentes. Inconvénient : ne fonctionne que pour les molécules fluorescentes.",tags:["Fluorimétrie","Spectrophotométrie","Émission","Sensibilité"]},
  {id:"aj3",prompt:"La quinine (λem = 450 nm) est dosée dans le Schweppes tonic. Quelle est la limite légale de concentration dans les boissons ?",choices:["10 mg/L","100 mg/L","500 mg/L","1 g/L"],answer:1,diff:1,explication:"La limite légale européenne pour la quinine dans les boissons est de 100 mg/L. Au-delà, la quinine peut provoquer des cinchonismes (troubles auditifs, vertiges). Sa présence est signalée sur l'étiquette des tonics.",tags:["Quinine","Réglementation","Tonic","100 mg/L"]},
  {id:"aj4",prompt:"Comment détermine-t-on graphiquement la concentration inconnue par la méthode des ajouts dosés ?",choices:["À partir de l'ordonnée à l'origine de la droite","Par extrapolation de la droite jusqu'à son intersection avec l'axe des abscisses (I=0), puis calcul Cx à partir de la pente","En divisant l'intensité de l'inconnue par la pente","En lisant directement la concentration sur l'axe des x à l'ordonnée de l'inconnue"],answer:1,diff:2,explication:"On trace I = f(Vs). La droite croise l'axe des abscisses (I=0) en Vs0 négatif. Cx = -(b/m) × (Cs / Vx) × Vtotal, obtenu par extrapolation. L'intersection représente le volume d'étalon 'équivalent' à la concentration inconnue.",tags:["Ajouts dosés","Extrapolation","Graphique","Fluorimétrie"]},
  {id:"aj5",prompt:"Pourquoi utilise-t-on de l'H2SO4 à 1 mol/L comme solvant pour le dosage fluorimétrique de la quinine ?",choices:["Pour précipiter les impuretés","Car le milieu acide protone la quinine sous sa forme diacide qui émet la fluorescence maximale","Pour éviter la dégradation de la cuve","Pour diminuer la viscosité de la solution"],answer:1,diff:2,explication:"La quinine diacide (quinium²⁺) en milieu H2SO4 (pH très acide, 0 M) est la forme présentant la fluorescence maximale et la plus stable. En milieu neutre ou basique, la quinine change de forme et son signal de fluorescence est réduit.",tags:["Quinine","H2SO4","Fluorescence","Protonation"]},
  {id:"aj6",prompt:"En méthode des ajouts dosés, pourquoi le volume de matrice (Schweppes) doit-il être identique dans toutes les solutions ?",choices:["Pour simplifier les calculs","Pour que l'effet matrice soit constant et identique dans toutes les solutions de la série","Pour éviter la saturation du détecteur","Car le volume impose la concentration de la gamme"],answer:1,diff:2,explication:"Si le volume de matrice varie, l'effet matrice change d'un point à l'autre → la droite n'est plus linéaire et le résultat final est faux. Tous les points de la série doivent avoir le même volume de matrice (ex: 4,0 mL fixe) pour que l'effet matrice soit constant et compensé.",tags:["Ajouts dosés","Effet matrice","Volume constant","Linéarité"]},
  {id:"aj7",prompt:"Les cuves utilisées en spectrofluorimétrie sont à 4 faces optiques car :",choices:["C'est une norme de fabrication esthétique","La fluorescence est mesurée perpendiculairement au faisceau d'excitation, nécessitant des faces de lecture sur 2 côtés","Les 4 faces permettent de contrôler la diffusion de la lumière","Pour résister à l'acide sulfurique"],answer:1,diff:2,explication:"En fluorimétrie, l'excitation entre par une face et la fluorescence émise sort par la face perpendiculaire. Donc 4 faces optiques transparentes (quartz, transparent UV) sont nécessaires. En absorbance UV-Vis, 2 faces suffisent.",tags:["Fluorimétrie","Cuve quartz","4 faces","Géométrie"]},
  {id:"aj8",prompt:"Quel est le domaine de linéarité de la fluorescence de la quinine (mol/L) utilisé dans ce protocole ?",choices:["0 à 1 µmol/L","0 à 6×10⁻⁶ mol/L (6 µmol/L)","0 à 1 mmol/L","0 à 100 mg/L directement"],answer:1,diff:2,explication:"Le domaine de linéarité de la fluorescence de la quinine dans H2SO4 est 0 à 6,0×10⁻⁶ mol/L. Au-delà, le signal sature (auto-absorption). Les solutions doivent être préparées dans cette gamme pour une quantification valide.",tags:["Quinine","Linéarité","Fluorescence","Domaine analytique"]}
];


const QB_CPG = [
  {id:"ba_cpg1",prompt:"La qualification opérationnelle d'un appareil analytique (CPG, HPLC, Spectro) est définie comme :",choices:["La validation de la méthode analytique","La preuve documentée que l'appareil fonctionne de façon répétée dans les limites définies par le constructeur","Le calibrage mensuel de l'appareil","L'achat du matériel certifié"],answer:1,diff:1,explication:"Qualification opérationnelle (OQ) = preuve documentée (en dynamique) que l'instrument atteint les spécifications définies par le constructeur dans l'environnement de l'utilisateur. À distinguer de la validation de méthode (VM) qui concerne la méthode analytique elle-même.",tags:["CPG","Qualification opérationnelle","Qualité analytique"]},
  {id:"ba_cpg2",prompt:"Pour la CPG Varian GC450 (détecteur TCD), le critère d'acceptation pour la justesse de la température du four est :",choices:["< 1°C d'écart","< 5% de la valeur de consigne","Écart moyen ≤ ± 3 % de la valeur de consigne","Exactement 0°C d'écart"],answer:2,diff:2,explication:"Critère justesse T° four CPG : la moyenne des températures mesurées (à 60°C et 140°C) ne doit pas dépasser ± 3 % de la valeur de consigne. Critère stabilité : écart max/min < 1°C sur 10 minutes. Ces deux critères sont indépendants.",tags:["CPG","Température four","Critère","Qualification"]},
  {id:"ba_cpg3",prompt:"Lors de la qualification de la CPG, le critère de répétabilité pour les temps de rétention (6 injections) est :",choices:["CV% < 5,0 %","CV% < 0,5 %","CV% < 2,0 %","CV% < 10 %"],answer:1,diff:2,explication:"Critères répétabilité CPG (6 injections de la solution test alcanes) : CV% temps de rétention < 0,5 % ET CV% surfaces des pics < 2,0 %. La solution test contient tétradécane (C14), pentadécane (C15) et hexadécane (C16) dans l'iso-octane.",tags:["CPG","Répétabilité","CV%","Temps de rétention"]},
  {id:"ba_cpg4",prompt:"Le bruit de fond maximal acceptable pour le détecteur TCD de la CPG Varian est :",choices:["< 5000 µV","< 500 µV","< 50 µV","< 5 µV"],answer:1,diff:2,explication:"Critères TCD (Varian GC450) : bruit de fond < 500 µV. Dérive de ligne de base < 1000 µV / 10 min (soit < 100 µV/min). Ces paramètres garantissent une sensibilité suffisante pour la détection des alcanes de la solution test.",tags:["CPG","TCD","Bruit de fond","Ligne de base"]},
  {id:"ba_cpg5",prompt:"La solution test utilisée pour l'étude de répétabilité de la CPG est composée de :",choices:["Glucose + saccharose + fructose dans l'eau","Caféine + paracétamol + aspirine dans le méthanol","Tétradécane + pentadécane + hexadécane dans l'iso-octane","Éthanol + méthanol + propanol dans l'eau"],answer:2,diff:1,explication:"Solution test CPG (qualification Varian GC450, TCD) : 2 gouttes de chaque alcane (C14 tétradécane, C15 pentadécane, C16 hexadécane) dans 10 mL d'iso-octane. Injection : 1 µL. Toxicité : toxiques par aspiration → port de gants obligatoire.",tags:["CPG","Solution test","Alcanes","TCD","Qualification"]},
  {id:"ba_cpg6",prompt:"La qualification opérationnelle d'une CPG est réalisée sous la responsabilité de :",choices:["Le fabricant de l'appareil","Le laboratoire utilisateur (opérateur/responsable qualité)","La DGCCRF","L'ANSM"],answer:1,diff:1,explication:"La qualification opérationnelle est sous la responsabilité de l'utilisateur (laboratoire). Le fabricant fournit les spécifications (IQ = qualification d'installation). L'utilisateur réalise l'OQ (fonctionnement) et la PQ (performance en conditions réelles). La traçabilité est conservée dans le dossier qualité.",tags:["CPG","Responsabilité","Qualification","Qualité analytique"]},
  {id:"ba_cpg7",prompt:"Pour les débits de gaz du TCD (référence et make-up), le critère de stabilité est :",choices:["Débit parfaitement constant (0% de variation)","Variation ≤ ± 10 % par rapport à la valeur indiquée par l'EFC","Variation < 1 mL/min","CV% < 2 %"],answer:1,diff:2,explication:"Critère débits TCD (Varian GC450) : écart max/min ≤ ± 10 % de la valeur indiquée par l'EFC (Electronic Flow Controller) sur 10 minutes. Un débit instable perturbe le signal de détection et rend les mesures de surfaces non comparables.",tags:["CPG","Débit gaz","TCD","EFC","Critère"]},
  {id:"ba_cpg8",prompt:"Quelle est la différence entre qualification d'un instrument et validation d'une méthode analytique ?",choices:["Ce sont deux termes synonymes","La qualification porte sur l'instrument (fonctionne-t-il ?) ; la validation porte sur la méthode (est-elle exacte et fiable pour cet usage ?)","La validation s'applique uniquement à la HPLC","La qualification est facultative, la validation est obligatoire"],answer:1,diff:2,explication:"Qualification = vérifier que l'instrument fonctionne conformément aux specs du constructeur (OQ) et dans les conditions d'utilisation (PQ). Validation de méthode = vérifier que la méthode analytique est exacte, précise, linéaire, spécifique, robuste pour l'analyte et la matrice concernés.",tags:["Qualification","Validation","Méthode analytique","CPG","Qualité"]},
];

const QB_SPECTRO_UV = [
  {id:"ba_su1",prompt:"Lors de la qualification d'un spectrophotomètre UV-Vis, quel étalon de référence est utilisé pour vérifier l'exactitude en longueur d'onde ?",choices:["Un verre coloré quelconque","Le filtre à l'oxyde d'holmium (Holmium AC-500) avec bandes certifiées","Une solution de KCl","De l'eau ultra-pure"],answer:1,diff:1,explication:"Le filtre à l'oxyde d'holmium (Holmium AC-500) présente des bandes d'absorption à des λ certifiées (ex : 278,5 nm ; 360,5 nm ; 418,0 nm…). Critère d'acceptation : écart ≤ ± 1,5 nm entre la valeur mesurée et la valeur certifiée.",tags:["Spectrophotomètre","Exactitude longueur d'onde","Holmium","Qualification"]},
  {id:"ba_su2",prompt:"Pour mesurer la lumière parasite d'un spectrophotomètre UV à 198 nm selon la Pharmacopée Européenne, on utilise :",choices:["NaNO₂ 50 g/L","NaI 10 g/L","KCl 12 g/L (critère T ≤ 1 %, i.e. A ≥ 2)","H₂SO₄ dilué"],answer:2,diff:2,explication:"Lumière parasite selon Ph.Eur. : KCl 12 g/L à 198 nm (critère T ≤ 0,001 %). NaI 10 g/L à 220 nm (T ≤ 10⁻⁴ %). NaNO₂ 50 g/L à 340 et 370 nm. Le critère général Ph.Eur. est T ≤ 1 % (A ≥ 2) ; les valeurs précises sont plus strictes pour chaque solution.",tags:["Spectrophotomètre","Lumière parasite","KCl","Pharmacopée Européenne"]},
  {id:"ba_su3",prompt:"La dérivée seconde d'absorbance d²A/dλ² est proportionnelle à :",choices:["La longueur d'onde λ uniquement","La concentration C de l'analyte (comme A en ordre 0 — loi de Beer-Lambert dérivée)","L'épaisseur de la cuve uniquement","1/C"],answer:1,diff:2,explication:"d²A/dλ² = (d²ε/dλ²) × b × C. Seul ε (coefficient d'extinction molaire) dépend de λ. L'épaisseur b et la concentration C sont constants → d²A/dλ² est bien proportionnelle à C. Utilité : meilleure résolution, suppression des interférences de matrice à variation lente avec λ.",tags:["Spectrophotomètre","Dérivée seconde","Beer-Lambert","Concentration"]},
  {id:"ba_su4",prompt:"La vanilline (C₈H₈O₃), analyte de l'épreuve RA7, est dosée dans le sucre vanillé. La teneur attendue dans une vraie gousse de vanille est :",choices:["5 à 25 mg/g de gousse","0,2 à 1,0 mg/g de gousse","100 mg/g de gousse","< 0,01 mg/g de gousse"],answer:1,diff:1,explication:"Une gousse de vanille contient 5 à 25 mg de vanilline par gramme. Pour le sucre vanillé (étiquette '4 % de gousse de vanille'), la teneur calculée attendue est de 0,2 à 1,0 mg/g. La solution mère M0 est préparée en dissolvant ~10 mg de vanilline dans 100 mL de soude 0,1 mol/L.",tags:["Vanilline","RA7","Dosage UV","Teneur","Sucre vanillé"]},
  {id:"ba_su5",prompt:"Lors du dosage de la vanilline (droite d'étalonnage), le critère d'acceptabilité du contrôle qualité (CQ) est :",choices:["± 1 %","± 5 %","± 10 % de la concentration de référence Cref","± 20 %"],answer:2,diff:1,explication:"Critère CQ dosage vanilline : la concentration mesurée (CEQ) doit se trouver dans l'intervalle Cref ± 10 %. Si le CQ est hors tolérances, la série de dosage est invalide et doit être répétée. C'est le même critère que pour la plupart des dosages HPLC.",tags:["Contrôle qualité","CQ","Critère","Dosage","Vanilline"]},
  {id:"ba_su6",prompt:"Le rapport A/B de la dérivée seconde du spectre du toluène (qualification spectro) doit être :",choices:["< 0,2","= 1,0","≥ 0,2 (extremum à 265 nm / extremum à 261 nm)","= 2,0"],answer:2,diff:3,explication:"Spectrophotométrie dérivée (qualification CAMSPEC) : ratio A/B = (extremum d2A/dλ² à 265 nm) / (extremum à 261 nm) doit être > 0,2. Ce ratio vérifie la résolution spectrale réelle de l'appareil en conditions dynamiques.",tags:["Dérivée seconde","Toluène","Résolution","Spectrophotomètre","CAMSPEC"]},
  {id:"ba_su7",prompt:"Le critère d'acceptation pour l'exactitude en absorbance (filtres gris neutres, qualification spectro UV-Vis) est :",choices:["± 0,1 unité d'absorbance","± 5 % des valeurs certifiées","≤ ± 2 % des valeurs du certificat d'étalonnage","Exactement 0 d'écart"],answer:2,diff:2,explication:"Exactitude en absorbance (filtres gris neutres AC-10, AC-30, AC-50, AC-100 entre 400 et 680 nm) : valeur mesurée ≤ ± 2 % des valeurs du certificat d'étalonnage. Les filtres couvrent toute la plage d'absorbance utilisée en routine.",tags:["Spectrophotomètre","Exactitude absorbance","Filtres gris","Qualification","Critère"]},
  {id:"ba_su8",prompt:"La résolution spectrale d'un spectrophotomètre UV-Vis est vérifiée par :",choices:["La solution de KCl","Le filtre holmium","Le spectre du toluène 0,02% dans l'hexane (ratio Amax/Amin entre 260 et 270 nm)","Une solution de vanilline"],answer:2,diff:2,explication:"Résolution (bande passante) : spectre du toluène 0,02 % (v/v) dans l'hexane entre 260 et 270 nm. On mesure le ratio Amax/Amin pour différentes largeurs de bande (SBW) : SBW 0,1-0,2 nm → ratio 1,7-1,8 ; SBW 0,5-2 nm → ratio 1,3-1,4. Un ratio trop faible indique une bande passante trop large.",tags:["Résolution","Bande passante","Toluène","Spectrophotomètre","SBW"]},
];

const QB_HPLC_SHIMADZU = [
  {id:"ba_hs1",prompt:"Lors de la qualification de la pompe HPLC Shimadzu Prominence, le critère de stabilité (fluctuation de pression) est :",choices:["≤ 0,05 MPa","≤ 0,20 MPa","≤ 1,00 MPa","≤ 5 % de la pression nominale"],answer:1,diff:2,explication:"Qualification pompe HPLC Shimadzu : fluctuation de pression ≤ 0,20 MPa. Exactitude du débit : déviation ≤ ± 5 % par rapport au débit nominal. La mesure du débit se fait en recueillant le solvant dans une fiole graduée de 5 mL avec un chronomètre.",tags:["HPLC","Shimadzu","Pompe","Qualification","Pression"]},
  {id:"ba_hs2",prompt:"Pour qualifier le détecteur UV-Vis SPD-20AV de la chaîne HPLC Shimadzu, la durée de vie maximale des lampes D₂ et W est :",choices:["500 heures","2000 heures","10 000 heures","Illimitée"],answer:1,diff:1,explication:"Durée de vie lampes détecteur UV-Vis Shimadzu : ≤ 2000 heures pour la lampe D₂ (deutérium, UV) ET pour la lampe W (tungstène, visible). Au-delà, les lampes doivent être remplacées. La durée est suivie dans le logiciel LABSolution.",tags:["HPLC","Shimadzu","Lampes D2 W","Détecteur UV","Durée de vie"]},
  {id:"ba_hs3",prompt:"Les critères de répétabilité d'injection pour la qualification HPLC Shimadzu (6 injections, caféine 20 mg/L) sont :",choices:["CV% tR < 2 % et CV% aires < 5 %","CV% tR < 0,5 % et CV% aires < 5,0 %","CV% tR < 0,5 % et CV% aires < 2,0 %","CV% tR < 0,1 % et CV% aires < 1 %"],answer:1,diff:2,explication:"Qualification répétabilité HPLC Shimadzu : CV% temps de rétention (tR) < 0,5 % ET CV% aires < 5,0 % sur 6 injections de caféine à 20 mg/L. À noter : le critère aire est plus large (5%) que pour la CPG (2%) car l'HPLC est plus sensible aux conditions chromatographiques.",tags:["HPLC","Shimadzu","Répétabilité","CV%","Caféine"]},
  {id:"ba_hs4",prompt:"Le critère de linéarité de la réponse du détecteur HPLC Shimadzu (gamme caféine 10-30 mg/L) est :",choices:["R² > 0,90","R² > 0,98 ET déviation ≤ ± 5 % pour chaque concentration","R² = 1,00 exact","R² > 0,95 uniquement"],answer:1,diff:2,explication:"Linéarité détecteur HPLC Shimadzu : R² > 0,98 ET déviation de chaque point par rapport à la droite ≤ ± 5 %. Déviation % = [(sensibilité relative − sensibilité relative standard) / sensibilité relative standard] × 100. Sensibilité relative = aire / concentration.",tags:["HPLC","Shimadzu","Linéarité","R²","Déviation","Caféine"]},
  {id:"ba_hs5",prompt:"La colonne utilisée pour la qualification de la HPLC Shimadzu Prominence est :",choices:["Colonne en phase normale silice","Phenomenex Gemini C18 (150×4,6 mm, 5 µm) — phase inverse","Colonne HILIC aqueuse","Colonne d'exclusion (SEC)"],answer:1,diff:1,explication:"Qualification HPLC Shimadzu : colonne Phenomenex Gemini C18 (150 × 4,6 mm, 5 µm) — phase inverse. Phase mobile : eau UP (voie A) / méthanol (voie B). Solvant de repos : 80/20 eau-MeOH. La caféine est séparée rapidement grâce à ses propriétés hydrophiles modérées.",tags:["HPLC","Shimadzu","Colonne C18","Phase inverse","Phenomenex"]},
  {id:"ba_hs6",prompt:"Pour vérifier l'exactitude du débit de la pompe HPLC Shimadzu, la méthode utilisée est :",choices:["Mesure de la pression en ligne","Collection du solvant dans une fiole graduée de 5 mL et chronométrage (débit réel = volume/temps)","Utilisation d'un débitmètre électronique intégré","Pesée du solvant collecté"],answer:1,diff:2,explication:"Vérification débit pompe Shimadzu : on recueille le solvant en sortie de la colonne dans une fiole graduée de 5 mL. On mesure le temps nécessaire au remplissage avec un chronomètre. Débit réel = 5 mL / temps (mL/min). Critère : déviation ≤ ± 5 % par rapport au débit nominal.",tags:["HPLC","Shimadzu","Débit pompe","Mesure","Exactitude"]},
  {id:"ba_hs7",prompt:"Le bruit de fond acceptable pour le détecteur UV-Vis de la HPLC Shimadzu est :",choices:["≤ 500 µAu","≤ 20 µAu (temps de réponse 2 s)","≤ 1000 µAu","≤ 1 µAu"],answer:1,diff:2,explication:"Bruit de fond détecteur Shimadzu SPD-20AV : ≤ 20 µAu (unités d'absorbance micro, pour un temps de réponse de 2 s). Dérive de ligne de base : ≤ 600 µAu/h (avec fluctuation de température ≤ 2°C). Ces valeurs sont bien inférieures à celles de la CPG (TCD).",tags:["HPLC","Shimadzu","Bruit de fond","Détecteur UV","µAu"]},
  {id:"ba_hs8",prompt:"La solution mère de caféine pour la qualification HPLC Shimadzu est préparée à :",choices:["20 mg/L directement","~1000 mg/L (~100 mg dans 100 mL d'eau UP)","100 mg/L","10 000 mg/L"],answer:1,diff:1,explication:"Solution mère caféine : ~100 mg de caféine pure pesée dans une fiole de 100 mL, complété à volume avec eau UP → C ≈ 1000 mg/L. Solution fille répétabilité : 20 mg/L (dilution 1/50 dans fiole 20 mL). Gamme linéarité : 5 solutions de 10 à 30 mg/L par prélèvements de 200 à 600 µL de la solution mère.",tags:["HPLC","Shimadzu","Caféine","Solution mère","Préparation"]},
];

const QB_ELISA_ENTERO = [
  {id:"ba_el1",prompt:"Une intoxination staphylococcique est causée par :",choices:["Les bactéries S. aureus vivantes dans l'intestin","Les entérotoxines préformées dans l'aliment (stables même sans bactéries viables)","Un virus contaminant l'aliment","Le staphylocoque coagulase-négatif uniquement"],answer:1,diff:1,explication:"Intoxination ≠ intoxication infectieuse. Les entérotoxines staphylococciques sont synthétisées et accumulées dans l'aliment avant ingestion. Elles sont thermostables (résistantes à 100°C). Dose minimale causant des troubles : 20 ng. Symptômes : vomissements intenses 1-6h après ingestion.",tags:["ELISA","Entérotoxine","Staphylocoque","Intoxination","Sécurité alimentaire"]},
  {id:"ba_el2",prompt:"Le principe de la technique ELISA utilisée pour le dosage de l'entérotoxine staphylococcique est :",choices:["Phase homogène, compétitive, directe","Phase hétérogène, non compétitive, sandwich indirect (conjugué = Ac anti-entérotoxine couplé à la phosphatase alcaline)","Phase homogène, non compétitive, directe","Phase hétérogène, compétitive, directe"],answer:1,diff:2,explication:"ELISA entérotoxine : phase hétérogène (microplaque) + non compétitive (pas d'Ag marqué) + sandwich indirect (Ag pris entre AcS fixé et conjugué). Conjugué = anticorps anti-entérotoxine A couplé à la phosphatase alcaline (PAL). Substrat : PNPP → couleur jaune → absorbance à 405 nm.",tags:["ELISA","Principe","Phase hétérogène","Sandwich","Conjugué"]},
  {id:"ba_el3",prompt:"Dans la technique ELISA pour l'entérotoxine, le substrat de la phosphatase alcaline (PAL) est :",choices:["TMB (substrat bleu pour peroxydase)","PNPP (paranitrophénylphosphate) → paranitrophénol jaune, lecture à 405 nm","ABTS","DAB"],answer:1,diff:1,explication:"PNPP (paranitrophénylphosphate) est hydrolysé par la phosphatase alcaline en paranitrophénol (couleur jaune) + phosphate. L'absorbance est lue à 405 nm. L'arrêt de réaction se fait avec NaOH 1 mol/L (50 µL) qui dénature l'enzyme et stabilise la couleur.",tags:["ELISA","PNPP","Phosphatase alcaline","405 nm","Substrat"]},
  {id:"ba_el4",prompt:"Le rôle de l'étape de saturation (surcoating au PBS-SAB) dans le protocole ELISA est :",choices:["Ajouter l'antigène à doser","Bloquer les sites non spécifiques de fixation sur le support solide (éviter les faux positifs)","Révéler la réaction enzymatique","Laver les anticorps non fixés"],answer:1,diff:1,explication:"Saturation (surcoating) : après le coating par l'anticorps sensibilisant, des sites de liaison non spécifiques restent libres sur la microplaque. PBS-SAB (sérum albumine bovine) sature ces sites → empêche la fixation non spécifique du conjugué → réduit le bruit de fond et les faux positifs.",tags:["ELISA","Saturation","Surcoating","SAB","Faux positifs"]},
  {id:"ba_el5",prompt:"L'absorbance nette dans le protocole ELISA entérotoxine est calculée par :",choices:["Absorbance brute × facteur de dilution","Absorbance brute − absorbance du témoin le plus élevé (blanc du support)","Absorbance brute + absorbance du contrôle","Log(Absorbance brute)"],answer:1,diff:1,explication:"Absorbance nette = absorbance brute − absorbance du témoin le plus élevé (A1 = blanc support ou B1 = témoin négatif selon le protocole). Cette soustraction élimine le bruit de fond non spécifique. La droite d'étalonnage est tracée avec les absorbances nettes en fonction de la concentration d'entérotoxine.",tags:["ELISA","Absorbance nette","Calcul","Témoin","Bruit de fond"]},
  {id:"ba_el6",prompt:"Dans le protocole ELISA entérotoxine staphylococcique, le puits B1 (AcS + PBS + conjugué) est le :",choices:["Témoin positif (maximum de signal)","Témoin négatif (absence d'antigène — signal doit être ≤ 0,040 abs. nette)","Contrôle qualité","Blanc du substrat"],answer:1,diff:2,explication:"Puits B1 (AcS sensibilisant + PBS à la place de l'Ag + conjugué + PNPP) = TÉMOIN NÉGATIF. Vérifie l'absence de signal en l'absence d'antigène. Son absorbance nette doit être ≤ 0,040. Un signal élevé en B1 indique une fixation non spécifique → revoir l'étape de saturation.",tags:["ELISA","Témoin négatif","B1","Contrôle","Faux positifs"]},
  {id:"ba_el7",prompt:"La gamme d'étalonnage ELISA entérotoxine est préparée par dilutions successives de raison 1/2 à partir de 10 ng/mL. Les 7 concentrations sont :",choices:["10, 9, 8, 7, 6, 5, 4 ng/mL","10, 5, 2,5, 1,25, 0,625, 0,3125, 0,156 ng/mL","10, 1, 0,1, 0,01, 0,001, 0,0001, 0,00001 ng/mL","5, 4, 3, 2, 1, 0,5, 0,25 ng/mL"],answer:1,diff:2,explication:"Dilutions de raison 1/2 depuis 10 ng/mL : 10 → 5 → 2,5 → 1,25 → 0,625 → 0,3125 → 0,156 ng/mL (7 dilutions dans des tubes de 200 µL final). On prélève 100 µL par tube pour déposer dans les puits. La 8ème position = blanc (PBS seul).",tags:["ELISA","Gamme","Dilutions en série","1/2","Entérotoxine"]},
  {id:"ba_el8",prompt:"La dose minimale d'entérotoxine staphylococcique A causant des troubles digestifs est :",choices:["200 µg","20 ng","2 mg","200 ng"],answer:1,diff:1,explication:"Dose minimale toxi-infectieuse : 20 ng d'entérotoxine staphylococcique. C'est une quantité extrêmement faible (nanogrammes) expliquant la grande toxicité de ces toxines et la nécessité d'une méthode ultra-sensible comme l'ELISA pour détecter des contaminations à des niveaux critiques dans les aliments.",tags:["ELISA","Entérotoxine","Dose minimale","20 ng","Sécurité alimentaire"]},
];


