// ═══ APP ═══
export default function App(){
  const[pid,setPid]=useState("bioalc");
  const[sec,setSec]=useState("referentiel");
  const[search,setSearch]=useState("");

  // ── Persistance étudiant ──
  const[studentName,setStudentName]=useLS("btsr_student",null);
  const[allProgress,setAllProgress]=useLS("btsr_progress",{});

  const completed=allProgress[studentName]?.completed||{};
  const qResults=allProgress[studentName]?.qr||{};

  const setCompleted=(fn)=>setAllProgress(prev=>{
    const cur=prev[studentName]?.completed||{};
    return{...prev,[studentName]:{...prev[studentName],completed:typeof fn==="function"?fn(cur):fn}};
  });
  const setQResults=(fn)=>setAllProgress(prev=>{
    const cur=prev[studentName]?.qr||{};
    return{...prev,[studentName]:{...prev[studentName],qr:typeof fn==="function"?fn(cur):fn}};
  });
  const[activeFiche,setAF]=useState(null);
  const[activeQuizTheme,setAQT]=useState(null);
  const[quizMode,setQM]=useState(null);
  const[qState,setQS]=useState(null);
  const[showAdmin,setShowAdmin]=useState(false);

  const prog=PROGRAMS.find(p=>p.id===pid);
  const totalQ=prog.quizThemes.reduce((a,t)=>a+t.bank.length,0);

  // Sync étudiant à Supabase à chaque changement de filière
  useEffect(()=>{if(studentName)syncStudent(studentName,pid);},[studentName,pid]);

  const switchProg=(id)=>{setPid(id);setSec("referentiel");setSearch("");setAF(null);setAQT(null);setQM(null);setQS(null)};
  const switchSec=(id)=>{setSec(id);setAF(null);setAQT(null);setQM(null);setQS(null)};

  const startQuiz=(theme,mode)=>{
    const n=Math.min(mode.questions,theme.bank.length);
    const questions=shuffle(theme.bank).slice(0,n);
    setAQT(theme);setQM(mode);setQS({i:0,ans:{},sc:0,fin:false,questions});
  };

  return(
    <div style={{minHeight:"100vh",background:`linear-gradient(170deg,#07060B,#0F0C18 50%,#0A0812)`,color:T.text,fontFamily:"'Sora','DM Sans',system-ui,sans-serif"}}>
      <style>{`@import url('https://fonts.googleapis.com/css2?family=Sora:wght@300;400;500;600;700;800&display=swap');*{box-sizing:border-box;margin:0;padding:0}body{background:#07060B}::-webkit-scrollbar{width:5px}::-webkit-scrollbar-thumb{background:${T.text3}30;border-radius:3px}::selection{background:${T.accent}40}input::placeholder{color:${T.text3}}@keyframes fu{from{opacity:0;transform:translateY(14px)}to{opacity:1;transform:translateY(0)}}@keyframes fi{from{opacity:0}to{opacity:1}}.hl{transition:transform .2s,box-shadow .2s,border-color .2s}.hl:hover{transform:translateY(-2px);border-color:${T.accent}30!important}.qo{transition:all .15s;cursor:pointer}.qo:hover:not([disabled]){transform:translateX(4px);border-color:${T.accent}40!important}`}</style>

      {!studentName&&<WelcomeModal onConfirm={n=>setStudentName(n)}/>}
      {showAdmin&&<AdminDashboard onClose={()=>setShowAdmin(false)}/>}

      {/* HEADER */}
      <header style={{position:"sticky",top:0,zIndex:100,background:`#07060BE0`,backdropFilter:"blur(24px)",borderBottom:`1px solid ${T.border}`}}>
        <div style={{maxWidth:1300,margin:"0 auto",padding:"11px 20px"}}>
          <div style={{display:"flex",alignItems:"center",gap:12,marginBottom:9}}>
            <div style={{width:38,height:38,borderRadius:12,background:`linear-gradient(135deg,${T.accent},${T.accent2})`,display:"flex",alignItems:"center",justifyContent:"center",fontWeight:900,fontSize:14,color:"#fff",boxShadow:`0 0 24px ${T.accent}25`,flexShrink:0}}>PH</div>
            <div style={{flex:1}}><div style={{fontWeight:800,fontSize:15.5,letterSpacing:-.3}}>Picpus House</div><div style={{fontSize:9,color:T.text3,fontWeight:700,letterSpacing:2,textTransform:"uppercase"}}>Plateforme Révisions BTS · {totalQ} questions</div></div>
            <div style={{position:"relative",width:200}}><input value={search} onChange={e=>setSearch(e.target.value)} placeholder="Rechercher…" style={{width:"100%",padding:"9px 14px 9px 32px",borderRadius:10,border:`1px solid ${T.border2}`,background:T.surface,color:T.text,fontSize:12,outline:"none"}}/><span style={{position:"absolute",left:10,top:"50%",transform:"translateY(-50%)",fontSize:12,opacity:.35}}>🔍</span></div>
            {studentName&&<StudentBadge name={studentName} onChangeName={()=>setStudentName(null)}/>}
            <button onClick={()=>setShowAdmin(true)} title="Administration" style={{width:32,height:32,borderRadius:9,border:`1px solid ${T.border}`,background:T.surface,color:T.text3,cursor:"pointer",fontSize:15,display:"flex",alignItems:"center",justifyContent:"center",flexShrink:0}}>🔐</button>
          </div>
          <div style={{display:"flex",gap:3,overflowX:"auto"}}>{PROGRAMS.map(p=><button key={p.id} onClick={()=>switchProg(p.id)} style={{padding:"7px 14px",borderRadius:9,border:pid===p.id?`1.5px solid ${p.color}50`:"1.5px solid transparent",background:pid===p.id?`${p.color}12`:"transparent",color:pid===p.id?p.color:T.text3,fontSize:11.5,fontWeight:700,cursor:"pointer",whiteSpace:"nowrap",flexShrink:0}}><span style={{marginRight:4}}>{p.icon}</span>{p.short}</button>)}</div>
        </div>
      </header>

      {/* SUB-NAV */}
      {pid!=="english"&&<div style={{maxWidth:1300,margin:"0 auto",padding:"14px 20px 0",display:"flex",gap:5,overflowX:"auto"}}>
        {SECTIONS.map(s=><button key={s.id} onClick={()=>switchSec(s.id)} style={{padding:"9px 16px",borderRadius:11,border:sec===s.id?`1.5px solid ${prog.color}35`:`1px solid ${T.border}`,background:sec===s.id?`${prog.color}0C`:T.surface,color:sec===s.id?T.text:T.text2,fontSize:12.5,fontWeight:600,cursor:"pointer",display:"flex",alignItems:"center",gap:6,whiteSpace:"nowrap",flexShrink:0}}>
          <span style={{fontSize:14}}>{s.icon}</span>{s.label}
          {s.id==="fiches"&&prog.fiches.length>0&&<Pill c={prog.color}>{prog.fiches.length}</Pill>}
          {s.id==="quiz"&&prog.quizThemes.length>0&&<Pill c={prog.color}>{totalQ}Q</Pill>}
        </button>)}
      </div>}

      {/* CONTENT */}
      <main style={{maxWidth:1300,margin:"0 auto",padding:"22px 20px 80px",animation:"fu .32s ease-out"}} key={`${pid}-${sec}-${activeFiche?.id||""}-${activeQuizTheme?.id||""}-${quizMode?.id||""}`}>
        {pid==="english"&&<EnglishApp color={prog.color}/>}
        {pid!=="english"&&<>
          {sec==="referentiel"&&<RefView prog={prog} search={search}/>}
          {sec==="fiches"&&!activeFiche&&<FichesList prog={prog} search={search} done={completed} onPick={setAF}/>}
          {sec==="fiches"&&activeFiche&&<FicheDetail f={activeFiche} c={prog.color} isDone={!!completed[`${pid}-${activeFiche.id}`]} onDone={()=>{setCompleted(p=>({...p,[`${pid}-${activeFiche.id}`]:Date.now()}));if(studentName)logFiche(studentName,pid,activeFiche.id,activeFiche.title);}} onBack={()=>setAF(null)} onQuiz={(themeId)=>{const t=prog.quizThemes.find(x=>x.ficheId===themeId);if(t){setAQT(t);setSec("quiz");setAF(null)}}}/>}
          {sec==="quiz"&&!activeQuizTheme&&<QuizHub prog={prog} search={search} res={qResults} onPickTheme={setAQT}/>}
          {sec==="quiz"&&activeQuizTheme&&!qState&&<QuizModeSelect theme={activeQuizTheme} onStart={(mode)=>startQuiz(activeQuizTheme,mode)} onBack={()=>setAQT(null)}/>}
          {sec==="quiz"&&activeQuizTheme&&qState&&<QuizPlay quiz={activeQuizTheme} mode={quizMode} s={qState} setS={setQS} c={activeQuizTheme.color||prog.color} onDone={(sc,tot)=>{setQResults(p=>{const k=`${pid}-${activeQuizTheme.id}-${quizMode.id}`;const prev=p[k];return{...p,[k]:{sc,tot,at:Date.now(),best:Math.max(sc,prev?.best||0),attempts:(prev?.attempts||0)+1}}});if(studentName)logQuiz(studentName,pid,activeQuizTheme.id,activeQuizTheme.title,quizMode.id,sc,tot);}} onBack={()=>{setQS(null);setQM(null)}} onBackToThemes={()=>{setQS(null);setQM(null);setAQT(null)}}/>}
          {sec==="annales"&&<AnnView prog={prog} search={search}/>}
          {sec==="progression"&&<ProgView prog={prog} pid={pid} done={completed} qr={qResults}/>}
        </>}
      </main>

      <footer style={{borderTop:`1px solid ${T.border}`,padding:"16px",textAlign:"center",fontSize:10,color:T.text3}}>Picpus House — BDE Campus Picpus · Aurlom Éducation · 2025–2026</footer>
    </div>
  );
}

// ─── SHARED ───
function Pill({c,children}){return <span style={{fontSize:9.5,background:`${c}20`,color:c,padding:"2px 7px",borderRadius:7,fontWeight:700}}>{children}</span>}
function Badge({c,children}){return <span style={{display:"inline-block",padding:"3px 9px",borderRadius:16,fontSize:10,fontWeight:700,background:`${c||T.accent}15`,color:c||T.accent,border:`1px solid ${c||T.accent}25`}}>{children}</span>}
function SH({icon,title,sub,c}){return <div style={{display:"flex",alignItems:"center",gap:13,marginBottom:24,padding:"18px 22px",borderRadius:T.r,background:`linear-gradient(135deg,${c}08,${c}03)`,border:`1px solid ${c}12`}}><span style={{fontSize:34}}>{icon}</span><div><h2 style={{fontSize:19,fontWeight:800,lineHeight:1.2}}>{title}</h2>{sub&&<p style={{fontSize:12,color:T.text3,marginTop:3}}>{sub}</p>}</div></div>}
function Empty({msg,hint}){return <div style={{textAlign:"center",padding:"56px 20px"}}><div style={{fontSize:44,marginBottom:10,opacity:.5}}>📭</div><div style={{fontSize:14,fontWeight:600,color:T.text2}}>{msg}</div>{hint&&<div style={{fontSize:12,color:T.text3,marginTop:5}}>{hint}</div>}</div>}
function Back({onClick,label="Retour"}){return <button onClick={onClick} style={{background:"none",border:"none",color:T.text2,cursor:"pointer",fontSize:12.5,fontWeight:600,marginBottom:14,display:"flex",alignItems:"center",gap:5}}>← {label}</button>}

// ═══ REFERENTIEL ═══
function RefView({prog,search}){
  const[open,setOpen]=useState({});
  const q=search.toLowerCase();
  const filtered=prog.blocs.map(b=>({...b,competences:b.competences.filter(c=>!q||c.label.toLowerCase().includes(q)||c.id.toLowerCase().includes(q)||c.savoirs.some(s=>s.toLowerCase().includes(q)))})).filter(b=>b.competences.length>0);
  return <div><SH icon={prog.icon} title={prog.name} sub={`${prog.blocs.length} blocs · ${prog.blocs.reduce((a,b)=>a+b.competences.length,0)} compétences`} c={prog.color}/>
    {filtered.map(b=><div key={b.id} style={{marginBottom:24}}>
      <div style={{display:"flex",alignItems:"center",gap:9,marginBottom:12}}><div style={{width:4,height:22,borderRadius:2,background:prog.color}}/><h3 style={{fontSize:14,fontWeight:700}}>{b.title}</h3>{b.unit&&<Badge c={prog.color}>{b.unit}</Badge>}</div>
      {b.themes.length>0&&<div style={{display:"flex",flexWrap:"wrap",gap:4,marginBottom:10,paddingLeft:13}}>{b.themes.map((t,i)=><span key={i} style={{fontSize:10,color:T.text3,padding:"2px 8px",borderRadius:5,background:`${T.text3}0C`,border:`1px solid ${T.border}`}}>{t}</span>)}</div>}
      <div style={{display:"flex",flexDirection:"column",gap:5}}>
        {b.competences.map(c=>{const o=!!open[c.id];return <div key={c.id} style={{background:T.card,border:`1px solid ${o?`${prog.color}28`:T.border}`,borderRadius:13,overflow:"hidden"}}>
          <button onClick={()=>setOpen(p=>({...p,[c.id]:!p[c.id]}))} style={{width:"100%",display:"flex",alignItems:"center",gap:10,padding:"13px 16px",background:"none",border:"none",cursor:"pointer",textAlign:"left",color:T.text}}>
            <span style={{width:32,height:32,borderRadius:8,display:"flex",alignItems:"center",justifyContent:"center",background:`${prog.color}12`,color:prog.color,fontWeight:800,fontSize:10.5,flexShrink:0}}>{c.id}</span>
            <span style={{flex:1,fontSize:13,fontWeight:600,lineHeight:1.3}}>{c.label}</span>
            <span style={{fontSize:15,color:T.text3,transform:o?"rotate(180deg)":"rotate(0)",transition:"transform .2s"}}>▾</span>
          </button>
          {o&&<div style={{padding:"0 16px 14px 58px",animation:"fi .2s"}}><div style={{fontSize:9.5,fontWeight:700,color:T.text3,marginBottom:6,letterSpacing:1,textTransform:"uppercase"}}>Savoirs associés</div><div style={{display:"flex",flexWrap:"wrap",gap:4}}>{c.savoirs.map((s,i)=><span key={i} style={{padding:"4px 10px",borderRadius:7,fontSize:11.5,background:T.surface,color:T.text,border:`1px solid ${T.border}`}}>{s}</span>)}</div></div>}
        </div>})}
      </div>
    </div>)}
    {filtered.length===0&&<Empty msg="Aucune compétence trouvée"/>}
  </div>;
}

// ═══ FICHES ═══
function FichesList({prog,search,done,onPick}){
  const q=search.toLowerCase();const fiches=prog.fiches.filter(f=>!q||f.title.toLowerCase().includes(q)||f.tags.some(t=>t.toLowerCase().includes(q)));
  if(!prog.fiches.length)return <Empty msg="Fiches en cours de création" hint="Les fiches BIOALC sont disponibles !"/>;
  const nc={Fondations:T.green,Intermédiaire:T.orange,Avancé:T.red};
  return <div><SH icon="📝" title="Fiches de révision" sub={`${fiches.length} fiches`} c={prog.color}/>
    <div style={{display:"grid",gridTemplateColumns:"repeat(auto-fill,minmax(280px,1fr))",gap:10}}>
      {fiches.map((f,i)=>{const d=done[`${prog.id}-${f.id}`];return <button key={f.id} className="hl" onClick={()=>onPick(f)} style={{background:T.card,border:`1px solid ${T.border2}`,borderRadius:T.r,padding:"18px",textAlign:"left",cursor:"pointer",color:T.text,display:"flex",flexDirection:"column",gap:8,animation:`fu .3s ease-out ${i*40}ms both`,position:"relative"}}>
        {d&&<div style={{position:"absolute",top:10,right:10,background:`${T.green}18`,color:T.green,fontSize:9.5,fontWeight:700,padding:"2px 7px",borderRadius:5}}>✓ Acquise</div>}
        <div style={{display:"flex",alignItems:"center",gap:7}}><span style={{background:`${nc[f.niveau]||T.accent}12`,color:nc[f.niveau]||T.accent,fontSize:9.5,fontWeight:700,padding:"2px 7px",borderRadius:5}}>{f.niveau}</span><span style={{fontSize:10.5,color:T.text3}}>{f.duree} min</span></div>
        <div style={{fontSize:14,fontWeight:700,lineHeight:1.3}}>{f.title}</div>
        <div style={{display:"flex",flexWrap:"wrap",gap:3}}>{f.tags.map(t=><span key={t} style={{fontSize:10,color:T.text2,padding:"1px 7px",borderRadius:4,background:`${T.text3}0C`}}>#{t}</span>)}</div>
      </button>})}
    </div>
  </div>;
}

function renderInline(text,c){
  if(!text)return text;
  const parts=text.split(/(\*\*.*?\*\*|\*[^*]+\*)/);
  if(parts.length===1)return text;
  return parts.map((p,i)=>{
    if(p.startsWith("**")&&p.endsWith("**"))return <strong key={i} style={{color:c,fontWeight:700}}>{p.slice(2,-2)}</strong>;
    if(p.startsWith("*")&&p.endsWith("*"))return <em key={i} style={{color:T.text2}}>{p.slice(1,-1)}</em>;
    return p;
  });
}
function FicheDetail({f,c,isDone,onDone,onBack,onQuiz}){
  const nc={Fondations:T.green,Intermédiaire:T.orange,Avancé:T.red,2:T.orange,3:T.red};
  const lines=f.contenu.split("\n");
  // Group consecutive table lines
  const groups=[];
  let i=0;
  while(i<lines.length){
    if(lines[i].trim().startsWith("|")){
      const tbl=[];
      while(i<lines.length&&lines[i].trim().startsWith("|")){tbl.push(lines[i]);i++;}
      groups.push({type:"table",lines:tbl});
    } else {
      groups.push({type:"line",content:lines[i]});i++;
    }
  }
  const renderTable=(tblLines,gi)=>{
    const rows=tblLines.filter(l=>!/^\s*\|[-:\s|]+\|\s*$/.test(l));
    const parsed=rows.map(r=>r.split("|").slice(1,-1).map(c=>c.trim()));
    if(!parsed.length)return null;
    return <div key={gi} style={{overflowX:"auto",margin:"12px 0"}}>
      <table style={{width:"100%",borderCollapse:"collapse",fontSize:12.5}}>
        <tbody>{parsed.map((row,ri)=>(
          <tr key={ri} style={{background:ri===0?`${c}18`:ri%2===0?"transparent":`rgba(255,255,255,0.025)`}}>
            {row.map((cell,ci)=>ri===0
              ? <th key={ci} style={{padding:"7px 12px",border:`1px solid ${T.border2}`,textAlign:"left",fontWeight:700,color:c,fontSize:11.5,whiteSpace:"nowrap"}}>{renderInline(cell,c)}</th>
              : <td key={ci} style={{padding:"6px 12px",border:`1px solid ${T.border2}`,color:T.text,verticalAlign:"top"}}>{renderInline(cell,c)}</td>
            )}
          </tr>
        ))}</tbody>
      </table>
    </div>;
  };
  const renderLine=(l,gi)=>{
    if(!l.trim())return <div key={gi} style={{height:6}}/>;
    if(l.startsWith("## "))return <div key={gi} style={{fontWeight:800,fontSize:15,color:c,marginTop:18,marginBottom:6,borderBottom:`1px solid ${c}30`,paddingBottom:5}}>{l.slice(3)}</div>;
    if(l.startsWith("### "))return <div key={gi} style={{fontWeight:700,fontSize:13.5,color:T.text,marginTop:12,marginBottom:3}}>{renderInline(l.slice(4),c)}</div>;
    if(l.startsWith("**")&&l.endsWith("**"))return <div key={gi} style={{fontWeight:700,fontSize:13.5,color:c,marginTop:12,marginBottom:3}}>{l.slice(2,-2)}</div>;
    if(l.startsWith("• ")||l.startsWith("▸ "))return <div key={gi} style={{paddingLeft:16,position:"relative",marginBottom:1}}><span style={{position:"absolute",left:0,color:c}}>{l[0]}</span>{renderInline(l.slice(2),c)}</div>;
    if(/^\d+\.\s/.test(l))return <div key={gi} style={{paddingLeft:16,marginBottom:1}}>{renderInline(l,c)}</div>;
    if(l.startsWith("→ ")||l.startsWith("→  "))return <div key={gi} style={{paddingLeft:14,color:T.text2,marginBottom:1}}><span style={{color:c}}>→</span> {renderInline(l.replace(/^→\s+/,""),c)}</div>;
    if(l.startsWith("✓ ")||l.startsWith("✗ "))return <div key={gi} style={{paddingLeft:16,position:"relative",marginBottom:1}}><span style={{position:"absolute",left:0,color:l[0]==="✓"?T.green:"#FF6370"}}>{l[0]}</span>{renderInline(l.slice(2),c)}</div>;
    if(l.startsWith("---"))return <hr key={gi} style={{border:"none",borderTop:`1px solid ${T.border2}`,margin:"10px 0"}}/>;
    if(l.startsWith("①")||l.startsWith("②")||l.startsWith("③"))return <div key={gi} style={{paddingLeft:22,position:"relative",marginBottom:2}}><span style={{position:"absolute",left:0,color:c,fontWeight:700}}>{l.match(/^[①-⑩]/)[0]}</span>{renderInline(l.slice(2),c)}</div>;
    return <div key={gi}>{renderInline(l,c)}</div>;
  };
  return <div style={{animation:"fu .3s"}}><Back onClick={onBack} label="Retour aux fiches"/>
    <div style={{background:T.card,border:`1px solid ${T.border2}`,borderRadius:T.r,padding:"26px",maxWidth:820}}>
      <div style={{display:"flex",alignItems:"center",gap:8,marginBottom:5,flexWrap:"wrap"}}><Badge c={nc[f.niveau]||T.orange}>{f.niveau}</Badge><span style={{fontSize:11.5,color:T.text3}}>{f.duree} min · {f.bloc}</span></div>
      <h2 style={{fontSize:21,fontWeight:800,marginBottom:7}}>{f.title}</h2>
      <div style={{display:"flex",gap:4,marginBottom:18,flexWrap:"wrap"}}>{f.tags.map(t=><span key={t} style={{fontSize:10.5,color:c,padding:"2px 9px",borderRadius:5,background:`${c}10`,border:`1px solid ${c}20`}}>#{t}</span>)}</div>
      <div style={{background:T.surface,borderRadius:11,padding:"20px",marginBottom:18,lineHeight:1.75,fontSize:13}}>
        {groups.map((g,gi)=>g.type==="table"?renderTable(g.lines,gi):renderLine(g.content,gi))}
      </div>
      <div style={{display:"flex",gap:9,flexWrap:"wrap"}}>
        <button onClick={onDone} style={{padding:"11px 22px",borderRadius:11,border:"none",background:isDone?`${T.green}18`:`linear-gradient(135deg,${c},${T.accent2})`,color:isDone?T.green:"#fff",fontSize:12.5,fontWeight:700,cursor:"pointer"}}>{isDone?"✓ Acquise":"Marquer acquise"}</button>
        {f.id&&<button onClick={()=>onQuiz(f.id)} style={{padding:"11px 22px",borderRadius:11,border:`1.5px solid ${c}35`,background:"transparent",color:c,fontSize:12.5,fontWeight:700,cursor:"pointer"}}>🎯 Quiz associé</button>}
      </div>
    </div>
  </div>;
}

// ═══ QUIZ HUB ═══
function QuizHub({prog,search,res,onPickTheme}){
  const q=search.toLowerCase();
  const themes=prog.quizThemes.filter(t=>!q||t.title.toLowerCase().includes(q)||t.tags.some(tg=>tg.toLowerCase().includes(q)));
  if(!prog.quizThemes.length)return <Empty msg="Quiz en cours de création" hint="170+ questions disponibles pour BIOALC !"/>;
  const totalQ=prog.quizThemes.reduce((a,t)=>a+t.bank.length,0);
  return <div><SH icon="🎯" title="Centre de Quiz" sub={`${themes.length} thèmes · ${totalQ} questions au total · 3 modes (Express 10Q / Standard 20Q / Marathon 50Q)`} c={prog.color}/>
    <div style={{display:"grid",gridTemplateColumns:"repeat(auto-fill,minmax(280px,1fr))",gap:10}}>
      {themes.map((t,i)=>{
        const bestResults=QUIZ_MODES.map(m=>{const r=res[`${prog.id}-${t.id}-${m.id}`];return r?{...r,mode:m}:null}).filter(Boolean);
        return <button key={t.id} className="hl" onClick={()=>onPickTheme(t)} style={{background:T.card,border:`1px solid ${T.border2}`,borderRadius:T.r,padding:"18px",textAlign:"left",cursor:"pointer",color:T.text,display:"flex",flexDirection:"column",gap:8,animation:`fu .3s ease-out ${i*40}ms both`}}>
          <div style={{display:"flex",alignItems:"center",gap:8}}><div style={{width:8,height:8,borderRadius:4,background:t.color||T.accent}}/><span style={{fontSize:14,fontWeight:700}}>{t.title}</span></div>
          <div style={{fontSize:11.5,color:T.text3}}>{t.bank.length} questions disponibles</div>
          <div style={{display:"flex",gap:3,flexWrap:"wrap"}}>{t.tags.map(tg=><span key={tg} style={{fontSize:10,color:T.text2,padding:"1px 7px",borderRadius:4,background:`${T.text3}0C`}}>#{tg}</span>)}</div>
          {bestResults.length>0&&<div style={{marginTop:3,padding:"7px 10px",borderRadius:7,background:`${T.green}0A`,border:`1px solid ${T.green}18`}}>
            {bestResults.map(r=><div key={r.mode.id} style={{fontSize:10,color:T.green,fontWeight:600}}>{r.mode.icon} {r.mode.label}: best {r.best}/{r.tot} ({Math.round(r.best/r.tot*100)}%)</div>)}
          </div>}
        </button>;
      })}
    </div>
  </div>;
}

function QuizModeSelect({theme,onStart,onBack}){
  return <div style={{animation:"fu .3s",maxWidth:600,margin:"0 auto"}}>
    <Back onClick={onBack} label="Tous les thèmes"/>
    <SH icon="🎯" title={theme.title} sub={`${theme.bank.length} questions dans la banque`} c={theme.color||T.accent}/>
    <div style={{fontSize:14,fontWeight:700,marginBottom:16}}>Choisissez votre mode :</div>
    <div style={{display:"flex",flexDirection:"column",gap:10}}>
      {QUIZ_MODES.map(m=>{
        const available=Math.min(m.questions,theme.bank.length);
        const disabled=available<5;
        return <button key={m.id} disabled={disabled} onClick={()=>!disabled&&onStart(m)} className={disabled?"":"hl"} style={{background:T.card,border:`1px solid ${T.border2}`,borderRadius:T.r,padding:"20px",textAlign:"left",cursor:disabled?"not-allowed":"pointer",color:disabled?T.text3:T.text,display:"flex",alignItems:"center",gap:16,opacity:disabled?.4:1}}>
          <span style={{fontSize:36}}>{m.icon}</span>
          <div>
            <div style={{fontSize:16,fontWeight:700}}>{m.label}</div>
            <div style={{fontSize:12,color:T.text3}}>{m.desc} · {available} questions disponibles</div>
          </div>
        </button>;
      })}
    </div>
  </div>;
}

// ═══ QUIZ PLAY ═══
function QuizPlay({quiz,mode,s,setS,c,onDone,onBack,onBackToThemes}){
  const{i,ans,sc,fin,questions}=s;
  if(!questions||!questions.length)return <Empty msg="Pas de questions disponibles"/>;
  const q=questions[i];const picked=ans[q?.id];const show=picked!==undefined;
  const pick=(n)=>{if(show)return;const ok=n===q.answer;setS(p=>({...p,ans:{...p.ans,[q.id]:n},sc:ok?p.sc+1:p.sc}))};
  const next=()=>{if(i+1>=questions.length){onDone(s.sc,questions.length);setS(p=>({...p,fin:true}))}else setS(p=>({...p,i:p.i+1}))};
  const restart=()=>{const n=Math.min(mode.questions,quiz.bank.length);const qs=shuffle(quiz.bank).slice(0,n);setS({i:0,ans:{},sc:0,fin:false,questions:qs})};

  if(fin){const pct=Math.round((sc/questions.length)*100);const em=pct>=90?"🏆":pct>=70?"🌟":pct>=50?"👍":"💪";
    return <div style={{animation:"fu .35s",maxWidth:700,margin:"0 auto"}}>
      <div style={{background:T.card,borderRadius:T.r,padding:"40px 28px",border:`1px solid ${T.border2}`,textAlign:"center"}}>
        <div style={{fontSize:52,marginBottom:12}}>{em}</div>
        <div style={{fontSize:12,color:T.text3,fontWeight:600,marginBottom:4}}>{mode.icon} {mode.label} — {quiz.title}</div>
        <h2 style={{fontSize:24,fontWeight:800,marginBottom:6}}>{sc}/{questions.length} correct</h2>
        <div style={{fontSize:34,fontWeight:800,color:pct>=70?T.green:pct>=50?T.orange:T.red,marginBottom:16}}>{pct}%</div>
        <div style={{height:7,borderRadius:3,background:`${T.text3}10`,marginBottom:24,maxWidth:300,margin:"0 auto 24px"}}><div style={{height:"100%",borderRadius:3,background:pct>=70?T.green:pct>=50?T.orange:T.red,width:`${pct}%`,transition:"width 1s"}}/></div>
        {/* Review */}
        <div style={{textAlign:"left",marginBottom:22,maxHeight:300,overflowY:"auto",paddingRight:8}}>
          {questions.map((qq,idx)=>{const a=ans[qq.id];const ok=a===qq.answer;return <div key={qq.id} style={{padding:"8px 12px",borderRadius:8,marginBottom:4,background:ok?`${T.green}06`:`${T.red}06`,border:`1px solid ${ok?`${T.green}15`:`${T.red}15`}`,fontSize:11.5}}>
            <span style={{color:ok?T.green:T.red,fontWeight:700}}>{ok?"✓":"✗"}</span> Q{idx+1}: {qq.prompt.slice(0,80)}{qq.prompt.length>80?"…":""}
            {!ok&&<div style={{color:T.text3,fontSize:10.5,marginTop:2}}>Bonne réponse: {qq.choices[qq.answer]}</div>}
          </div>})}
        </div>
        <div style={{display:"flex",gap:9,justifyContent:"center",flexWrap:"wrap"}}>
          <button onClick={restart} style={{padding:"11px 24px",borderRadius:11,border:"none",background:`linear-gradient(135deg,${c},${T.accent2})`,color:"#fff",fontSize:12.5,fontWeight:700,cursor:"pointer"}}>🔄 Recommencer</button>
          <button onClick={onBack} style={{padding:"11px 24px",borderRadius:11,border:`1.5px solid ${T.border2}`,background:"transparent",color:T.text,fontSize:12.5,fontWeight:600,cursor:"pointer"}}>Changer de mode</button>
          <button onClick={onBackToThemes} style={{padding:"11px 24px",borderRadius:11,border:`1.5px solid ${T.border2}`,background:"transparent",color:T.text,fontSize:12.5,fontWeight:600,cursor:"pointer"}}>Tous les quiz</button>
        </div>
      </div>
    </div>;
  }

  return <div style={{animation:"fu .3s",maxWidth:700,margin:"0 auto"}}>
    <Back onClick={onBackToThemes} label="Quitter le quiz"/>
    <div style={{display:"flex",alignItems:"center",justifyContent:"space-between",marginBottom:12}}>
      <div><span style={{fontSize:13,fontWeight:700}}>{quiz.title}</span><span style={{fontSize:11,color:T.text3,marginLeft:8}}>{mode.icon} {mode.label}</span></div>
      <span style={{fontSize:11.5,color:T.text3,fontWeight:600}}>Q{i+1}/{questions.length}</span>
    </div>
    <div style={{height:4,borderRadius:2,background:`${T.text3}10`,marginBottom:18}}><div style={{height:"100%",borderRadius:2,background:c,width:`${((i+1)/questions.length)*100}%`,transition:"width .35s"}}/></div>
    <div style={{background:T.card,borderRadius:T.r,padding:"24px",border:`1px solid ${T.border2}`}}>
      {q.diff&&<div style={{marginBottom:8}}>{[1,2,3].map(d=><span key={d} style={{fontSize:10,marginRight:2,opacity:d<=q.diff?1:.2}}>⭐</span>)}</div>}
      <div style={{fontSize:15,fontWeight:700,lineHeight:1.4,marginBottom:18}}>{q.prompt}</div>
      <div style={{display:"flex",flexDirection:"column",gap:7}}>
        {q.choices.map((ch,n)=>{const sel=picked===n;const ok=n===q.answer;return <button key={n} className="qo" disabled={show} onClick={()=>pick(n)} style={{padding:"13px 16px",borderRadius:11,border:`1.5px solid ${show&&ok?`${T.green}45`:show&&sel&&!ok?`${T.red}45`:sel?`${c}45`:T.border2}`,background:show&&ok?`${T.green}0A`:show&&sel&&!ok?`${T.red}0A`:sel?`${c}06`:T.surface,color:T.text,fontSize:13,fontWeight:600,textAlign:"left",display:"flex",alignItems:"center",gap:11}}>
          <span style={{width:26,height:26,borderRadius:7,display:"flex",alignItems:"center",justifyContent:"center",fontSize:11,fontWeight:700,background:show&&ok?`${T.green}18`:show&&sel?`${T.red}18`:`${T.text3}10`,color:show&&ok?T.green:show&&sel?T.red:T.text3,flexShrink:0}}>{show?(ok?"✓":(sel?"✗":String.fromCharCode(65+n))):String.fromCharCode(65+n)}</span>{ch}
        </button>})}
      </div>
      {show&&q.explication&&<div style={{marginTop:14,padding:"12px 14px",borderRadius:9,background:`${c}08`,border:`1px solid ${c}18`,fontSize:12.5,lineHeight:1.5,color:T.text2,animation:"fi .25s"}}><span style={{fontWeight:700,color:c}}>💡 </span>{q.explication}</div>}
      <div style={{marginTop:16,display:"flex",justifyContent:"space-between",alignItems:"center"}}>
        <span style={{fontSize:11.5,color:T.text3}}>Score: {sc}/{i+(show?1:0)}</span>
        {show&&<button onClick={next} style={{padding:"10px 22px",borderRadius:10,border:"none",background:`linear-gradient(135deg,${c},${T.accent2})`,color:"#fff",fontSize:12.5,fontWeight:700,cursor:"pointer"}}>{i+1<questions.length?"Suivante →":"Résultats 🎯"}</button>}
      </div>
    </div>
  </div>;
}

// ═══ ANNALES ═══
