function speak(text,lang="en-GB",rate=0.85){
  if(!window.speechSynthesis)return;
  window.speechSynthesis.cancel();
  const u=new SpeechSynthesisUtterance(text);
  u.lang=lang;u.rate=rate;
  const voices=window.speechSynthesis.getVoices();
  const v=voices.find(v=>v.lang==="en-GB")||voices.find(v=>v.lang==="en-US")||voices.find(v=>v.lang.startsWith("en"));
  if(v)u.voice=v;
  window.speechSynthesis.speak(u);
}

const EN_FILIERE_LABELS={bioalc:"BIOALC",abm:"ABM",bm:"BM",ol:"Opticien-Lunetier",fed:"FED C",prodent:"Prothésiste Dentaire"};

// ─── ENGLISH HOME ───
function EnglishApp({color}){
  const[filiere,setFiliere]=useState(null);
  const[mode,setMode]=useState(null);
  const filieres=Object.keys(EN_FILIERE_LABELS);
  const modes=[
    {id:"vocab",icon:"📚",title:"Vocabulaire",desc:"Quiz EN↔FR sur le vocabulaire de ta filière"},
    {id:"pronunciation",icon:"🎤",title:"Prononciation",desc:"Prononce le mot — l'IA vérifie ta prononciation (Chrome/Edge)"},
    {id:"dictation",icon:"✍️",title:"Dictée",desc:"Écoute le mot et écris-le correctement"},
    {id:"listening",icon:"🎧",title:"Compréhension orale",desc:"Écoute un texte et réponds aux questions sans le lire"},
  ];
  if(mode==="vocab"&&filiere)return <EnglishVocab filiere={filiere} color={color} onBack={()=>setMode(null)}/>;
  if(mode==="pronunciation"&&filiere)return <EnglishPronunciation filiere={filiere} color={color} onBack={()=>setMode(null)}/>;
  if(mode==="dictation"&&filiere)return <EnglishDictation filiere={filiere} color={color} onBack={()=>setMode(null)}/>;
  if(mode==="listening"&&filiere)return <EnglishListening filiere={filiere} color={color} onBack={()=>setMode(null)}/>;
  return <div style={{animation:"fu .3s"}}>
    <SH icon="🇬🇧" title="Anglais professionnel" sub="4 activités pour maîtriser l'anglais de ton BTS" c={color}/>
    <div style={{marginBottom:24}}>
      <div style={{fontSize:12.5,fontWeight:700,marginBottom:10,color:T.text2}}>Ta filière :</div>
      <div style={{display:"flex",gap:7,flexWrap:"wrap"}}>
        {filieres.map(f=><button key={f} onClick={()=>setFiliere(f)} style={{padding:"8px 16px",borderRadius:10,border:filiere===f?`1.5px solid ${color}50`:`1px solid ${T.border2}`,background:filiere===f?`${color}12`:T.surface,color:filiere===f?color:T.text2,fontSize:12,fontWeight:700,cursor:"pointer"}}>{EN_FILIERE_LABELS[f]}</button>)}
      </div>
    </div>
    {!filiere&&<div style={{padding:"18px",borderRadius:T.r,background:`${color}08`,border:`1px solid ${color}18`,fontSize:13,color:T.text3}}>👆 Sélectionne ta filière pour commencer</div>}
    {filiere&&<div style={{display:"grid",gridTemplateColumns:"repeat(auto-fill,minmax(260px,1fr))",gap:12}}>
      {modes.map((m,i)=><button key={m.id} className="hl" onClick={()=>setMode(m.id)} style={{background:T.card,border:`1px solid ${T.border2}`,borderRadius:T.r,padding:"22px",textAlign:"left",cursor:"pointer",color:T.text,animation:`fu .3s ease-out ${i*60}ms both`}}>
        <div style={{fontSize:36,marginBottom:10}}>{m.icon}</div>
        <div style={{fontSize:15,fontWeight:700,marginBottom:5}}>{m.title}</div>
        <div style={{fontSize:12,color:T.text3,lineHeight:1.4}}>{m.desc}</div>
      </button>)}
    </div>}
  </div>;
}

// ─── VOCAB ───
function EnglishVocab({filiere,color,onBack}){
  const bank=ENGLISH_VOCAB[filiere]||[];
  const[items]=useState(()=>shuffle(bank));
  const[idx,setIdx]=useState(0);
  const[dir,setDir]=useState("en_to_fr");// en_to_fr or fr_to_en
  const[picked,setPicked]=useState(null);
  const[score,setScore]=useState(0);
  const[done,setDone]=useState(false);
  if(!bank.length)return <div><Back onClick={onBack}/>  <Empty msg="Vocabulaire non disponible pour cette filière"/></div>;
  const item=items[idx];
  const wrongPool=items.filter((_,i)=>i!==idx);
  const[choices]=useState(()=>{});
  const getChoices=useMemo(()=>{
    const wrongs=shuffle(wrongPool).slice(0,3);
    const opts=dir==="en_to_fr"
      ?[item.fr,...wrongs.map(w=>w.fr)]
      :[item.word,...wrongs.map(w=>w.word)];
    return shuffle(opts);
  },[idx,dir,item]);
  const answer=dir==="en_to_fr"?item.fr:item.word;
  const question=dir==="en_to_fr"?item.word:item.fr;
  const isCorrect=picked===answer;
  const next=()=>{
    if(idx+1>=items.length){setDone(true);return;}
    setIdx(i=>i+1);setPicked(null);
    setDir(Math.random()>.5?"en_to_fr":"fr_to_en");
  };
  const pick=(c)=>{if(picked)return;if(c===answer)setScore(s=>s+1);setPicked(c);};
  if(done){const pct=Math.round(score/items.length*100);return <div style={{animation:"fu .3s",maxWidth:600,margin:"0 auto"}}>
    <div style={{background:T.card,borderRadius:T.r,padding:"36px",border:`1px solid ${T.border2}`,textAlign:"center"}}>
      <div style={{fontSize:48,marginBottom:10}}>{pct>=80?"🏆":pct>=60?"🌟":"💪"}</div>
      <h2 style={{fontSize:22,fontWeight:800,marginBottom:6}}>{score}/{items.length}</h2>
      <div style={{fontSize:32,fontWeight:800,color:pct>=70?T.green:pct>=50?T.orange:T.red,marginBottom:20}}>{pct}%</div>
      <div style={{display:"flex",gap:9,justifyContent:"center"}}>
        <button onClick={()=>{setIdx(0);setPicked(null);setScore(0);setDone(false);}} style={{padding:"11px 22px",borderRadius:11,border:"none",background:`linear-gradient(135deg,${color},#2563EB)`,color:"#fff",fontSize:12.5,fontWeight:700,cursor:"pointer"}}>🔄 Recommencer</button>
        <button onClick={onBack} style={{padding:"11px 22px",borderRadius:11,border:`1.5px solid ${T.border2}`,background:"transparent",color:T.text,fontSize:12.5,fontWeight:600,cursor:"pointer"}}>← Retour</button>
      </div>
    </div>
  </div>;}
  return <div style={{animation:"fu .3s",maxWidth:640,margin:"0 auto"}}>
    <Back onClick={onBack} label="Activités anglais"/>
    <div style={{display:"flex",justifyContent:"space-between",alignItems:"center",marginBottom:10}}>
      <span style={{fontSize:12.5,fontWeight:700}}>Vocabulaire — {EN_FILIERE_LABELS[filiere]}</span>
      <span style={{fontSize:11.5,color:T.text3}}>{idx+1}/{items.length} · Score: {score}</span>
    </div>
    <div style={{height:4,borderRadius:2,background:`${T.text3}10`,marginBottom:18}}><div style={{height:"100%",borderRadius:2,background:color,width:`${((idx+1)/items.length)*100}%`,transition:"width .35s"}}/></div>
    <div style={{background:T.card,border:`1px solid ${T.border2}`,borderRadius:T.r,padding:"26px"}}>
      <div style={{fontSize:10.5,color:T.text3,marginBottom:6,fontWeight:700,letterSpacing:.8}}>{dir==="en_to_fr"?"ANGLAIS → FRANÇAIS":"FRANÇAIS → ANGLAIS"}</div>
      <div style={{fontSize:24,fontWeight:800,marginBottom:4}}>{question}</div>
      {dir==="en_to_fr"&&item.ipa&&<div style={{fontSize:12,color:T.text3,marginBottom:4,fontFamily:"monospace"}}>{item.ipa}</div>}
      <button onClick={()=>speak(dir==="en_to_fr"?item.word:item.fr,dir==="en_to_fr"?"en-GB":"fr-FR")} style={{marginBottom:18,padding:"6px 13px",borderRadius:8,border:`1px solid ${color}30`,background:`${color}10`,color,fontSize:11,fontWeight:600,cursor:"pointer"}}>🔊 Écouter</button>
      {dir==="en_to_fr"&&item.example&&<div style={{fontSize:11.5,color:T.text3,marginBottom:16,fontStyle:"italic",padding:"8px 12px",borderRadius:7,background:`${T.text3}08`,border:`1px solid ${T.border}`}}>"{item.example}"</div>}
      <div style={{display:"flex",flexDirection:"column",gap:7}}>
        {getChoices.map((c,n)=>{const sel=picked===c;const ok=c===answer;return <button key={n} disabled={!!picked} onClick={()=>pick(c)} className="qo" style={{padding:"12px 16px",borderRadius:10,border:`1.5px solid ${picked&&ok?`${T.green}45`:picked&&sel&&!ok?`${T.red}45`:sel?`${color}45`:T.border2}`,background:picked&&ok?`${T.green}0A`:picked&&sel&&!ok?`${T.red}0A`:T.surface,color:T.text,fontSize:13,fontWeight:600,textAlign:"left",display:"flex",alignItems:"center",gap:9}}>
          <span style={{width:26,height:26,borderRadius:7,display:"flex",alignItems:"center",justifyContent:"center",fontSize:11,fontWeight:700,background:picked&&ok?`${T.green}18`:picked&&sel?`${T.red}18`:`${T.text3}10`,color:picked&&ok?T.green:picked&&sel?T.red:T.text3,flexShrink:0}}>{picked?(ok?"✓":(sel?"✗":String.fromCharCode(65+n))):String.fromCharCode(65+n)}</span>{c}
        </button>;})}
      </div>
      {picked&&<div style={{marginTop:16,display:"flex",justifyContent:"space-between",alignItems:"center"}}>
        <span style={{fontSize:12,color:isCorrect?T.green:T.red,fontWeight:700}}>{isCorrect?"✓ Correct !":"✗ Raté"}</span>
        <button onClick={next} style={{padding:"10px 22px",borderRadius:10,border:"none",background:`linear-gradient(135deg,${color},#2563EB)`,color:"#fff",fontSize:12.5,fontWeight:700,cursor:"pointer"}}>{idx+1<items.length?"Suivant →":"Résultats 🎯"}</button>
      </div>}
    </div>
  </div>;
}

// ─── PRONUNCIATION ───
function EnglishPronunciation({filiere,color,onBack}){
  const bank=ENGLISH_VOCAB[filiere]||[];
  const[items]=useState(()=>shuffle(bank));
  const[idx,setIdx]=useState(0);
  const[status,setStatus]=useState("idle");// idle | listening | success | fail | unsupported
  const[transcript,setTranscript]=useState("");
  const recRef=useRef(null);
  const SR=window.SpeechRecognition||window.webkitSpeechRecognition;
  const supported=!!SR;
  if(!bank.length)return <div><Back onClick={onBack}/><Empty msg="Vocabulaire non disponible pour cette filière"/></div>;
  const item=items[idx];
  const check=(t)=>{
    const norm=(s)=>s.toLowerCase().replace(/[^a-z]/g,"");
    const ok=norm(t).includes(norm(item.word))||norm(item.word).includes(norm(t))||norm(t)===norm(item.word);
    setTranscript(t);setStatus(ok?"success":"fail");
  };
  const listen=()=>{
    if(!supported){setStatus("unsupported");return;}
    speak(item.word);
    setTimeout(()=>{
      const rec=new SR();rec.lang="en-US";rec.maxAlternatives=5;rec.continuous=false;rec.interimResults=false;
      recRef.current=rec;
      rec.onresult=(e)=>{const alts=Array.from(e.results[0]).map(a=>a.transcript);check(alts[0]);};
      rec.onerror=(e)=>{if(e.error!=="no-speech")setStatus("fail");else setStatus("idle");};
      rec.onend=()=>{if(status==="listening")setStatus("idle");};
      setStatus("listening");rec.start();
    },1400);
  };
  const next=()=>{setIdx(i=>i+1<items.length?i+1:0);setStatus("idle");setTranscript("");};
  const statusColors={idle:color,listening:"#F59E0B",success:T.green,fail:T.red};
  const sc=statusColors[status]||color;
  return <div style={{animation:"fu .3s",maxWidth:580,margin:"0 auto"}}>
    <Back onClick={onBack} label="Activités anglais"/>
    <div style={{display:"flex",justifyContent:"space-between",marginBottom:10}}>
      <span style={{fontSize:12.5,fontWeight:700}}>Prononciation — {EN_FILIERE_LABELS[filiere]}</span>
      <span style={{fontSize:11.5,color:T.text3}}>{idx+1}/{items.length}</span>
    </div>
    {!supported&&<div style={{marginBottom:12,padding:"10px 14px",borderRadius:9,background:`${T.red}0C`,border:`1px solid ${T.red}25`,fontSize:12,color:T.red}}>⚠️ Reconnaissance vocale non disponible — utilisez Chrome ou Edge</div>}
    <div style={{background:T.card,border:`1px solid ${sc}30`,borderRadius:T.r,padding:"32px",textAlign:"center"}}>
      <div style={{fontSize:11,color:T.text3,marginBottom:8,fontWeight:700,letterSpacing:.8}}>PRONONCE CE MOT</div>
      <div style={{fontSize:32,fontWeight:800,marginBottom:4}}>{item.word}</div>
      {item.ipa&&<div style={{fontSize:14,color:T.text3,marginBottom:4,fontFamily:"monospace"}}>{item.ipa}</div>}
      <div style={{fontSize:13,color:T.text2,marginBottom:20}}>{item.fr}</div>
      <button onClick={()=>speak(item.word)} style={{marginBottom:20,padding:"7px 15px",borderRadius:8,border:`1px solid ${color}30`,background:`${color}10`,color,fontSize:11.5,fontWeight:600,cursor:"pointer"}}>🔊 Exemple de prononciation</button>
      <div style={{marginBottom:20}}>
        <button onClick={listen} disabled={status==="listening"} style={{width:80,height:80,borderRadius:40,border:`3px solid ${sc}`,background:`${sc}15`,color:sc,fontSize:28,cursor:"pointer",display:"flex",alignItems:"center",justifyContent:"center",margin:"0 auto",transition:"all .2s"}}>
          {status==="listening"?"⏳":status==="success"?"✓":status==="fail"?"✗":"🎤"}
        </button>
        <div style={{fontSize:11,color:T.text3,marginTop:8}}>
          {status==="idle"?"Clique pour parler":status==="listening"?"Écoute en cours…":status==="success"?"Excellent ! Prononciation correcte":status==="fail"?"Pas tout à fait, réessaie":""}
        </div>
        {transcript&&<div style={{marginTop:6,fontSize:12,color:T.text3}}>Reconnu : "<em>{transcript}</em>"</div>}
      </div>
      <div style={{display:"flex",gap:9,justifyContent:"center"}}>
        {(status==="success"||status==="fail")&&<button onClick={listen} style={{padding:"9px 18px",borderRadius:10,border:`1.5px solid ${color}35`,background:"transparent",color,fontSize:12,fontWeight:600,cursor:"pointer"}}>🔄 Réessayer</button>}
        <button onClick={next} style={{padding:"9px 18px",borderRadius:10,border:"none",background:`linear-gradient(135deg,${color},#2563EB)`,color:"#fff",fontSize:12,fontWeight:700,cursor:"pointer"}}>Mot suivant →</button>
      </div>
    </div>
  </div>;
}

// ─── DICTATION ───
function EnglishDictation({filiere,color,onBack}){
  const bank=ENGLISH_VOCAB[filiere]||[];
  const[items]=useState(()=>shuffle(bank));
  const[idx,setIdx]=useState(0);
  const[input,setInput]=useState("");
  const[checked,setChecked]=useState(false);
  const[score,setScore]=useState(0);
  const[done,setDone]=useState(false);
  if(!bank.length)return <div><Back onClick={onBack}/><Empty msg="Vocabulaire non disponible pour cette filière"/></div>;
  const item=items[idx];
  const norm=(s)=>s.trim().toLowerCase();
  const isCorrect=norm(input)===norm(item.word);
  const playWord=()=>speak(item.word,"en-GB",0.7);
  const check=()=>{if(!input.trim())return;if(isCorrect)setScore(s=>s+1);setChecked(true);};
  const next=()=>{
    if(idx+1>=items.length){setDone(true);return;}
    setIdx(i=>i+1);setInput("");setChecked(false);
  };
  if(done){const pct=Math.round(score/items.length*100);return <div style={{animation:"fu .3s",maxWidth:600,margin:"0 auto"}}>
    <div style={{background:T.card,borderRadius:T.r,padding:"36px",border:`1px solid ${T.border2}`,textAlign:"center"}}>
      <div style={{fontSize:48,marginBottom:10}}>{pct>=80?"🏆":pct>=60?"🌟":"💪"}</div>
      <h2 style={{fontSize:22,fontWeight:800,marginBottom:6}}>{score}/{items.length}</h2>
      <div style={{fontSize:32,fontWeight:800,color:pct>=70?T.green:pct>=50?T.orange:T.red,marginBottom:20}}>{pct}%</div>
      <div style={{display:"flex",gap:9,justifyContent:"center"}}>
        <button onClick={()=>{setIdx(0);setInput("");setChecked(false);setScore(0);setDone(false);}} style={{padding:"11px 22px",borderRadius:11,border:"none",background:`linear-gradient(135deg,${color},#2563EB)`,color:"#fff",fontSize:12.5,fontWeight:700,cursor:"pointer"}}>🔄 Recommencer</button>
        <button onClick={onBack} style={{padding:"11px 22px",borderRadius:11,border:`1.5px solid ${T.border2}`,background:"transparent",color:T.text,fontSize:12.5,fontWeight:600,cursor:"pointer"}}>← Retour</button>
      </div>
    </div>
  </div>;}
  return <div style={{animation:"fu .3s",maxWidth:580,margin:"0 auto"}}>
    <Back onClick={onBack} label="Activités anglais"/>
    <div style={{display:"flex",justifyContent:"space-between",marginBottom:10}}>
      <span style={{fontSize:12.5,fontWeight:700}}>Dictée — {EN_FILIERE_LABELS[filiere]}</span>
      <span style={{fontSize:11.5,color:T.text3}}>{idx+1}/{items.length} · Score: {score}</span>
    </div>
    <div style={{height:4,borderRadius:2,background:`${T.text3}10`,marginBottom:18}}><div style={{height:"100%",borderRadius:2,background:color,width:`${((idx+1)/items.length)*100}%`,transition:"width .35s"}}/></div>
    <div style={{background:T.card,border:`1px solid ${T.border2}`,borderRadius:T.r,padding:"28px",textAlign:"center"}}>
      <div style={{fontSize:11,color:T.text3,marginBottom:6,fontWeight:700,letterSpacing:.8}}>ÉCOUTE ET ÉCRIS LE MOT</div>
      <div style={{fontSize:13,color:T.text2,marginBottom:20}}>{item.fr}</div>
      <button onClick={playWord} style={{marginBottom:24,width:70,height:70,borderRadius:35,border:`2px solid ${color}40`,background:`${color}10`,color,fontSize:28,cursor:"pointer",display:"flex",alignItems:"center",justifyContent:"center",margin:"0 auto 24px"}}>🔊</button>
      {!checked&&<div style={{marginBottom:16}}>
        <input value={input} onChange={e=>setInput(e.target.value)} onKeyDown={e=>{if(e.key==="Enter")check();}} placeholder="Écris le mot en anglais…" style={{width:"100%",padding:"13px 16px",borderRadius:11,border:`1.5px solid ${T.border2}`,background:T.surface,color:T.text,fontSize:15,fontWeight:600,outline:"none",textAlign:"center"}}/>
        <button onClick={check} style={{marginTop:12,padding:"11px 28px",borderRadius:11,border:"none",background:`linear-gradient(135deg,${color},#2563EB)`,color:"#fff",fontSize:13,fontWeight:700,cursor:"pointer"}}>Vérifier</button>
      </div>}
      {checked&&<div style={{marginBottom:16}}>
        <div style={{fontSize:20,fontWeight:800,color:isCorrect?T.green:T.red,marginBottom:6}}>{isCorrect?"✓ Correct !":"✗ Incorrect"}</div>
        {!isCorrect&&<div style={{fontSize:16,fontWeight:700,color:T.text,marginBottom:6}}>Réponse : <span style={{color}}>{item.word}</span></div>}
        {item.ipa&&<div style={{fontSize:12,color:T.text3,fontFamily:"monospace",marginBottom:12}}>{item.ipa}</div>}
        <button onClick={()=>speak(item.word,"en-GB",0.7)} style={{marginBottom:14,padding:"7px 15px",borderRadius:8,border:`1px solid ${color}30`,background:`${color}10`,color,fontSize:11.5,fontWeight:600,cursor:"pointer"}}>🔊 Réécouter</button>
        <div><button onClick={next} style={{padding:"11px 24px",borderRadius:11,border:"none",background:`linear-gradient(135deg,${color},#2563EB)`,color:"#fff",fontSize:12.5,fontWeight:700,cursor:"pointer"}}>{idx+1<items.length?"Mot suivant →":"Résultats 🎯"}</button></div>
      </div>}
    </div>
  </div>;
}

// ─── LISTENING ───
function EnglishListening({filiere,color,onBack}){
  const bank=ENGLISH_LISTENING[filiere]||[];
  const[exIdx,setExIdx]=useState(0);
  const[phase,setPhase]=useState("intro");// intro | playing | questions | result
  const[answers,setAnswers]=useState({});
  const[score,setScore]=useState(null);
  if(!bank.length)return <div><Back onClick={onBack}/><Empty msg="Exercices d'écoute non disponibles pour cette filière"/></div>;
  const ex=bank[exIdx];
  const playText=()=>{
    speak(ex.text,"en-GB",0.8);
    setPhase("playing");
    const ms=ex.text.split(" ").length*0.65*1000+2500;
    setTimeout(()=>setPhase("questions"),ms);
  };
  const pick=(qi,ci)=>{if(answers[qi]!==undefined)return;setAnswers(p=>({...p,[qi]:ci}));};
  const submit=()=>{
    const sc=ex.questions.reduce((a,q,i)=>a+(answers[i]===q.answer?1:0),0);
    setScore(sc);setPhase("result");
  };
  const nextEx=()=>{
    const next=exIdx+1<bank.length?exIdx+1:0;
    setExIdx(next);setPhase("intro");setAnswers({});setScore(null);
    window.speechSynthesis.cancel();
  };
  const allAnswered=ex.questions.every((_,i)=>answers[i]!==undefined);
  const levelColors={A2:T.green,B1:T.orange,B2:T.red};
  return <div style={{animation:"fu .3s",maxWidth:680,margin:"0 auto"}}>
    <Back onClick={onBack} label="Activités anglais"/>
    <div style={{display:"flex",justifyContent:"space-between",alignItems:"center",marginBottom:14}}>
      <span style={{fontSize:12.5,fontWeight:700}}>Compréhension orale — {EN_FILIERE_LABELS[filiere]}</span>
      <div style={{display:"flex",gap:6}}>
        {bank.map((_,i)=><button key={i} onClick={()=>{setExIdx(i);setPhase("intro");setAnswers({});setScore(null);window.speechSynthesis.cancel();}} style={{width:26,height:26,borderRadius:6,border:`1.5px solid ${i===exIdx?`${color}50`:T.border2}`,background:i===exIdx?`${color}12`:T.surface,color:i===exIdx?color:T.text3,fontSize:11,fontWeight:700,cursor:"pointer"}}>{i+1}</button>)}
      </div>
    </div>
    <div style={{background:T.card,border:`1px solid ${T.border2}`,borderRadius:T.r,padding:"26px"}}>
      <div style={{display:"flex",gap:8,alignItems:"center",marginBottom:12}}>
        <Badge c={levelColors[ex.level]||color}>{ex.level}</Badge>
        <span style={{fontSize:14,fontWeight:700}}>{ex.title}</span>
      </div>
      {phase==="intro"&&<div style={{textAlign:"center",padding:"24px 0"}}>
        <div style={{fontSize:13,color:T.text2,marginBottom:20,lineHeight:1.5}}>Tu vas entendre un texte en anglais.<br/><strong style={{color:T.text}}>Ne lis pas le texte</strong> — écoute attentivement et réponds ensuite aux questions.</div>
        <button onClick={playText} style={{padding:"14px 32px",borderRadius:12,border:"none",background:`linear-gradient(135deg,${color},#2563EB)`,color:"#fff",fontSize:14,fontWeight:700,cursor:"pointer",display:"inline-flex",alignItems:"center",gap:8}}>🎧 Lancer l'écoute</button>
        <div style={{marginTop:12,fontSize:11,color:T.text3}}>Durée estimée : ~{Math.round(ex.text.split(" ").length*0.65)}s · {ex.questions.length} questions</div>
      </div>}
      {phase==="playing"&&<div style={{textAlign:"center",padding:"24px 0"}}>
        <div style={{fontSize:28,marginBottom:10,animation:"fi .5s infinite alternate"}}>🔊</div>
        <div style={{fontSize:14,fontWeight:600,color:T.text2,marginBottom:8}}>Lecture en cours…</div>
        <div style={{fontSize:12,color:T.text3,marginBottom:18}}>Écoute attentivement, les questions arrivent dans quelques secondes.</div>
        <button onClick={()=>setPhase("questions")} style={{padding:"9px 20px",borderRadius:10,border:`1.5px solid ${T.border2}`,background:"transparent",color:T.text2,fontSize:12,cursor:"pointer"}}>Passer aux questions →</button>
      </div>}
      {(phase==="questions"||phase==="result")&&<div>
        {phase==="questions"&&<button onClick={()=>{window.speechSynthesis.cancel();speak(ex.text,"en-GB",0.8);}} style={{marginBottom:16,padding:"7px 15px",borderRadius:8,border:`1px solid ${color}30`,background:`${color}10`,color,fontSize:11.5,fontWeight:600,cursor:"pointer"}}>🔊 Réécouter</button>}
        {phase==="result"&&<div style={{marginBottom:16,padding:"14px 18px",borderRadius:10,background:score>=ex.questions.length*.7?`${T.green}0A`:`${T.orange}0A`,border:`1px solid ${score>=ex.questions.length*.7?T.green:T.orange}25`,textAlign:"center"}}>
          <div style={{fontSize:20,fontWeight:800,color:score>=ex.questions.length*.7?T.green:T.orange}}>{score}/{ex.questions.length} — {Math.round(score/ex.questions.length*100)}%</div>
        </div>}
        {ex.questions.map((q,qi)=>{const picked=answers[qi];const show=phase==="result";return <div key={qi} style={{marginBottom:16,padding:"16px",borderRadius:11,background:T.surface,border:`1px solid ${T.border}`}}>
          <div style={{fontSize:13.5,fontWeight:700,marginBottom:10}}>Q{qi+1} : {q.prompt}</div>
          <div style={{display:"flex",flexDirection:"column",gap:6}}>
            {q.choices.map((c,ci)=>{const sel=picked===ci;const ok=ci===q.answer;return <button key={ci} disabled={picked!==undefined||phase==="result"} onClick={()=>pick(qi,ci)} className="qo" style={{padding:"10px 14px",borderRadius:9,border:`1.5px solid ${show&&ok?`${T.green}45`:show&&sel&&!ok?`${T.red}45`:sel?`${color}45`:T.border2}`,background:show&&ok?`${T.green}0A`:show&&sel&&!ok?`${T.red}0A`:sel?`${color}06`:T.card,color:T.text,fontSize:12.5,fontWeight:600,textAlign:"left",display:"flex",gap:9}}>
              <span style={{width:22,height:22,borderRadius:6,display:"flex",alignItems:"center",justifyContent:"center",fontSize:10,fontWeight:700,background:show&&ok?`${T.green}18`:show&&sel?`${T.red}18`:`${T.text3}10`,color:show&&ok?T.green:show&&sel?T.red:T.text3,flexShrink:0}}>{show?(ok?"✓":(sel?"✗":String.fromCharCode(65+ci))):String.fromCharCode(65+ci)}</span>{c}
            </button>;})}
          </div>
        </div>;})}
        {phase==="questions"&&<button onClick={submit} disabled={!allAnswered} style={{width:"100%",padding:"13px",borderRadius:11,border:"none",background:allAnswered?`linear-gradient(135deg,${color},#2563EB)`:`${T.text3}20`,color:allAnswered?"#fff":T.text3,fontSize:13,fontWeight:700,cursor:allAnswered?"pointer":"not-allowed",marginTop:4}}>{allAnswered?"Valider mes réponses":"Réponds à toutes les questions"}</button>}
        {phase==="result"&&<div style={{display:"flex",gap:9,justifyContent:"center",marginTop:8}}>
          <button onClick={nextEx} style={{padding:"11px 22px",borderRadius:11,border:"none",background:`linear-gradient(135deg,${color},#2563EB)`,color:"#fff",fontSize:12.5,fontWeight:700,cursor:"pointer"}}>{exIdx+1<bank.length?"Exercice suivant →":"Recommencer depuis le début"}</button>
          <button onClick={onBack} style={{padding:"11px 22px",borderRadius:11,border:`1.5px solid ${T.border2}`,background:"transparent",color:T.text,fontSize:12.5,fontWeight:600,cursor:"pointer"}}>← Retour</button>
        </div>}
      </div>}
    </div>
  </div>;
}
